PRAGMA foreign_keys = ON;

-- Восстановление исходного каталога. Существующие тайтлы не перезаписываются.

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098967f","title":"Магическая битва. Книга 11. Колония Токио № 2. Колония Сакурадзима","author":"Гэгэ Акутами","type":"Манга","cover":"https://s1.livelib.ru/boocover/1010709416/140/75c3/Gege_Akutami__Magicheskaya_bitva._Kniga_11._Koloniya_Tokio_No_2._Koloniya_Sakura.jpg","isbn":"9785389261761","publisher":"Азбука","pubDate":"2024","language":"Русский","series":"Графические романы. Манга","genres":["Манга"],"annotation":"Маги-заклинатели продолжают вести ожесточенные сражения в колониях, надеясь переломить ход «Смертельной миграции». Очередь доходит до Киндзи Хакари, третьекурсника магического колледжа, отстраненного от занятий. Его противниками становятся Шарль Бернар, мангака, использующий силу воображения, и перерожденный маг Хадзимэ Касимо, повелевающий электричеством. Впрочем, Хакари тоже не лыком шит: он владеет крайне необычной и мощной проклятой техникой, которая превращает каждый бой в азартную игру...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2026-05","rating":5,"review":"","added":9999999,"hdCover":"https://content.img-gorod.ru/pim/products/images/30/28/0191044d-3b46-7fb7-b379-5ed95b293028.jpg"},{"id":"098967e","title":"Магическая битва. Книга 10. Колония Токио № 1. Колония Сэндай","author":"Гэгэ Акутами","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1009193302/140/fc10/Gege_Akutami__Magicheskaya_bitva._Kniga_10._Koloniya_Tokio_No_1._Koloniya_Sendaj.jpg","isbn":"978-5-389-24754-3","publisher":"Азбука","pubDate":"2024","language":"Русский","series":"Графические романы. Манга","genres":["Комиксы","манга","графические романы"],"annotation":"«Смертельная миграция» набирает обороты! Студенты магического колледжа быстро приходят к выводу, что нельзя терять ни минуты: если они хотят сорвать план Кэндзяку, им придется принять участие в его жестокой игре. Юдзи Итадори и Мэгуми Фусигуро отправляются в колонию Токио № 1, где надеются заручиться поддержкой Хигурумы, одного из сильнейших игроков. Но не успевают заклинатели оказаться на территории проведения игры, как на них нападают другие участники, жаждущие крови!..","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2026-04","rating":5,"review":"","added":9999998,"hdCover":"https://content.img-gorod.ru/pim/products/images/02/9d/018f5cb6-1b1b-7f53-9825-6929bd4c029d.jpg"},{"id":"098967d","title":"Магическая битва. Книга 9. Перелетный гусь. Пламя","author":"Гэгэ Акутами","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1008971998/140/92bc/Gege_Akutami__Magicheskaya_bitva._Kniga_9._Pereletnyj_gus._Plamya.jpg","isbn":"978-5-389-24137-4","publisher":"Азбука","pubDate":"2023","language":"Русский","series":"Графические романы. Манга","genres":["Комиксы","манга","графические романы"],"annotation":"Масштабная битва в районе Сибуя осталась позади... Маги потерпели разгромное поражение, и на волю вырвалась армия злобных духов, погрузившая Токио в хаос. Кроме того, проклинатель по имени Кэндзяку пробудил в тысяче людей магические способности, чтобы привести свой коварный план в жизнь. Юдзи Итадори и его товарищи спешат остановить негодяя, но получится ли у них? Ведь теперь, когда Сатору Годзё, могущественный из магов, запечатан во Вратах Заключения, заклинателям остается полагаться только на собственные силы...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2026-02","rating":5,"review":"","added":9999997,"hdCover":"https://content.img-gorod.ru/pim/products/images/c5/ed/018f5cb7-df6c-7b47-bf31-8866d971c5ed.jpg"},{"id":"098967c","title":"Магическая битва. Книга 8. Инцидент в Сибуе: Трансформация. Инцидент в Сибуе: Закрыть врата","author":"Гэгэ Акутами","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1008756022/140/a307/Gege_Akutami__Magicheskaya_bitva._Kniga_8._Intsident_v_Sibue_Transformatsiya._In.jpg","isbn":"978-5-389-23423-9","publisher":"Азбука","pubDate":"2023","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Пока Сатору Годзё находится в заключении, на одной из подземных станций Сибуи разгорается смертельный бой между Юдзи Итадори и Махито, проклятием особого уровня. Юноша изрядно вымотан физически и морально, в то время как проклятый дух полон сил: битва для него подобна веселой игре. На помощь Итадори уже спешат его товарищи-заклинатели, но успеют ли они вовремя, или эта долгая ночь унесет жизнь еще одного мага?.. В восьмую книгу вошли главы 125–142.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-11","rating":4.5,"review":"","added":9999996,"hdCover":"https://content.img-gorod.ru/pim/products/images/03/63/018f5cae-6e20-7ee8-aa59-22bb6f670363.jpg"},{"id":"098967b","title":"Магическая битва. Книга 7: Инцидент в Сибуе: Раскат грома. Инцидент в Сибуе: Правый и неправый","author":"Гэгэ Акутами","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1008528265/140/b50e/Gege_Akutami__Magicheskaya_bitva._Kniga_7_Intsident_v_Sibue_Raskat_groma._Intsid.jpg","isbn":"978-5-389-22753-8","publisher":"Азбука","pubDate":"2023","language":"Русский","series":"Графические романы. Манга","genres":["Комиксы","манга","графические романы"],"annotation":"Операция по спасению Сатору Годзё в самом разгаре!  Сильнейший из магов оказывается запечатан во Вратах Заключения, и если срочно ничего не предпринять — баланс сил в магическом мире будет нарушен раз и навсегда. Студенты и работники токийского колледжа с боем прорываются к станции «Сибуя», где и находится плененный Годзё, но на их пути встают невероятно могущественные противники.  Ситуация осложняется еще больше, когда на поле битвы объявляется вернувшийся с того света Тодзи Фусигуро, более известный как Убийца Магов...  В книгу вошли главы 107–124.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-10","rating":5,"review":"","added":9999995,"hdCover":"https://content.img-gorod.ru/pim/products/images/a7/b7/018f5cae-787f-71b5-b20a-c8be1827a7b7.jpg"},{"id":"098967a","title":"Магическая битва. Книга 6. Инцидент в Сибуе: Открыть врата. Инцидент в Сибуе: Спиритизм","author":"Гэгэ Акутами","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1008461270/140/2fc3/Gege_Akutami__Magicheskaya_bitva._Kniga_6._Intsident_v_Sibue_Otkryt_vrata._Intsi.jpg","isbn":"978-5-389-22493-3","publisher":"Азбука","pubDate":"2023","language":"Русский","series":"Графические романы. Манга","genres":["Комиксы","манга","графические романы"],"annotation":"31 октября 2018 года, Токио. Район Сибуя внезапно накрывает Завеса, не выпускающая местных жителей за свои пределы. Вокруг барьера собираются заклинатели магического колледжа — им приказано не вмешиваться и ждать дальнейших указаний. Тем временем за Завесу заходит Сатору Годзё, самый сильный из магов: проникнув на станцию метро, оказавшуюся в опасной зоне, он понимает, что проклятые духи взяли в заложники не одну сотню гражданских.  Сатору вступает в схватку с врагами, еще не зная, что за боем внимательно наблюдает Сугуру Гэто — зловещий проклинатель, цель которого — запечатать Годзё во Вратах Заключения…  В книгу вошли главы 89-106.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-10","rating":4.5,"review":"","added":9999994,"hdCover":"https://content.img-gorod.ru/pim/products/images/c6/8f/018f5cb3-3e62-7f82-9405-737e6d65c68f.jpg"},{"id":"0989679","title":"Магическая битва. Книга 5. Таланты умирают молодыми. В преддверии праздника","author":"Гэгэ Акутами","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1008297763/140/ea5b/Gege_Akutami__Magicheskaya_bitva._Kniga_5._Talanty_umirayut_molodymi._V_preddver.jpg","isbn":"978-5-389-22224-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2023","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Сатору Годзё и Сугуру Гэто – звёзды первой величины в Токийском магическом колледже, поэтому у них были все шансы защитить Рико Аманай – воплощение Звёздной Плазмы для мастера Тэнгэна, под контролем которого находятся все магические барьеры. И всё шло по плану – дуэт заклинателей без проблем справляется с полчищами проклинателей и киллеров. Пока на сцену не выходит большой специалист своего дела Тодзи Фусигуро по прозвищу Убийца Магов… Юдзи, Мэгуми и Нобару тоже ждёт веселье: им предстоит задержать предателя, затесавшегося в стройные ряды магов – и это не кто иной, как…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-10","rating":4.5,"review":"","added":9999993,"hdCover":"https://content.img-gorod.ru/pim/products/images/5f/30/018f5cb3-470f-7246-8e6f-1d8fe0b65f30.jpg"},{"id":"0989678","title":"Магическая битва. Книга 4. Начало повиновения. Пагубный талант","author":"Гэгэ Акутами","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007904835/140/743d/Gege_Akutami__Magicheskaya_bitva._Kniga_4._Nachalo_povinoveniya._Pagubnyj_talant.jpg","isbn":"978-5-389-22085-0","publisher":"Азбука","pubDate":"2022","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Маги-заклинатели успешно отразили атаку проклятого духа и его приспешников, произошедшую во время программы обмена опытом между колледжами. Но кто стоял за тщательно спланированным нападением и почему противники решились на такой шаг именно сейчас? Ответов на эти вопросы нет. Как и времени на раздумья. Ведь на горизонте уже маячит новое задание: расследовать убийство четырех мужчин из разных японских городов — все жертвы были заколоты проклятым духом на пороге их дома.  Юдзи, Мэгуми и Нобара прибывают в школу, где когда-то учились убитые, в надежде обнаружить хоть какие-нибудь зацепки. И вскоре становится ясно, что задание намного опаснее, чем казалось на первый взгляд…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-09","rating":4.5,"review":"","added":9999992,"hdCover":"https://content.img-gorod.ru/pim/products/images/77/47/018f5cb0-1fb1-7e57-a2eb-e8ea68227747.jpg"},{"id":"0989677","title":"Магическая битва 0. Токийский магический колледж: Ослепительная тьма","author":"Гэгэ Акутами","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007355958/140/4423/Gege_Akutami__Magicheskaya_bitva_0._Tokijskij_magicheskij_kolledzh_Oslepitelnaya.jpg","isbn":"978-5-389-21178-0","publisher":"Азбука","pubDate":"2022","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Юта Оккоцу – юноша с несчастной судьбой: его возлюбленная Рика Оримото погибла в результате несчастного случая, однако ее душа так и не смогла упокоиться… И теперь Рика повсюду сопровождает Юту в виде проклятого духа, которого невозможно обуздать или контролировать.  Отчаявшийся молодой человек решает запереться в темной комнате, боясь причинить боль окружающим. Но помощь приходит, откуда не ждали: маг по имени Сатору Годзё предлагает Юте поступить в Токийский магический колледж, где ему помогут научиться контролировать собственное проклятие.  Юта соглашается на предложение, даже не подозревая, что вскоре окажется втянут в грядущую войну магов…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-09","rating":3.5,"review":"","added":9999991,"hdCover":"https://content.img-gorod.ru/pim/products/images/59/d2/018f5cad-318d-7e8d-9ee4-a24076a359d2.jpg"},{"id":"0989676","title":"Магическая битва. Книга 3. Командный бой. Черная вспышка","author":"Гэгэ Акутами","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007560528/140/b5f9/Gege_Akutami__Magicheskaya_bitva._Kniga_3._Komandnyj_boj._Chernaya_vspyshka.jpg","isbn":"978-5-389-21834-5","publisher":"Азбука","pubDate":"2022","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Программа обмена опытом с Киотским колледжем в самом разгаре! Токийские студенты принялись выполнять практические задания, но очень быстро поняли: их противники задумали что-то ужасное. Прикрываясь соревнованиями, киотские маги собрались изгнать Сукуну из тела Юдзи Итадори — а погибнет при этом юноша или нет, им все равно. Заклинатели из Токио хотят во что бы то ни стало предотвратить убийство друга и бросаются в бой, выбрав себе оппонента по силам. На территории колледжа начинаются магические битвы, в которых ни один соперник не желает уступать другому!..","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-09","rating":4,"review":"","added":9999990,"hdCover":"https://content.img-gorod.ru/pim/products/images/25/75/018f5ca5-7809-7d3c-ba0d-180422df2575.jpg"},{"id":"0989675","title":"Магическая битва. Книга 2","author":"Гэгэ Акутами","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007410822/140/49f4/Gege_Akutami__Magicheskaya_bitva._Kniga_2.jpg","isbn":"978-5-389-21389-0","publisher":"Азбука","pubDate":"2022","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"В одном из токийских кинотеатров сотрудники обнаруживают тела трех старшеклассников, чьи головы деформированы неестественным образом. Информацию о загадочном убийстве передают в Токийский магический колледж, и на место происшествия приезжают Юдзи Итадори и его старший коллега. Маги берутся за расследование, не подозревая, что вскоре им предстоит сделать страшное открытие. Тем временем жизнь в магическом колледже тоже не стоит на месте: сокурсники Юдзи вовсю готовятся к приближающейся ежегодной программе обмена опытом с киотскими заклинателями, которые, по слухам, значительно превосходят токийских студентов…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-09","rating":4.5,"review":"","added":9999989,"hdCover":"https://content.img-gorod.ru/pim/products/images/21/56/018f5ca5-44e1-7d8b-b830-d83e5b562156.jpg"},{"id":"0989674","title":"Магическая битва. Книга 1. Двуликий Сукуна. Проклятый плод","author":"Гэгэ Акутами","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007146912/140/b9e4/Gege_Akutami__Magicheskaya_bitva._Kniga_1._Dvulikij_Sukuna._Proklyatyj_plod.jpg","isbn":"978-5-389-20871-1","publisher":"Азбука","pubDate":"2022","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Юдзи Итадори – обычный старшеклассник. И хотя мальчик от рождения обладает выдающимися физическими данными, спорт его совсем не интересует. Юноша предпочитает проводить время со своими друзьями в Клубе исследователей паранормальных явлений. Однажды в руки школьников попадает высушенный палец Двуликого Сукуны, короля проклятий. И с этой секунды жизнь Итадори начинает круто меняться: Юдзи становится частью невиданного ранее мира… Мира магии и заклинаний.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-09","rating":4.5,"review":"","added":9999988,"hdCover":"https://content.img-gorod.ru/pim/products/images/a7/77/018f5cba-5aa5-7f44-a67e-ea0cb447a777.jpg"},{"id":"0989673","title":"Дух во плоти. История о големе","author":"Стив Найлс,Мэтт Санторо,Дэйв Уокер,Нэйт Пикос","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007455858/140/5c08/__Duh_vo_ploti._Istoriya_o_goleme.jpg","isbn":"978-5-6046988-7-7","publisher":"Alpaca","pubDate":"2022","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Вы можете не знать этого автора, но вы наверняка слышали о фильме «30 дней ночи». Это экранизация одноименного комикса великолепного сценариста Стива Найлза. Создано это чудо в сотрудничестве с талантливым дебютантом Мэттом Санторо и художником Дэйвом Уоктером, номинированным на премию Расса Мэннинга в 2012 году.  Вторая мировая война. Британский самолёт терпит крушение в поле близ небольшой деревни. На расследование происшествия отправляется немецкий офицер с вооружённой охраной. Нетрудно догадаться, чем это грозит местным жителям, коренным евреям. Но что, если на их защиту встанет могущественный дух из библейских преданий: дух... во плоти?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-08","rating":3,"review":"","added":9999987,"hdCover":""},{"id":"0989672","title":"Горажде: зона безопасности. Война в Восточной Боснии 1992–1995","author":"Джо Сакко","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003631634/140/902d/Dzho_Sakko__Gorazhde_zona_bezopasnosti._Vojna_v_Vostochnoj_Bosnii_19921995.jpg","isbn":"","publisher":"Бумкнига","pubDate":"2021","language":"","series":"","genres":[],"annotation":"В 1995 году Джо Сакко, основоположник графической журналистики, автор «Палестины», отправился в Восточную Боснию, чтобы собрать свидетельства очевидцев Боснийской войны. Он одним из первых журналистов оказался в мусульманском анклаве Горажде, осажденном боснийскими сербами, и провел десятки интервью с запертыми в ловушку жителями, не имеющими доступа к внешнему миру, электричеству и водопроводу.  «Горажде: зона безопасности» — это magnum opus Сакко, который позволил ему стать одним из самых известных журналистов Америки. В 2001 году книга стала лауреатом премии имени Уилла Айснера и была номинирована на премию имени Харви Курцмана. Кроме того, журнал Time назвал «Горажде» лучшим комиксом 2000 года, а New York Times включил его в список главных книг 2001 года.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-08","rating":5,"review":"","added":9999986,"hdCover":""},{"id":"0989671","title":"ПСЫ Galaxy Gang. Добро пожаловать на Хунд (сборник)","author":"Даниил Ветлужских","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003022448/140/9a35/Daniil_Vetluzhskih__PSY_Galaxy_Gang._Dobro_pozhalovat_na_Hund_sbornik.jpg","isbn":"978-5-91339-844-4","publisher":"КомФедерация","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Давным-давно в далекой-далекой галактике жил-был пёс. Целая собачья планета Хунд, если точнее, цветущая и пахнущая. И пока одни псы бороздили просторы галактики, исследуя неизведанные миры, некоторые их коллеги чинили непотребства и наводили хаос во вселенной, угождая своим низменным инстинктам. Фидель — самый прославленный повеса, стопроцентный пьяница и наркоман, готовый на всё ради денег, славы и новой партии веществ. Именно ему предстоит встретиться со зловещим Людвигом, одержимым мегаломаньяком, мечтающим завладеть силой древних богов и уничтожить мир. И не факт, что Фидель и его команда будут готовы отказаться от распутств и измениться во благо всего собачества. \"Псы. Galaxy Gang\" — масштабная космическая сага от российских авторов, в лучших традициях \"Автостопом по галактике\" и \"Звездных войн\", помноженная на бескомпромиссность \"Криминального чтива\". Такой коктейль придется по вкусу всем любителям провокационных историй .","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-08","rating":3.5,"review":"","added":9999985,"hdCover":""},{"id":"0989670","title":"Берсерк. На воле","author":"Джефф Лемир","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007436889/140/c5b1/Dzheff_Lemir__Berserk._Na_vole.jpg","isbn":"978-5-6048461-2-4","publisher":"Alpaca","pubDate":"2022","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Беспощадный варвар оказывается в реалиях современного мегаполиса и вынужден защищать своих новых друзей от злого чародея, у которого с Берсерком личные счёты.  Лауреаты премии Айснера, ДЖЕФФ ЛЕМИР, МАЙК ДЕОДАТО-МЛ. и ФРЭНК МАРТИН представляют комикс в жанре городского фэнтези!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-08","rating":3.5,"review":"","added":9999984,"hdCover":""},{"id":"098966f","title":"П.С.: После смерти","author":"Скотт Снайдер,Джефф Лемир","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002775949/140/f2ca/__P.S._Posle_smerti.jpg","isbn":"978-5-04-090302-3","publisher":"Fanzon","pubDate":"2018","language":"Русский","series":"Комиксы. Современная классика","genres":["Комиксы","манга","графические романы"],"annotation":"Спустя годы после обнаружения генетического препарата, дарующего бессмертие, одного человека начинают одолевать сомнения, что-то не сходится в его воспоминаниях. И он отправляется в путешествие, которое перевернёт его представление о мире и заставит встретиться с прошлым и прежними жизнями.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-08","rating":4,"review":"","added":9999983,"hdCover":""},{"id":"098966e","title":"Подводный сварщик","author":"Джефф Лемир","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005933142/140/ad8d/Dzheff_Lemir__Podvodnyj_svarschik.jpg","isbn":"978-5-9500670-7-5","publisher":"Рамона","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Джек Джозеф, подводный сварщик на нефтяной вышке у побережья Новой Шотландии привык к огромному давлению во время работы на большой глубине. Однако ничто не может сравниться с давлением, которое он ощущает из-за того, что вот-вот станет отцом. Ныряя всё глубже и глубже, Джек отдаляется от своей молодой жены и их ещё не родившегося сына. Как вдруг однажды на дне ледяного Тихого океана происходит нечто необычное. Там Джека ждёт таинственная и сверхъестественная встреча, которая навсегда изменит его жизнь.  «Подводный сварщик» — это история об обычных работягах и ошеломительных тайнах. Она рассказывает об отцах и детях, рождении и смерти, воспоминаниях и реальности, а также о сокровищах, что мы прячем глубоко внутри.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-08","rating":3,"review":"","added":9999982,"hdCover":""},{"id":"098966d","title":"Графство Эссекс. Том 3. Сельская медсестра","author":"Джефф Лемир","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002982141/140/e4fb/Dzheff_Lemir__Grafstvo_Esseks._Tom_3._Selskaya_medsestra.jpg","isbn":"978-5-905295-52-2","publisher":"Alt Graph","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Заключительный том трилогии посвящен одному дню из жизни необычной медсестры Энн Кенневилль. Она посещает своих любимых пациентов, которые уже практически стали ей родными и которым она всегда готова прийти на помощь. Для Энн важно, чтобы они не просто поправились, но и стали хоть капельку счастливее. Именно она станет связующим звеном, которое объединит все три тома «Графства Эссекс» в трогательное полотно, где из потерь, сожаления и прощения сотканы судьбы нескольких поколений одной семьи из канадской глубинки.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-08","rating":4,"review":"","added":9999981,"hdCover":""},{"id":"098966c","title":"Графство Эссекс. Том 2. Истории о призраках","author":"Джефф Лемир","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002888669/140/da87/Dzheff_Lemir__Grafstvo_Esseks._Tom_2._Istorii_o_prizrakah.jpg","isbn":"978-5-905295-49-2","publisher":"Alt Graph","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Во втором томе трилогии Джефф Лемир рассказывает о жизни братьев Лу и Винсента Лебуфа и их взаимоотношениях на протяжении почти семи десятилетий. Старший брат Лу, глухой и одинокий старик, доживает свои последние дни на ферме. Его переполняют чувства вины и раскаяния за свои поступки, которые разрушили его семью. Все, что теперь остается Лу, — это вспоминать о детстве на ферме, о молодости в Торонто, где он в 1950-е вместе с братом играл в хоккей в профессиональном клубе, и горько сожалеть о когда-то принятых решениях. Сейчас он лишь молчаливый наблюдатель, преследуемый собственными воспоминаниями.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-08","rating":4,"review":"","added":9999980,"hdCover":""},{"id":"098966b","title":"Графство Эссекс. Том 1. Жизнь на ферме","author":"Джефф Лемир","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002843416/140/76bc/Dzheff_Lemir__Grafstvo_Esseks._Tom_1._Zhizn_na_ferme.jpg","isbn":"978-5-905295-46-1","publisher":"Alt Graph","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Джефф Лемир рассказывает историю десятилетнего Лестера, который недавно осиротел и теперь живет на ферме своего дяди на северо-западе канадской провинции Онтарио. Им сложно найти общий язык, и Лестер заводит дружбу с владельцем местной заправки Джимми Лебуфом, который когда-то был профессиональным хоккеистом, но из-за травмы был вынужден уйти из хоккея. Вместе они погружаются в выдуманный мир супергероев и инопланетных захватчиков, а еще играют в хоккей на замерзшем озере.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-08","rating":3.5,"review":"","added":9999979,"hdCover":""},{"id":"098966a","title":"Звёздный свет","author":"Марк Миллар,Горан Парлов","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001567233/140/e194/__Zvjozdnyj_svet.jpg","isbn":"978-5-91339-383-8","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Давным давно пилот ВВС США Дюк Маккуин побывал на далёкой планете Тантал, где помог свергнуть кровожадного тирана. Но по возвращению на Землю ему никто не верит, и Дюк тихо стареет, всеми забытый... до тех пор, пока Танталу вновь не понадобится его помощь!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-08","rating":3,"review":"","added":9999978,"hdCover":""},{"id":"0989669","title":"Хрононавты","author":"Шон Гордон Мёрфи,Марк Миллар","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002131242/140/0906/__Hrononavty.jpg","isbn":"978-5-91339-488-0","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Доктор Куинн и доктор Райли - учёные, но не такие, какими мы привыкли видеть учёных. Это не угрюмые старики в белых халатах, а молодые люди, полные жизни и амбиций. Они строят машину времени (в рамках государственной программы США, конечно же, не у себя же в гараже её строить). И, чтобы избежать изменения времени в будущем, они должны лишь наблюдать, и ни в коем случае не вмешиваться в прошлое. Но что, если бросить всё в будущем и стать безраздельными владельцами всего времени?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-08","rating":4.5,"review":"","added":9999977,"hdCover":""},{"id":"0989668","title":"Немезис","author":"Марк Миллар,Стив МакНивен","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001554280/140/65ec/__Nemezis.jpg","isbn":"9789859039393","publisher":"ALDEN comics","pubDate":"2017","language":"Русский","series":"","genres":["Зарубежная фантастика"],"annotation":"Великий создатель комикса и фильма Kick-Ass сотворил ещё один наикрутейший комикс! Millar & McNiven’s Nemesis (рус. Немезис Миллара и МакНивена) — серия комиксов, написанная Марком Милларом и проиллюстрированная Стивом МакНивеном. Серию издавала Icon Comics, импринт Marvel Comics. Nemesis является третьей совместной работой Миллара и МакНивена после Civil War и Old Man Logan.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-07","rating":3.5,"review":"","added":9999976,"hdCover":""},{"id":"0989667","title":"Два брата","author":"Фабио Мун,Габриэль Ба","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006182685/140/60b3/__Dva_brata.jpg","isbn":"978-5-00146-981-0","publisher":"Манн, Иванов и Фербер","pubDate":"2021","language":"Русский","series":"МИФ. Комиксы","genres":["Комиксы","манга","графические романы"],"annotation":"«Два брата» — адаптация одного из самых известных бразильских романов начала XX века, выполненная признанными авторами комиксов Фабио Муном и Габриэлем Ба. Это глубокая история о любви, обмане, семейных тайнах, распаде семьи и поисках самого себя.  Братья-близнецы, Омар и Якуб, внешне похожи как две капли воды, но совершенно разные по характеру. После серьезной ссоры между мальчиками, «хорошего сына» Якуба родители отправляют из Бразилии к родственникам в Ливан — на долгие пять лет. А непутевый младший — Омар — остается вести праздную жизнь... И к моменту, когда старший брат вернется домой, изменится весь мир... и только Омар останется прежним.  Это адаптация одного из самых известных романов Милтона Хатума, одного из главных современных бразильских писателей. Профессор и переводчик, Милтон написал четыре романа, получивших премии и изданных на двенадцати языках в четырнадцати странах: Tale of a Certain Orient (Blumsbury/UK), Ashes of the Amazon (Bloomsbury/UK), Orphans of Eldorado (Canongate/UK) и The Brothers («Братья») (Bloomsbury/UK. Farrar, Straus and Giroux/USA). В опросе двух ведущих бразильских газет The Brothers («Братья») были названы лучшим бразильским романом периода 1990-2005 гг. По трем романам Милтона сняты фильмы.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-07","rating":4.5,"review":"","added":9999975,"hdCover":""},{"id":"0989666","title":"Бразильские истории","author":"Фабио Мун,Габриэль Ба","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002764178/140/515c/__Brazilskie_istorii.jpg","isbn":"978-5-905295-43-0","publisher":"Alt Graph","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Фабио Мун и Габриэль Ба — братья-близнецы из Бразилии, которые уже более двадцати лет создают комиксы. Они работали с такими знаковыми авторами, как Джосс Уидон (Sugarshock), Джерард Уэй («Академия Амбрелла»), Майк Миньола («БРПД 1947») и Мэтт Фрэкшн (Casanova). На двоих они делят пять премии Айснера, а их главным успехом на данный момент, пожалуй, является комикс Daytripper. Начиналось же всё с небольших чёрно-белых комиксов.  Сборник «Бразильские истории» включает двенадцать ранних работ Фабио Муна и Габриэля Ба. Над какими-то историями они работали вместе, какие-то — рисовали в одиночку. Но все эти комиксы объединяет одно: на их страницах братья исследуют природу настоящих чувств. В свои полные реализма истории о дружбе и любви они вплетают мистические элементы, например призраков и альтернативные реальности. Калейдоскоп рассказов погружает читателей в городские пейзажи загадочного Сан-Паулу и магический реализм Латинской Америки.  Рисунок Фабио Муна и Габриэля Ба прост и элегантен, но их внимание к деталям позволяет создавать живые и многоплановые картины городской жизни. Четкие линии и всего два цвета — черный и белый — превращают страницы в выразительные и волнующие полотна.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-06","rating":4,"review":"","added":9999974,"hdCover":""},{"id":"0989665","title":"Структура пыли","author":"Александр Ярин,Филипп Ярин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006091521/140/87e8/__Struktura_pyli.jpg","isbn":"978-5-04-119365-2","publisher":"Эксмо, Комильфо","pubDate":"2021","language":"Русский","series":"Комильфо. КомФедерация. Отечественные комиксы","genres":["Комиксы","манга","графические романы"],"annotation":"В 1995 году группа американских учёных отправляется в предгорья Тянь-Шаня, их цель – зафиксировать исчезающие диалекты и ускользающую историю местных народов. Но боже! Какие чудовищные события расколют их дружную компанию в далекой пустыне! Раскаленные пески Монголии таят в себе древние ужасы, о которых помнят даже не все старожилы… Но эта книга — не просто хоррор-головоломка на грани безумия. Прочитав её, поневоле задумаешься: кто руководит нашими судьбами? Боги? Мы сами? Никто? А что если историей управляют незаметные частички – пылинки, бактерии, вирусы, у которых есть своя воля, неведомая человеку?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-06","rating":3.5,"review":"","added":9999973,"hdCover":""},{"id":"0989664","title":"Западня","author":"Джош Симмонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002995910/140/e14b/Dzhosh_Simmons__Zapadnya.jpg","isbn":"978-5-99093-702-4","publisher":"КомФедерация","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"«Западня» – это 11 небольших историй картуниста Джоша Симмонса, которые в той или иной мере представляют собой воплощение понятия «ужас». Сюжеты этих мини-комиксов самодостаточны и сводятся к стремлению автора показать истинное определение хоррора. Забудтье об всём, что вы читали прежде/ мбо с подобным отвращением и отторжением от происходящего вы столкнетесь впервые. И даже если добро в итоге победит зло, не спешите радоваться хэппи-энду. Ведь порой это всего лишь западня.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-06","rating":2,"review":"","added":9999972,"hdCover":""},{"id":"0989663","title":"Боевой парень","author":"Пол Поуп","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002051286/140/d6d2/Pol_Poup__Boevoj_paren.jpg","isbn":"978-5-9908127-9-6","publisher":"Jellyfish Jam","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Монстры осаждают город Аркополис. Лишь один герой способен остановить их - великий борец со злом Хаггард Уэст. К несчастью, Хаггард Уэст мертв. И когда жителям Аркополиса кажется, что надежды больше нет, в городе появляется новый герой — загадочный подросток, известный только как Боевой Парень. Горожане удивлены, монстры удивлены, но больше всех удивлен сам Боевой Парень, ведь он не ожидал что станет последней надеждой Аркополиса! Самостоятельный графический роман из цикла \"Боевой парень\".  Иллюстрация на обложке П.Поупа.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-06","rating":4.5,"review":"","added":9999971,"hdCover":""},{"id":"0989662","title":"Мэдмен. Приключения","author":"Майкл Аллред,Майкл Аллредм","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007005099/140/3bdb/__Medmen._Priklyucheniya.jpg","isbn":"978-5-6046284-2-3","publisher":"Alpaca","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Ох уж эти сапожки… Ох уж эти шрамы на твоём лице… Ох уж эти огромные, пустые глаза….НУЖНО БЫТЬ БЕЗУМЦЕМ, ЧТОБЫ ЛЮБИТЬ ТЕБЯ! НО КАК МОЖНО НЕ ЛЮБИТЬ САМОГО ШИКАРНОГО СУПЕРГЕРОЯ В МИРЕ?! Встречайте легендарного Фрэнка Эйнштейна, более известного как... МЭДМЕН!  Про шальное сумасбродство этой серии слыхали даже те, кто далёк от книжек для неразумных - но зачем слушать других, когда можно самому с разбега сигануть в безумную пропасть мира Майка Оллреда!  ВПЕРВЫЕ НА РУССКОМ ЯЗЫКЕ!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-06","rating":4,"review":"","added":9999970,"hdCover":""},{"id":"0989661","title":"Автор","author":"Алексей Хромогин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003403815/140/6b41/Aleksej_Hromogin__Avtor.jpg","isbn":"978-5-91339-867-3","publisher":"КомФедерация","pubDate":"2019","language":"Русский","series":"Комильфо. КомФедерация. Отечественные комиксы","genres":["Комиксы","манга","графические романы"],"annotation":"1837 год. А. С. Пушкин переживает смерть своей матери Надежды Осиповны и готовится к приближающейся дуэли с Дантесом. Но мало кто знает, что в этот год Пушкин начинает писать свое лучшее произведение.  Алексей Хромогин («Первый человек на Земле», «Огни в лесу», представляет этюд-размышление о том, где проходит грань между шедевром и посредственностью. Влияют ли на наше восприятие произведения жизнь и смерть человека, создавшего его? И нужен ли автор своему творению?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-06","rating":4,"review":"","added":9999969,"hdCover":""},{"id":"0989660","title":"Первый человек на Земле","author":"Алексей Хромогин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003002689/140/93cc/Aleksej_Hromogin__Pervyj_chelovek_na_Zemle.jpg","isbn":"978-5-91339-829-1","publisher":"КомФедерация","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Псевдо-документальный рассказ Алексея Хромогина о знаменитом полете первого человека в космос - это не очередная хроника эпохального события и тем более не ода великому космонавту. Скорее размышление: трепетное, полное почтения и уважения к легендарной фигуре. Что, если тебе тесно на Земле? Что, если надежда на величие космоса - это ошибка, и там нет ничего, кроме необъятной мертвой пучины? Или напротив: что, если в этой пучине кто-то уже ожидает тебя?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-06","rating":2.5,"review":"","added":9999968,"hdCover":""},{"id":"098965f","title":"Огни в лесу","author":"Алексей Хромогин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002910968/140/d80c/Aleksej_Hromogin__Ogni_v_lesu.jpg","isbn":"978-5-99093-696-6","publisher":"КомФедерация","pubDate":"2018","language":"Русский","series":"Комильфо. КомФедерация. Отечественные комиксы","genres":["Комиксы","манга","графические романы"],"annotation":"В загадочной деревне в Тульской губернии при крайне таинственных обстоятельствах стали пропадать люди. И вот специальная структура ПТГ отправляет на расследование двух агентов, которым, по-хорошему, разобраться бы сначала со своими собственными демонами. Что это: проделки местного серийного убийцы, череда несчастных случаев, или же здесь имеют место быть потусторонние силы? Присоединяйтесь к расследованию, и всё встанет на свои места. А может, и нет...  Алексей Хромогин уже известен читателям по своему комиксу «Чёртов кабак», сейчас перед вами его первая действительно большая работа. «Огни в лесу» представляют из себя прекрасный мистический детектив, в котором можно проследить влияние эстетики сериалов «Твин Пикс» и «Улицы разбитых фонарей», стиля Майка Миньолы в его «Хеллбое» и даже песен «Короля и Шута».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-06","rating":3.5,"review":"","added":9999967,"hdCover":""},{"id":"098965e","title":"Блюз Старого Города","author":"Янис Милоноянис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002884275/140/f4a1/Yanis_Milonoyanis__Blyuz_Starogo_Goroda.jpg","isbn":"978-5-6040823-2-4","publisher":"Jellyfish Jam","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"2048 год, Новые Афины. Мир искусственного интеллекта, роботов и летающих боевых костюмов. Детектив Солано из Специальной Полиции расследует убийство кибернетически улучшенного директора транснациональной корпорации«Хаяси». Это расследование приведёт его в самое сердце пустынного Старого Города и заставит поставить под сомнение все, что Солано знал раньше.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-06","rating":4,"review":"","added":9999966,"hdCover":""},{"id":"098965d","title":"Победители Невозможного. Вторая война с амфибиями","author":"Алексей Горбут,Алексей Волков","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002884264/140/cf7c/__Pobediteli_Nevozmozhnogo._Vtoraya_vojna_s_amfibiyami.jpg","isbn":"978-5-6040824-6-1","publisher":"Jellyfish Jam","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Марс, Вулканика и Мор продолжают поиски загадочного путешественника во времени, но оказываются в эпицентре новой войны между амфибиями коварного Ихтиора и загадочными аборигенами под командованием бессмертного Сиврэна!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-06","rating":3.5,"review":"","added":9999965,"hdCover":""},{"id":"098965c","title":"Победители невозможного","author":"Алексей Волков","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002717042/140/0993/Aleksej_Volkov__Pobediteli_nevozmozhnogo.jpg","isbn":"978-5-9908125-9-8","publisher":"ИП Коташевская Б. Д.","pubDate":"2017","language":"Русский","series":"","genres":[],"annotation":"Победители Невозможного вдохновлены не только обширным пластом западных и российских комиксов, но и фантастикой (в том числе, советской), и классической литературой, и даже старым аниме. От Булгакова до Стругацких, от Metal Men до \"Приключений Электроника\", от Булычева до Dragon Ball Z - референсы и культурные аллюзии превращают сборник во что-то куда более важное, чем просто комикс о четверке людей с суперспособностями.  Это независимый проект команды, которая невероятно много делает для развития российской комикс-культуры. Те, кто читал \"Фронтир\", наверняка с нами согласятся - \"Победителей Невозможного\" без внимания оставить нельзя. - Это просто очень увлекательный комикс (кстати, авторы обещают продолжение!), и вкупе с подробной историей создания персонажей и отдельных сюжетов - она, разумеется, тоже включена в сборник - он создает мир альтернативной России, в которой (и из которой) герои ухитряются попадать в самые странные места и ситуации.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-06","rating":3.5,"review":"","added":9999964,"hdCover":""},{"id":"098965b","title":"Девочка-Апокалипсис. Ария конца света","author":"Эндрю Маклин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001863261/140/63f9/Endryu_Maklin__DevochkaApokalipsis._Ariya_kontsa_sveta.jpg","isbn":"978-5-9908127-1-0","publisher":"Jellyfish Jam","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Научно-фантастический комикс о пост-апокалиптической жизни и уходу за кошками!  Ария: она совсем одна на краю мира, но у нее есть задание! Ну не совсем одна – с ней её кот Драже. В заросших джунглями руинах города, они вместе ищут древний артефакт невероятной мощи. Когда она чуть не погибает после нападения дикарей, Ария вдруг выходит на след артефакта. Но она не единственная, кто охотится за ним – и теперь, чтобы выполнить задание и наконец вернуться домой, Арии придется взглянуть в лицо смерти.  «Девочка-Апокалипсис: Ария Конца света» - первый графический роман инди-сенсации Эндрю Маклина, мощное высказывание о природе жестокости и человечности на развалинах мира будущего.  «Эндрю Маклин – не просто один из моих любимых художников. Его «Девочка-Апокалипсис» так умело сочетает элементы «Навсикаи из Долины Ветров» и «Времени Приключений», что он теперь один из моих любимых авторов комиксов», - Майкл Эвон Оминг (создатель комикса «Powers»)  «Эндрю Маклин – один из самых оригинальных комиксистов. Он видит мир иначе, чем мы, и потому он просто идеален для этого медиума», - Джон Аркуди («Б.Р.П.Д», «Rumble»)","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-02","rating":3.5,"review":"","added":9999963,"hdCover":""},{"id":"098965a","title":"Война Зомби","author":"Кевин Истмен","type":"Книга","cover":"https://s1.livelib.ru/boocover/1004688565/140/6722/Kevin_Istmen__Vojna_Zombi.jpg","isbn":"978-5-04-113213-2","publisher":"КомФедерация","pubDate":"2020","language":"Русский","series":"","genres":["Биографии и мемуары"],"annotation":"Такого зомби-апокалипсиса вы ещё не видели! На военных кладбищах мёртвые восстают из своих могил!  Кто остановит их?! Лётчице-истребителю Джине предстоит выяснить, что возвращает этих вооружённых до зубов мертвецов, и как их вновь отправить на тот свет. Ураганный зомби экшн, выполненный в лучших традициях фильмов категории \"Б\", от Кевина Истмана (\"Подростки Мутанты Ниндзя Черепашки\") и Эрика Тэлбота (Heavy Metal)!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-01","rating":4,"review":"","added":9999962,"hdCover":""},{"id":"0989659","title":"Годзилла в Аду","author":"Джеймс Стоко","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003627594/140/535a/Dzhejms_Stoko__Godzilla_v_Adu.jpg","isbn":"","publisher":"КомФедерация","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"«Годзилла в Аду» — от автора и художника недавнего комикса «Годзилла: Полувековая война» Джеймса Стоко, а также других талантливых художников.  Король монстров попадает в Ад! А там его уже поджидают как инфернальные версии побеждённых им врагов, так и местные гигантские твари. С каждым выпуском Годзилла опускается на новый уровень Преисподней, и показывать кто тут главный кайдзю на районе становится всё сложнее!  Минисерия состоит из пяти выпусков. Издание подготовлено совместно с командой Vicious Membrane.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-01","rating":2.5,"review":"","added":9999961,"hdCover":""},{"id":"0989658","title":"Годзилла: Полувековая война","author":"Джеймс Стоко","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003403809/140/c4b8/Dzhejms_Stoko__Godzilla_Poluvekovaya_vojna.jpg","isbn":"978-5-04-104095-6","publisher":"КомФедерация","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"ЭТО НОВЫЙ И ЗАХВАТЫВАЮЩИЙ ВЗГЛЯД НА ЦАРСТВО УНИЧТОЖЕНИЯ ГОДЗИЛЛЫ ОТ ДЖЕЙМСА СТОКО! В 1954-ом году лейтенант Ота Мураками оказывается свидетелем первого нападения Годзиллы на Японию. Вместе со своим товарищем Кентаро, Ота отчаянно старается спасти жизни… И в процессе этого его одержимость Королём Монстров растягивается на долгие 50 лет!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Перечитал","read":"2025-01","rating":4,"review":"Предыдущее прочтение: Июнь 2021, оценка 4","added":9999960,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989657","title":"Зомби против роботов","author":"Эшли Вуд,Крис Райалл","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001271613/140/64ac/__Zombi_protiv_robotov.jpg","isbn":"978-5-91339-320-3","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Все началось с простой идеи – бездушные роботы борются с взбесившимися зомби за жизнь последнего живого человеческого ребенка. Когда в эту историю внезапно вмешиваются выжившие Амазонки, противостояние выливается в крупномасштабную битву, наполнившую весь мир гулом войны! Полное издание, включающее все комиксы серий «Зомби против Роботов» и «Зомби против Роботов против Амазонок».  Эшли Вуд – австралийский художник и иллюстратор, известный своим уникальным стилем, совмещающим масляную живопись и цифровые технологии. Этот микс превращает каждый его комикс в произведение искусства.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-01","rating":4.5,"review":"","added":9999959,"hdCover":""},{"id":"0989656","title":"Я убил Адольфа Гитлера","author":"Джейсон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001590602/140/ebbb/Dzhejson__Ya_ubil_Adolfa_Gitlera.jpg","isbn":"978-5-91339-398-2","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"ЧТО, ЕСЛИ БЫ мы жили в мире, где «наёмный убийца» — это законная и обычная профессия, как доктор или адвокат?  ЧТО, ЕСЛИ БЫ учёный нанял такого убийцу на самое потрясающее задание в его карьере… отправиться назад во времени и убить Адольфа Гитлера до того, как он стал злым диктатором?  А ЧТО, ЕСЛИ БЫ Гитлеру удалось пережить покушение, проникнуть в машину времени и попасть в XXI век… оставив будущего убийцу одного на 70 лет?  Если вы думаете, что знаете ответы на эти вопросы… то ошибаетесь. И вы обязательно должны прочитать «Я убил Адольфа Гитлера», шедевр с серьёзной миной от Джейсона.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-01","rating":4,"review":"","added":9999958,"hdCover":""},{"id":"0989655","title":"Бандитка. Вуаля!","author":"Пол Тобин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002777216/140/4ea2/Pol_Tobin__Banditka._Vualya.jpg","isbn":"978-5-6040823-0-0","publisher":"Jellyfish Jam","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Она загадочна, дерзка и неуловима. Она считает себя лучшей воровкой в мире и готова пойти наперекор властям и преступному миру. Она - Бандитка! Но сейчас она ввязалась в опасное дело, которое может стоить ей не только свободы, но и жизни. Сможет ли Бандитка справиться с угрозой, не потеряв стиля и присутствия духа?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-01","rating":4,"review":"","added":9999957,"hdCover":""},{"id":"0989654","title":"Дом Покаяния","author":"Питер Дж. Томаси","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007315605/140/6c89/Piter_Dzh._Tomasi__Dom_Pokayaniya.jpg","isbn":"978-5-6047218-3-4","publisher":"Alpaca","pubDate":"2022","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"1905 год. Молодая вдова Сара Винчестер ведёт масштаб ную стройку: день и ночь не стихает бой молотков, а новые комнаты, этажи и ложные ходы появляются в её доме один за другим. Злые языки говорят, наследница оружейной империи выжила из ума. Но им невдомёк, что дом Сары – это пристанище заблудших душ. Никто не знает, что лишь звуки инструментов мешают призра кам невинных жертв отомстить Саре за грехи её семьи…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-01","rating":3.5,"review":"","added":9999956,"hdCover":""},{"id":"0989653","title":"Кромвель Стоун. Полное издание (сборник)","author":"Андреас","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1008837178/140/f7a4/Andreas__Kromvel_Stoun._Polnoe_izdanie_sbornik.jpg","isbn":"978-5-00116-904-8","publisher":"Питер","pubDate":"2023","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Трилогия Андреаса в духе лавкрафтовских ужасов впервые на русском языке.  Тринадцать человек чудом спасаются после бунта на корабле, но затем начинают один за другим исчезать при таинственных и зловещих обстоятельствах. Кромвель Стоун может стать следующим, поэтому он решает выяснить, кто стоит за этими похищениями, но оказывается втянут в гораздо более опасную и странную историю, чем мог себе представить.  Издание включает три части графического романа: \"Кромвель Стоун\", \"Возвращение Кромвеля Стоуна\" и \"Завещание Кромвеля Стоуна\".","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-01","rating":4.5,"review":"","added":9999955,"hdCover":""},{"id":"0989652","title":"Kingsman. Красный алмаз","author":"Роб Уильямс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005966154/140/102a/Rob_Uilyams__Kingsman._Krasnyj_almaz.jpg","isbn":"978-5-04-119109-2","publisher":"Комильфо","pubDate":"2021","language":"Русский","series":"Комиксы по фильмам, играм и сериалам","genres":["Комиксы","манга","графические романы"],"annotation":"Сиквел полюбившегося критикам комикса Марка Миллара и Дэйва Гиббонса \"Kingsman. Секретная служба\", набитый приключениями до отказа. Эггси вернулся. Ему приказано спасти принца Филиппа и раскрыть международный террористический заговор, а заодно доказать, что он — настоящий агент Kingsman... и спасти мир. Его дяди-наставника больше нет рядом, и Эггси придётся полагаться только на собственные шпионские навыки, чтобы выследить злодея, решившего уничтожить всю мировую экономику. По всему миру вспыхивают беспорядки, общество в современном его виде вот-вот погибнет, а Эггси отвлекает от задания невероятно сексуальная шпионка из Южной Африки...  Эта серия-бомба за авторством Роба Уильямса (\"Отряд самоубийц\") и Саймона Фрейзера расскажет о том, как наш герой из народа справляется с задачей, которая сделала бы честь самому Джеймсу Бонду.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2024-09","rating":3,"review":"","added":9999954,"hdCover":""},{"id":"0989651","title":"Kingsman. Секретная служба","author":"Марк Миллар,Дэйв Гиббонс,Мэттью Вон,Энди Маннинг,Ангус Макки,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006077574/140/8a92/__Kingsman._Sekretnaya_sluzhba.jpg","isbn":"978-5-04-116450-8","publisher":"Комильфо","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В 2014 году автор комикса \"Мордобой\" Марк Миллар, легендарный художник \"Хранителей\" Дэйв Гиббонс и популярный кинорежиссёр Мэтью Вон объединились в работе над одним из лучших новых комиксов последних лет \"Kingsman: Секретная служба\", чтобы в двадцать первом веке заново изобрести жанр шпионской драмы. Успех киноленты был закреплён спустя три года продолжением \"Kingsman: Золотое кольцо\", а в 2020 году зрителей ожидает и приквел оригинальной истории. Но всё началось с комикса, который вы держите в руках...  Агент британской секретной службы берётся перевоспитать своего непутёвого племянника после того, как тот в очередной раз попадает в полицейский участок. С целью наставить юношу на путь истинный дядя начинает обучать Гэри тонкостям своего ремесла, чтобы превратить парня из лондонского гопника в супершпиона! Долой спортивную одежду и дешёвые побрякушки, пришло время дорогих костюмов и пуленепробиваемых зонтиков. Теперь вместе они должны раскрыть таинственные похищения суперзвезд научно-фантастических фильмов и предотвратить уничтожение 90% населения Земли.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2024-09","rating":3.5,"review":"","added":9999953,"hdCover":""},{"id":"0989650","title":"Доктор Стрэндж. Клятва","author":"Брайан К. Вон,Маркос Мартин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001518880/140/864c/__Doktor_Strendzh._Klyatva.jpg","isbn":"ISSN 2304-9057","publisher":"Ашет Коллекция, Панини Рус","pubDate":"2016","language":"Русский","series":"Marvel. Официальная коллекция комиксов","genres":["Комиксы","манга","графические романы"],"annotation":"Доктор Стефан Стрэндж должен расследовать самое важное мистическое дело за всю его карьеру - попытку покушения на его собственную жизнь! Чтобы раскрыть эту тайну Стрэнджу придется совершить удивительное путешествие через параллельные реальности и преступный мир Нью-Йорка. Ситуация осложняется тем, что лучший друг Стрэнджа - его преданный ученик Вонг - находится на краю гибели.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2023-12","rating":4,"review":"","added":9999952,"hdCover":""},{"id":"098964f","title":"1602","author":"Нил Гейман,Энди Куберт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001437850/140/716f/__1602.jpg","isbn":"2304-9057","publisher":"Ашет Коллекция, Панини Рус","pubDate":"2015","language":"Русский","series":"Marvel. Официальная коллекция комиксов","genres":["Комиксы","манга","графические романы"],"annotation":"Англия, 1602 год - Елизаветинская эпоха подходит к концу, страну будоражат странные грозы и слухи о могущественных потусторонних существах, которые бродят по земле. По всей Европе такие знакомые и вместе с тем такие совершенно новые герои и злодеи, включая Ника Фьюри, Человека-Паука, Людей Икс и Доктора Дума, оказываются впутанными в хитроумный заговор, который может приблизить конец света.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал"