  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989387","title":"Вселенная DC. Rebirth. Флэш. Книга 1. Молния бьет дважды","author":"Джошуа Уильямсон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002809288/140/19a1/Dzhoshua_Uilyamson__Vselennaya_DC._Rebirth._Flesh._Kniga_1._Molniya_bet_dvazhdy.jpg","isbn":"978-5-389-14587-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"История начинается со встречи Барри Аллена и Уолли Уэста, которая упоминается в комиксе «Вселенная DC. Rebirth». Воспоминания о забытой Барри Алленом жизни возвращаются к нему, и Алый Спидстер узнает, что в ход времени вмешалась загадочная сила… Разобраться бы с этим, но порожденная Силой Скорости буря проносится через Централ-сити и наделяет способностями мирных жителей. Теперь на героя взвалилась ответственность за воспитание новых спидстеров. Займут ли новички сторону добра или решат использовать дар в корыстных целях?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-05","rating":4,"review":"","added":9999239,"hdCover":""},{"id":"0989386","title":"Человек-Паук. Другой","author":"Питер Дэвид,Джей Майкл Стражински,Реджинальд Хадлин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002845352/140/ec96/__ChelovekPauk._Drugoj.jpg","isbn":"978-5-04-097326-2","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Человек-Паук. Избранное","genres":["Комиксы","манга","графические романы"],"annotation":"Его беспокоят странные сны. Его тревожит растущее чувство опасности. Он убеждён, что все вокруг жаждут его крови. Паучок сталкивается с величайшей угрозой… вероломным врагом, которого в одиночку не одолеть. Но Паук не одинок, с ним его друзья: Рид Ричардс, Стефан Стрэндж и Хэнк Пим. Но смогут ли даже величайшие умы изменить судьбу? И если смогут — пойдут ли на это? Наконец приняв правду, Питер Паркер решает отложить красно-синее трико и провести время с тётей Мэй и Эм Джей. Но у Морлана иные планы… и в этот раз рядом нет Иезекииля, способного помочь стенолазу. Усаживайтесь поудобнее, преданные фанаты, — такой битвы вы ещё не видели, ведь Пауку противостоит враг, которого он ещё никогда не побеждал! Избитый до полусмерти, он оказывается в месте, совершенно не похожем на рай или ад. Человека-Паука ждёт приключение, равного которому у него ещё не было. И если Питер надеется хоть как-то остановить Морлана, у него есть всего два варианта: измениться или умереть!..","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-05","rating":3.5,"review":"","added":9999238,"hdCover":""},{"id":"0989385","title":"Флэшпойнт","author":"Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002724585/140/e95c/Dzheff_Dzhons__Fleshpojnt.jpg","isbn":"978-5-389-13896-4","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Барри Аллен был супергероем. В облике Флэша он сражался со злом. Но в один прекрасный день он не узнал мир вокруг себя. Здесь Чудо-Женщина и Аквамен уже погубили миллионы людей в войне за власть. Здесь Зеленым Фонарем никогда не становился землянин, и ни одна живая душа ничего не слышала о Супермене. Здесь Бэтмен использует кровавые методы в борьбе с противниками, а самый быстрый человек на планете – всего лишь обычный криминалист.  В этом мире у Барри Аллена нет друзей и сверхскорости, но он помнит о том, что было раньше. Осталось всего ничего – убедить других супергероев помочь ему повернуть время вспять...  МИР НИКОГДА НЕ БУДЕТ ПРЕЖНИМ.  Звездная команда в лице писателя Джеффа Джонса («ЛИГА СПРАВЕДЛИВОСТИ») и художника Энди Кьюберта («БЭТМЕН») с гордостью представляют «ФЛЭШПОЙНТ» – незабываемое событие, которое навсегда изменит Вселенную DC!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-05","rating":3.5,"review":"","added":9999237,"hdCover":""},{"id":"0989384","title":"Клаус","author":"Грант Моррисон,Дэн Мора","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002907043/140/c2ff/__Klaus.jpg","isbn":"978-5-04-098212-7","publisher":"Эксмо, Fanzon","pubDate":"2018","language":"Русский","series":"Комиксы. Современная классика","genres":["Комиксы","манга","графические романы","Зарубежное фэнтези"],"annotation":"Его любят дети и взрослые по всему миру… Но знает ли кто-нибудь, откуда на самом деле взялся Санта-Клаус?  Погрузившись в мрачную старину, где сплелись мифы и магия, «Клаус» рассказывает историю о прошлом Санты. О том, как один человек со своим верным волком бросил вызов тоталитарному государству и стоящему за ним древнему злу...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-04","rating":4.5,"review":"","added":9999236,"hdCover":""},{"id":"0989383","title":"Чёрная Вдова. Полное издание","author":"Крис Сэмни,Марк Уэйд,Мэтт Уилсон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002824728/140/a25e/__Chjornaya_Vdova._Polnoe_izdanie.jpg","isbn":"978-5-04-096583-0","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Они поразили вас \"Сорвиголовой\", а теперь команда, получившая премию Айснера, Марк Уэйд и Крис Сэмни, возводит Чёрную Вдову на новый уровень, заставив её пуститься в бега! У Наташи на всю жизнь хватит секретов, а когда самые страшные из них становятся достоянием общественности, о безопасности можно забыть. З.А.Щ.И.Т.А. выступает против своего некогда самого ценного агента, и Наташа начинает в одиночку искать ответы в этой истории, полной захватывающего, кладущего на лопатки экшна и шпионажа! Вдова окажется там, куда предпочла бы никогда не возвращаться, увидит реинкарнацию жуткой Красной Комнаты: Тёмную Комнату! Всё заходит слишком далеко, и Наташе придётся показать, чего она стоит и на что способна.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-04","rating":3.5,"review":"","added":9999235,"hdCover":""},{"id":"0989382","title":"Чудеса","author":"Курт Бьюсик, Алекс Росс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002718658/140/1c0b/Kurt_Byusik_Aleks_Ross__Chudesa.jpg","isbn":"978-5-9909878-7-6","publisher":"Jellyfish Jam","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Взгляните на рождение вселенной Marvel глазами обычного человека. Фотограф Фил Шелдон не обладает какими-то удивительными способностями, но у него есть невероятное журналистское чутье и умение оказаться в нужное время в нужном месте. Вместе с ним, читатель станет свидетелем появления первого Человека-Факела и нападения Нэмора на Нью-Йорк, рождения Мстителей и анти-мутантской паники, вторжения Галактуса и судьбоносной дуэли Человека-Паука с Зеленым Гоблином за жизнь Гвен Стейси.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-04","rating":3.5,"review":"","added":9999234,"hdCover":""},{"id":"0989381","title":"Отряд Икс. Книга 2","author":"Рик Ремендер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002808950/140/f0ef/Rik_Remender__Otryad_Iks._Kniga_2.jpg","isbn":"978-5-6040823-4-9,  978-5-6040823-6-2","publisher":"Jellyfish Jam","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Росомаха. Псайлок. Архангел. Фантомекс. Дэдпул. Дэтлок. Вместе, они - Отряд Икс, команда мутантов с лицензией на убийство. Именно так они разобрались с Апокалипсисом, но в итоге столкнулись с ещё большей опасностью. Злодей отравил разум их напарника Архангела, и тот стал всемогущим и безумным Темным Ангелом. Теперь Отряду Икс предстоит сложный выбор, ведь уберечь мир от нового геноцида означает убить друга и возлюбленного. Но даже если они решается на такое, хватит ли у них сил? Также в книге: путешествие в опасный Иной Мир, встреча с корпусом Капитанов Британия и охота на злодеев из Эры Апокалипсиса!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-04","rating":3.5,"review":"","added":9999233,"hdCover":""},{"id":"0989380","title":"Джокер","author":"Брайан Азарелло,Ли Бермехо","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002326940/140/ea63/__Dzhoker.jpg","isbn":"978-5-389-12610-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Джокер выбрался из психушки, но ему, несмотря на улыбку, совсем не весело. За время его отсутствия бывшие подчиненные растащили хозяйский пирог до последней крошки, а самого Джокера списали со счетов, решив, что тот уже не вернется. Однако Джокер снова на свободе и пуще прежнего жаждет утопить Готэм в крови.  В долгих блужданиях по сумеркам души ему составят компанию такие персонажи, как Пингвин, Двуликий, Убийца Крок, Харли Квинн, Загадочник и, конечно же, Бэтмен… и да поможет им всем Господь.  История Джокера, рассказанная от лица его верного, хоть и наивного подручного по имени Джонни Фрост, — классический криминальный нуар, зубодробительный трип по городу среди залитых дождем улиц, грязного белья и сплошных разочарований.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-04","rating":4,"review":"","added":9999232,"hdCover":""},{"id":"098937f","title":"Царство Небесное","author":"Марк Уэйд,Алекс Росс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002791481/140/4bd8/__Tsarstvo_Nebesnoe.jpg","isbn":"978-5-389-13325-9","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"«Царство Небесное» - легендарное, впечатляющее произведение, не потерявшее своей значимости с 1996 года, когда Марк Уэйд и Алекс Росс познакомили мир с этим шедевром комикс-индустрии. Впервые на русском языке!  Супергерои вездесущи, но героизм встречается все реже…  Десятилетиями решая самые острые проблемы Земли, члены Лиги Справедливости в конце концов отошли в тень. Однако пришедшее им на смену новое поколение борцов с преступностью вселяет в людей больше ужаса, нежели уверенности в завтрашнем дне. И снова будущее планеты оказывается под угрозой. Тогда Супермен, Чудо-Женщина и Бэтмен должны снова взяться за дело, чтобы в последней битве отстоять истину и справедливость!  Настоящее издание включает выпуски 1 - 4 и более сотни страниц набросков, эскизов, и разнообразных рабочих материалов, отражающих процесс создания одного из культовых комиксов DC.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-04","rating":4,"review":"","added":9999231,"hdCover":""},{"id":"098937e","title":"Вселенная DC. Rebirth. Бэтмен. Detective Comics. Книга 1. Восстание бэтменов","author":"Джеймс Тайнион IV","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002785643/140/e950/Dzhejms_Tajnion_IV__Vselennaya_DC._Rebirth._Betmen._Detective_Comics._Kniga_1._V.jpg","isbn":"978-5-389-14319-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Жестоко избит профессиональный убийца, причем сделал это кто-то, прикрывшийся личиной Бэтмена. Оказавшись на месте преступления, Темный Рыцарь находит дрон, взломав который, понимает, что на плащеносцев Готэма началась охота. Противник силен, но что особенно удивительно – использует снаряжение Бэтмена и его тактику ведения боя. Мотивы нападающих не ясны, однако очевидно, что поодиночке герои Готэма с ними не справятся. Поэтому Бэтмен решает создать спецотряд во главе с Бэтвумен, призванный бороться с новой угрозой. Но смогут ли Брюс Уэйн и Кэтрин Кейн полностью положиться друг на друга? Ведь Брюс что-то скрывает, и совсем скоро Кэтрин узнает, что именно.  Отличная книга для новичков в мире DC! «Бэтмен: Detective Comics. Книга 1. Восстание бэтменов» – мощный триллер, созданный писателем Джеймсом Тайнионом IV («Бэтмен и Робин навсегда») и художниками Эдди Барроузом («Найтвинг») и Альваро Мартинесом («Люди Икс: Ultimate Comics»). Эта книга – метеорит на небосклоне DC. Включает выпуски №934–940.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-03","rating":4,"review":"","added":9999230,"hdCover":""},{"id":"098937d","title":"Звёздные войны. Официальная коллекция комиксов. Выпуск № 2 - Классика. Часть 2","author":"Крис Клэрмонт,Арчи Гудвин,Арчи Гудвин, Крис Клэрмонт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002817772/140/7b98/__Zvjozdnye_vojny._Ofitsialnaya_kollektsiya_komiksov._Vypusk_No_2__Klassika._Cha.jpg","isbn":"","publisher":"DeAgostini","pubDate":"2018","language":"Русский","series":"Звёздные войны. Официальная коллекция комиксов","genres":["Комиксы","манга","графические романы"],"annotation":"После уничтожения «Звезды Смерти» Альянс повстанцев отправляет Люка Скайуокера на поиски места для главной базы. Его путешествие приведет к столкновениям с драконьими лордами, деспотичными правителями и даже с космическими пиратами. Потому что Империя – не единственное, чего стоит опасаться в Галактике! К счастью, наш герой всегда может рассчитывать на команду «Сокола Тысячелетия», принцессу Лею Органу и своих верных дроидов. Но достаточно ли будет их сил, чтобы выжить на «Колесе» – весьма негостеприимной космической станции?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-03","rating":2.5,"review":"","added":9999229,"hdCover":""},{"id":"098937c","title":"Звёздные войны. Официальная коллекция комиксов. Выпуск № 1 - Классика. Часть 1","author":"Арчи Гудвин,Дональд Глут,Рой Томас,Говард Чайкин","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002808521/140/4cb9/__Zvjozdnye_vojny._Ofitsialnaya_kollektsiya_komiksov._Vypusk_No_1__Klassika._Cha.jpg","isbn":"","publisher":"DeAgostini","pubDate":"2018","language":"Русский","series":"Звездные войны. Официальная коллекция комиксов","genres":[],"annotation":"Том 1. В сборник вошли выпуски серии «Звёздные войны» (1977-1978) #1-11.  Эта наиболее полная коллекция комиксов о Легендарной Вселенной включает в себя лучшие истории, созданные более, чем за 40 лет существования Космической саги — начиная с первых комиксов, опубликованных в 1977 году, заканчивая работами последних лет. Многие из комиксов коллекции будут опубликованы в России впервые. В коллекции представлены такие легендарные серии, как Империя, Тёмные времена, Войны клонов, Восстание, Наследие и многие другие. Коллекция в том числе включает уникальные истории, которые никогда не появлялись в фильмах. Корешки книг образуют рисунок с героями саги. 200 страниц красочных комиксов в твёрдом переплёте в каждом выпуске (среднее количество страниц).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-03","rating":2.5,"review":"","added":9999228,"hdCover":""},{"id":"098937b","title":"Академия Амбрелла (сборник)","author":"Джерард Уэй,Габриэль Ба","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003000006/140/1ff5/__Akademiya_Ambrella_sbornik.jpg","isbn":"978-5-04-101982-2","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Альтернативные комиксы","genres":["Комиксы","манга","графические романы"],"annotation":"Академия Амбрелла. Black Edition Более двадцати лет назад на свет появились сорок три необыкновенных ребёнка. Семеро из них выжили и были усыновлены сэром Реджинальдом Харгривзом. Пройдут годы, и они станут знаменитой Академией Амбрелла, невероятной командой с суперспособностями, чьё призвание - спасти весь мир. Однако эта история не о их детстве, а о том, что случилось потом, гораздо позже. Знаменитый экс-солист группы My Chemical Romance Джерард Уэй и бразильский художник комиксов Габриэль Ба (Daytripper, Casanova, De:TALES) расскажут нам не просто ещё одну историю спасения мира супергероями. Во-первых, это совершенно удивительные и уникальные супергерои, а во-вторых, акцент в этой книге делается на их взаимоотношениях и внутренних переживаниях, вопросах совести и жизненной цели, а не на умении летать или драться с роботами-убийцами. В данное издание вошли две книги: \"Академия Амбрелла: Сюита Апокалипсиса\" и \"Академия Амбрелла: Даллас\". Вторая книга намного круче первой, но без первой вы ни за что не поймёте, почему вторая такая классная. А впрочем… они обе потрясающие, здесь есть всё: зомби-робот Гюстав Эйфель, гигантская ожившая статуя Авраама Линкольна, убийственная музыка, самые опасные убийцы за все времена, которые носят мультяшные маски и обожают печенье от девочек-скаутов. И ещё, конечно же, будет уничтожен мир. Звучит захватывающе? Тогда эта книга для вас. Кстати, ещё она получила кучу премий, в том числе и премию Айснера за лучшую мини-серию.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-03","rating":3,"review":"","added":9999227,"hdCover":""},{"id":"098937a","title":"Удивительный Человек-Паук. Гражданская Война","author":"Дж. Майкл Стражински","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002869818/140/1790/Dzh._Majkl_Strazhinski__Udivitelnyj_ChelovekPauk._Grazhdanskaya_Vojna.jpg","isbn":"978-5-04-097441-2","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Жизнь Питера Паркера ещё никогда не была такой запутанной… и опасной. Прибыв в Стэмфорд на место трагедии, дабы оказать помощь жертвам, Питер неожиданно отправляется с Тони Старком в Вашингтон. Там в Белом доме и будет неминуемо принят Акт о регистрации сверхлюдей. Пока вселенная Marvel готовится к вступлению в силу закона, что навсегда изменит общественный статус супергероев, Питер вынужден сделать личный и очень важный выбор... возможно, самый важный в его жизни. Гражданская Война поделила супергеройское общество на два лагеря, но останется ли Паучок верен своему решению?  В сборник вошли комиксы \"Удивительный Человек Паук\" #532-538, написанные Дж. Майклом Стражински и проиллюстрированные Роном Гарни.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-03","rating":2.5,"review":"","added":9999226,"hdCover":""},{"id":"0989379","title":"Хранители. Начало: Ночная Сова. Доктор Манхэттен. Озимандия (сборник)","author":"Джей Майкл Стражински,Лен Уэйн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002112590/140/b4e4/__Hraniteli._Nachalo_Nochnaya_Sova._Doktor_Manhetten._Ozimandiya_sbornik.jpg","isbn":"978-5-389-09807-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Серия долгожданных приквелов к одному из величайших графических романов всех времен «Хранители» наконец перед вами!  В течение более чем двадцати лет предыстории культовых персонажей Алана Мура и Дэйва Гиббонса оставались загадкой. До сих пор. Но DC Comics собрал команду самых выдающихся творцов в индустрии, которые смогли развернуть мир «Хранителей», протянув в прошлое истории наиболее противоречивых антигероев из когда-либо действовавших на страницах комиксов.  Какой путь прошел Адриан Вейдт, будущий Озимандия, чтобы стать умнейшим человеком на Земле? Кого убрал с этого пути? Какую цену заплатил? На какие жертвы обрек человечество и самого себя? Перед нами бескомпромиссный портрет человека, чье бескорыстное желание спасти испорченную планету было оплачено потерей человечности.  Героем Дэна Драйберга был Ночная Сова — упорный защитник справедливости и воплощение честности. Отчаянное желание сбежать из неблагополучного дома приводит Дэна в дом его кумира — Холлиса Мейсона, человека, скрывающегося под маской Ночной Совы. Впечатлив Мейсона технической смекалкой, Дэн принимает от него эстафету борца с преступностью.  Джон Остерман — педантичный и добросовестный ученый, который в результате страшного несчастного случая при проведении эксперимента, превратился в расщепляющего атом Доктора Манхэттена. Бывший ученый скользит во времени сквозь прошлое, настоящее и будущее. Свободный от всех земных оков, он наблюдает за временными потоками того, что уже произошло, могло произойти и еще только может. Наделенный почти божественными силами и способностью менять мир малейшим движением Доктор Манхэттен сражается за последние капли своей ускользающей человечности.  Безжалостный гений Озимандия, непостижимый Доктор Манхэттен, летящий во тьме Ночная Сова – на страницах второго сборника. Лен Уэйн и Майкл Стражински создали великолепный бэкграунд, подарив классическим образам новую жизнь, а блистательная команда художников в лице Джэ Ли, Энди Кьюберта, Джо Кьюберта, Билла Сенкевича, Адама Хьюза и других, заставили эти образы заиграть новыми красками.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-02","rating":4,"review":"","added":9999225,"hdCover":""},{"id":"0989378","title":"Вселенная DC. Rebirth. Зеленая Стрела. Книга 1: Смерть и жизнь Оливера Квина (сборник)","author":"Бенджамин Перси","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002827756/140/f931/Bendzhamin_Persi__Vselennaya_DC._Rebirth._Zelenaya_Strela._Kniga_1_Smert_i_zhizn.jpg","isbn":"978-5-389-14439-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Репутация Оливера Квина – избалованного миллиардера из Сиэтла, руководителя компании «Квин Индастриз» – оставляет желать лучшего. Но мало кто знает, каков он на самом деле. Ведь по ночам Оливер перевоплощается в Зеленую Стрелу, невозмутимого борца за справедливость, патрулирующего улицы Сиэтла.  И Стреле есть чем заняться – в городе начали пропадать бездомные. Десятки исчезнувших в неизвестном направлении женщин и детей. Кому они нужны и кто считает себя вправе безнаказанно творить зло прямо под носом у полиции? Затеяв свое расследование, Квин выясняет, что не все, кому он доверял, были честны с ним. Подняться с колен, когда тебя предают самые близкие, способен не каждый. Сможет ли Зеленая Стрела найти в себе силы, чтобы разрушить преступный сговор и вернуть обратно свою жизнь?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-01","rating":4,"review":"","added":9999224,"hdCover":""},{"id":"0989377","title":"Вселенная DC. Rebirth. Лига Справедливости. Книга 2. Заражение","author":"Брайан Хитч","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002842647/140/1033/Brajan_Hitch__Vselennaya_DC._Rebirth._Liga_Spravedlivosti._Kniga_2._Zarazhenie.jpg","isbn":"978-5-389-14591-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"После того как состав Лиги Справедливости пополнили Супермен из другого мира и двое молодых и энергичных Зеленых Фонарей, команда стала сильнее, крепче, и перед ней открылись новые перспективы. Никогда еще она не была такой сплоченной, и кажется, теперь ни одному злодею не выстоять перед мощью лучших в мире супергероев.  Но что делать, если враг неосязаем? Если он – компьютерный код, который может обрушить спутник Лиги, взять под контроль Киборга и взломать Кольцо Зеленого Фонаря? Смогут ли герои отследить неуловимый вирус, способный проникнуть в любую систему, и найти его создателя прежде, чем пострадают невинные люди?  Ответы на все эти вопросы ждут вас в сборнике «ЛИГА СПРАВЕДЛИВОСТИ. КНИГА 2. ЗАРАЖЕНИЕ», в котором сценарист БРАЙАН ХИТЧ («ЛИГА СПРАВЕДЛИВОСТИ АМЕРИКИ») и художники НИЛ ЭДВАРДС («ТЕМНЫЕ МСТИТЕЛИ») и ДЭНИЕЛ ЭНРИКЕС («ЛИГА СПРАВЕДЛИВОСТИ АМЕРИКИ») продолжают сагу о главной команде супергероев комиксов. Под этой обложкой собраны выпуски «ЛИГИ СПРАВЕДЛИВОСТИ» #6-11.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-01","rating":2,"review":"","added":9999223,"hdCover":""},{"id":"0989376","title":"Вселенная DC. Rebirth. Лига Справедливости. Книга 1. Машины Уничтожения (сборник)","author":"Брайан Хитч","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002785607/140/264c/Brajan_Hitch__Vselennaya_DC._Rebirth._Liga_Spravedlivosti._Kniga_1._Mashiny_Unic.jpg","isbn":"978-5-389-14447-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Они — величайшие герои в истории нашей планеты. Но самого великого из них больше нет.  Супермен погиб. Человек из Стали отдал свою жизнь, защищая мир, который стал для него родным, и теперь его друзьям придется сражаться без него. Но упавшее знамя подхватил другой Супермен, пришедший к нам из иной, погибшей вселенной.  Впрочем, Бэтмен, Чудо-Женщина, да и другие члены Лиги не спешат признавать его своим союзником. Новому Супермену придется многое доказать. Причем доказать очень скоро. Ведь Землю атакует противник, чье могущество невозможно измерить. И вот-вот придут в действие исполинские механизмы, которые изуродуют поверхность нашей планеты и превратят ее обитателей в живое оружие.  Машины Уничтожения. Чтобы их отключить, потребуются совместные усилия всех членов Лиги Справедливости. Всех до единого.  Суперзвезды комикс-индустрии Брайан Хитч («Лига Справедливости Америки») и Тони С. Дэниел («Супермен/Чудо-Женщина») объединили свои усилия, прокладывая величайшей команде супергероев дорогу в новую эру. «Лига Справедливости. Книга 1. Машины Уничтожения» — настоящий фейерверк среди событий DC Rebirth! В сборник вошли выпуски 1-5 «Лиги Справедливости», а также одиночный выпуск «Лига Справедливости: Rebirth».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-01","rating":2,"review":"","added":9999222,"hdCover":""},{"id":"0989375","title":"Веном. Том 2","author":"Рик Ремендер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002796114/140/7e08/Rik_Remender__Venom._Tom_2.jpg","isbn":"978-5-91878-253-8","publisher":"Фантастика Книжный Клуб","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Посреди Лас-Вегаса открывается портал в Преисподнюю, и теперь Веном должен объединиться с Красным Халком, Икс-23 и Призрачным Гонщиком, чтобы вместе с ними остановить распространение Ада на Земле. Удастся ли четырём небезупречным героям одолеть своих внутренних демонов и сплотиться ради спасения мира в самый тёмный час? Впереди Венома ждёт череда опаснейших испытаний: Преступный Гений, желая уничтожить его, сколотил банду из Джека-Фонарщика, Человека-Мухи, Токсина и других злодеев! Следуя дьявольскому плану вожака, они объявляют семье и друзьям Флэша Томпсона войну, в которой не обойдётся без жертв! Тем временем Веном присоединяется к Тайным Мстителям, но сколько в нём осталось от самого Флэша? Хоть симбиот под контролем, мрачные секреты Томпсона всё же могут погубить его — особенно после возвращения прежнего носителя Венома, Эдди Брока!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-01","rating":3.5,"review":"","added":9999221,"hdCover":""},{"id":"0989374","title":"Веном. Том 1","author":"Рик Ремендер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002072044/140/a511/Rik_Remender__Venom._Tom_1.jpg","isbn":"978-5-91878-177-7","publisher":"Фантастика Книжный Клуб","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Флэш Томпсон — в прошлом задира, а ныне верный друг Питера Паркера — самый большой фанат Человека-Паука. Именно кумир вдохновил его вступить добровольцем в ряды армии США, где он стал героем войны и ветераном, награждённым знаками отличия. Несмотря на утрату ног, Флэш никогда не терял достоинства и желания продолжать службу. Теперь правительство предложило ему шанс стать героем ещё раз, но для этого Томпсону придётся примерить необычный костюм — инопланетного симбиота. Создание-паразит не только даёт своему носителю силы, как у Человека-Паука, но и подвергает опасности полного соединения с собой. Флэш Томпсон — это Веном, смертоносный оперативник правительства, которого посылают в горячие точки против опаснейших врагов государства. Герой и раньше преодолевал трудности, но на этот раз его сильнейшим соперником может оказаться он сам.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-01","rating":4,"review":"","added":9999220,"hdCover":""},{"id":"0989373","title":"Веном. Полное собрание","author":"Дэниел Уэй","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002948886/140/f2c1/Deniel_Uej__Venom._Polnoe_sobranie.jpg","isbn":"978-5-91878-307-8","publisher":"Фантастика Книжный Клуб","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Инопланетный симбиот Веном, одаряющий человека-носителя смертельными сверхспособностями, сливается с людьми, испытывающими сильные низменные эмоции: ярость, ревность и ненависть. Именно они его привлекают. Отделённый от Эдди Брока, заклятый враг Человека-Паука объявляется рядом с полярным кругом — с лёгкостью перепрыгивая с носителя на носителя, он бежит от загадочных сил, имеющих собственные планы на неуловимого пришельца. Пытаясь утолить зверский голод и жажду адреналина, Веном прокладывает кровавую просеку на пути к цивилизации. В северных областях Канады он обращает внимание на невысокого заросшего парня с дурным характером: Росомаху из Людей Икс! А когда место действия переносится в Нью-Йорк, Человек-Паук и Фантастическая четвёрка вынуждены ликвидировать последствия разрушений, вызванных ДВУМЯ кровожадными веномоподобными существами! И входит Эдди Брок! Издание содержит выпуски «Венома» № 1–18, написанные Дэниелом Уэем, иллюстрированные Франсиско Эррерой, Пако Мединой, Шоном Гэллоуэем и Скотти Янгом..","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-01","rating":3.5,"review":"","added":9999219,"hdCover":""},{"id":"0989372","title":"Громовержцы. Полная коллекция","author":"Уоррен Эллис,Майк Деодато","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002541906/140/fd99/__Gromoverzhtsy._Polnaya_kollektsiya.jpg","isbn":"978-5-9909878-2-1","publisher":"Jellyfish Jam","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Громовержцы — команда бывших злодеев, вставших на сторону добра. Они изо всех сил старались заработать доверие публики… но так и не приблизились к своей цели — признание не пришло. Однако после событий Гражданской войны всё изменилось: пора Америке познать силу настоящего правосудия! Страна утратила веру в героев. Теперь она готова поверить в чудовищ. Настал час Громовержцев!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-01","rating":4,"review":"","added":9999218,"hdCover":""},{"id":"0989371","title":"Лига Справедливости. Книга 6. Война Дарксайда. Часть 1","author":"Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002688008/140/36d1/Dzheff_Dzhons__Liga_Spravedlivosti._Kniga_6._Vojna_Darksajda._Chast_1.jpg","isbn":"978-5-389-13723-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Несколько лет назад супергерои создали Лигу Справедливости для борьбы с Дарксайдом и его армией парадемонов. Тогда совместными усилиями им удалось остановить злодея, и Земля была спасена. И вот Дарксайд вновь оказывается на нашей планете, которой суждено стать полем боя с Анти-Монитором – самым разрушительным существом во всей Мультивселенной.  Чудо-Женщина, Супермен, Бэтмен и остальные участники Лиги вместе с Мистером Чудо пытаются предотвратить грядущее сражение. Но когда в битве, результатом которой может стать исчезновение всего сущего, сходятся два воплощения абсолютного зла, даже лучшие из лучших могут оказаться бессильными.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":5,"review":"","added":9999217,"hdCover":""},{"id":"0989370","title":"Арчи. Том 6","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003165064/140/6772/Mark_Uejd__Archi._Tom_6.jpg","isbn":"978-5-04-105955-2","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Комильфо. Арчи (обложка)","genres":["Комиксы","манга","графические романы"],"annotation":"Приближается важнейшее событие в жизни школьников Ривердейла – весенние танцы! А поскольку в городе распались почти все пары, главная интрига заключается в том, кто с кем придёт! Танцы обещают кучу сюрпризов: ребята встречаются и расстаются, Арчи снова играет на гитаре, на сцену выходят \"Джози и Кошечки\", Реджи вынашивает очередной зловредный план, а Би готовится сообщить всем важное известие – но никто и не представляет, что будет дальше! Раскрылась тайна семьи Блоссомов – и она удивит весь Ривердейл, в том числе и Шерил с Джейсоном! Ведь их настоящий отец возвращается, чтобы отомстить. И вернётся он именно в день танцев. Этот роковой вечер станет для всех испытанием! Школьники Ривердейла окажутся в заложниках у отца Блоссомов! Реджи заплатит за свои злодеяния! А когда вам покажется, что всё позади, Ривердейл снова встанет на уши!  В этой книге собраны последние комиксы исторического рана Марка Уэйда на обновлённой серии \"Арчи\". В книгу вошли выпуски \"АРЧИ\" #28–32 от сценаристов МАРКА УЭЙДА (\"Царство небесное\",, \"Чёрная Вдова\") и ИЭНА ФЛИННА (\"Джагхед\", \"Могучие Крестоносцы\") и художницы ОДРИ МОК (\"Джози и Кошечки\", Heroine Chic).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3.5,"review":"","added":9999216,"hdCover":""},{"id":"098936f","title":"Арчи. Том 5","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003165062/140/88a5/Mark_Uejd__Archi._Tom_5.jpg","isbn":"978-5-04-105952-1","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Комильфо. Арчи (обложка)","genres":["Комиксы","манга","графические романы"],"annotation":"Бетти Купер – не просто добросердечная девчушка из соседнего двора. Она – душа Ривердейла. Почему? Узнаете в пятом сборнике признанных и любимых комиксов об Арчи! Ривердейл неспокоен: из-за автокатастрофы всеобщая любимица Бетти Купер оказалась в инвалидном кресле. Город пытается оправиться от потрясения, но все прекрасно понимают, что ничего уже не будет как прежде. Бетти изо всех сил старается вновь встать на ноги, а Реджи Мэнтл теперь изгой, ведь именно его все винят в случившемся. Непростая ситуация раскрывает Бетти глаза: она видит, насколько благородны и добродушны её друзья... а Арчи всё сильнее в неё влюбляется! Но как же Вероника? Дружба и отношения теперь под ударом, судьбы летят под откос, целые семьи рвут связи друг с другом, и только школьники Ривердейла могут спасти город от кризиса.  \"Душа Ривердейла\" – это трогательный сюжет о подлинном смысле дружбы. В пятый том \"Арчи\" вошли выпуски 25–27 от звёздного сценариста МАРКА УЭЙДА (\"Царство небесное\", \"Чёрная Вдова\") и художницы ОДРИ МОК (\"Джози и кошечки\", Heroine Chic).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3.5,"review":"","added":9999215,"hdCover":""},{"id":"098936e","title":"Арчи. Том 4","author":"Марк Уэйд,Пит Вудс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002927863/140/8d11/__Archi._Tom_4.jpg","isbn":"978-5-04-100547-4","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Жизнь Арчи и его лучших друзей изменится навсегда на страницах книги «Под откос», четвёртого сборника обласканного критиками комикс-бестселлера «Арчи». Это один из самых обсуждаемых комиксов последних лет!  Борьба Арчи с его заклятым врагом Реджи Мэнтлом достигает пика: они устраивают гонку, чтобы определить, кто из них настоящий король Ривердейла. Но они понятия не имеют, что в дело вмешается подруга и бывшая девушка Арчи Бетти Купер – и это приведёт к катастрофическим последствиям. Уцелеет ли один из героев в неожиданной схватке со смертью?  Берущая за душу и обладающая всеми характерными для последних комиксов об Арчи история «Под откос» раскрывает истинную природу отношений культовых персонажей. Читатели испытают чувство утраты и узнают, что такое настоящая дружба.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3.5,"review":"","added":9999214,"hdCover":""},{"id":"098936d","title":"Арчи. Том 2","author":"Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002721827/140/15db/Mark_Uejd__Archi._Tom_2.jpg","isbn":"978-5-91339-576-4","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"ПРИКЛЮЧЕНИЯ НОВОГО АРЧИ ПРОДОЛЖАЮТСЯ!  Любимый рыжий герой Америки возвращается в очередном томе новой увлекательной серии «Арчи».  Богатая и неприступная Вероника Лодж привела в Ривердейл бурю… в результате которой всем нужно выбрать сторону, а Арчи Эндрюс застрял в самом эпицентре. От школьного романа до политических интриг, такого Арчи вы ещё не видели!  Суперзвезда серии, автор МАРК УЭЙД объединился с восходящей звездой, художницей ВЕРОНИКОЙ ФИШ, и новыми коллегами в лице ТОМАСА ПИТИЛЛИ и РАЙАНА ДЖЕМПОЛА, чтобы представить современный взгляд на легендарных жителей Ривердейла.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3.5,"review":"","added":9999213,"hdCover":""},{"id":"098936c","title":"Арчи. Том 1","author":"Фиона Стэплз,Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001889110/140/32de/__Archi._Tom_1.jpg","isbn":"978-5-91339-415-6","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Добро пожаловать в новый Ривердейл! Арчи Эндрюс, любимый подросток Америки, перерождается на страницах этого потрясающего сборника первых шести выпусков легендарной серии комиксов.  Встречайте Арчи, ученика средней школы Ривердейла, его чудаковатого друга-обжору Джагхеда, соседскую девчонку Бетти и состоятельную выскочку Веронику Лодж в перезапуске всеми любимого мира «Арчи». Здесь есть всё: любовный треугольник, дружба, юмор, очарование и море веселья в современном ключе.  Над комиксом работали настоящие мастера жанра: сценарист Марк Уэйд («Сорвиголова») и знаменитые художницы: Фиона Стэплз («Сага»), Энни Ву и Вероника Фиш. В первом томе «Арчи» читателей ждёт новый подход к полюбившейся многим концепции «Арчи Комикс», в котором нашлось место всему лучшему из 75-летней истории издательства.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3.5,"review":"","added":9999212,"hdCover":""},{"id":"098936b","title":"Injustice: Боги среди нас. Год второй. Книга 2","author":"Том Тэйлор","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002730435/140/3045/Tom_Tejlor__Injustice_Bogi_sredi_nas._God_vtoroj._Kniga_2.jpg","isbn":"978-5-389-14112-4","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Грядет война между героями, которые некогда были друзьями. Война богов. У сурового диктатора Супермена появляется новый союзник — наводящий ужас Корпус Синестро. Стражи Вселенной не рады действиям Супермена и отправляют Корпус Зеленых Фонарей на помощь альянсу героев, выступивших против его несправедливого режима. Все, от самой грандиозной космической силы до крохотной зеленой пули, будет пущено в ход против обезумевшего бога. Но смерть — не единственный способ остановить его.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":4.5,"review":"","added":9999211,"hdCover":""},{"id":"098936a","title":"Вселенная DC. Rebirth. Лига Справедливости против Отряда Самоубийц","author":"Роб Уильямс,Джошуа Уильямсон,Тим Сили","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002950885/140/7a18/__Vselennaya_DC._Rebirth._Liga_Spravedlivosti_protiv_Otryada_Samoubijts.jpg","isbn":"978-5-389-15251-9","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Самые могущественные супергерои Земли из Лиги Справедливости неустанно сражаются со злодеями, оберегая покой мирных жителей. Но как быть, когда ради дела нужно поступиться моральными принципами? Пригласить Отряд Самоубийц – секретную Опергруппу Икс, действующую под руководством Аманды Уоллер? Ее бойцы не стесняются в выборе средств во имя достижения поставленных целей. И все бы ничего, если бы не Бэтмен.  Темный Рыцарь ни за что не потерпит существования организации подобного рода, и Лига Справедливости его в этом поддержит. Но, пока Лига и Отряд заняты борьбой друг с другом, преступный гений-телепат Максвелл Лорд собирает армию непобедимых злодеев, чтобы с их помощью завладеть опаснейшим оружием и получить полный контроль над миром!  Этот остросюжетный кроссовер с участием величайших героев и злодеев в истории DC создан звездной командой авторов, включающей писателей Джошуа Уильямсона, Тима Сили, Роба Уильямса и Сая Спурье, крупнейших художников Джейсона Фейбока, Тони С. Дэниела, Хесуса Мерино, Фернандо Пасарина, Робсона Роша, Говарда Портера, Скота Итона, Райли Россмо, Кристиана Дусэ и Джузеппе Кафаро.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3.5,"review":"","added":9999210,"hdCover":""},{"id":"0989369","title":"Дэдпул MAX. Полное издание","author":"Дэвид Лэпхем,Шон Кристал,Кайл Бейкер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002946167/140/8ee1/__Dedpul_MAX._Polnoe_izdanie.jpg","isbn":"978-5-04-099065-8","publisher":"Эксмо, Комильфо","pubDate":"2019","language":"Русский","series":"Дэдпул. Полные издания","genres":["Комиксы","манга","графические романы"],"annotation":"Суди психа по делам его!  Уэйд Уилсон — самый опасный и ценный наёмник, работающий на Дядю Сэма. но ему, как, например, автомату Калашникова, нужна рука, которая не позволит ему бить мимо цели. Следить за тем, чтобы Дэдпул выполнял порученные ему задания во что бы то ни стало, — работа Боба. Но помимо этого, именно ему приходится ещё и получать за двоих — его сломанные кости и психологические травмы тому доказательство.  Этот психопатический дуэт становится на путь саморазрушения, попутно уничтожая бандитов, террористов, правительство, шлюшек с пушками, собственное жуткое прошлое и своих возлюбленных. И всё это ради борьбы за свободу, во время которой им придётся столкнуться со всем ужасом, накопившимся в их собственных душах.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3,"review":"","added":9999209,"hdCover":""},{"id":"0989368","title":"Мстители","author":"Джордж Перес,Курт Бьюсик, Алекс Росс","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002950979/140/51ef/__Mstiteli.jpg","isbn":"9772619134209-002","publisher":"Hachette","pubDate":"2019","language":"Русский","series":"Супергерои Марвел. Официальная коллекция.","genres":["Детские книги"],"annotation":"Когда начинаются новые, смутные времена, а со злодеями, угрожающими человечеству, уже не справиться в одиночку, величайшие герои Вселенной Marvel объединяются в непобедимую боевую команду Мстителей. В этом выпуске вы узнаете о том, как команда впервые собралась для битвы с богом Локи, а также станете свидетелями одного из самых масштабных сражений команды с суперзлодеем-металоманьяком Альтроном и полчищами его роботов-копий.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3,"review":"","added":9999208,"hdCover":""},{"id":"0989367","title":"Паучьи миры","author":"Питер Дэвид,Кристос Гейдж,Дэн Слотт,Дэннис Хоуплесс,Майк Коста,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003003193/140/197f/__Pauchi_miry.jpg","isbn":"978-5-91339-596-2","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"ПОПАДАНКИ","genres":["Комиксы","манга","графические романы"],"annotation":"Один из смертоноснейших врагов Паучка снова вернулся. Но на этот раз он не один. Вся семья Морлана, зовущая себя Наследниками, несётся по всей мультивселенной, питаясь жизненными силами суперлюдей-арахнидов. И они не остановятся, пока не поглотят каждого Человека-Паука! Ни один герой не сможет выжить. Чтобы дать хоть какой-нибудь отпор, Паукам придётся объединиться - от Удивительного до Непревзойдённого, от Необычайного до Сенсационного, от Дружелюбного Соседа до Совершенного, от 1602 до 2099. Мультяшные Пауки! Пауки-Клоны! Пауки в крутых костюмах! Даже Космический Паук! В этом событии вы встретите всех, начиная с давних любимчиков, таких как Бен Рейли, и - да! - Свина-Паука, заканчивая новыми звёздами, такими как огромный робот ПА//к и впечатляюще крутая Гвен-Паук. Присоединяйтесь к Женщине-Пауку, Алому Пауку, Шёлк, Человеку-Пауку 2099, Совершенному Человеку-Пауку, вырванному из своего времени, Непревзойдённому Человеку-Пауку, Девушкам-Паукам из настоящего и будущего, и - разумеется - единственному и неповторимому Человеку-Пауку в команде стенолазов всех времён и миров.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019","rating":3.5,"review":"","added":9999207,"hdCover":""},{"id":"0989366","title":"Вселенная DC. Rebirth. Бэтмен: Ночь людей-монстров","author":"Стив Орландо,Том Кинг","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002824663/140/8aab/__Vselennaya_DC._Rebirth._Betmen_Noch_lyudejmonstrov.jpg","isbn":"978-5-389-14886-4","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Бэт-команда спасает Готэм, но на этот раз угроза нависла не только над жителями города, но и над теми, кто занимается их спасением…  Метеосводки не радуют жителей Готэма: на город надвигается буря, и некоторые его районы вот-вот окажутся под водой. Полиция с помощью плащеносцев начинает масштабную эвакуацию. Никто из героев даже не подозревает, что капризы погоды – это не самое страшное, с чем им доведется столкнуться этой ночью.  «Бэтмен: Ночь людей-монстров» – первый кроссовер в истории DC Rebirth, созданный командой в лице СТИВА ОРЛАНДО («MIDNIGHTER»), ТОМА КИНГА («BATMAN»), ТИМА СИЛИ («BATMAN ETERNAL»), ДЖЕЙМСА ТАЙНИОНА IV («DETECTIVE COMICS»), РАЙЛИ РОССМО («CONSTANTINE: THE HELLBLAZER»), РОЖЕ АНТОНИО («BATGIRL AND THE BIRDS OF PREY») и ЭНДИ МАКДОНАЛЬДА («THE NEW 52: FUTURE''S END»).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018-12","rating":3.5,"review":"","added":9999206,"hdCover":""},{"id":"0989365","title":"Вселенная DC. Rebirth. Издание делюкс","author":"Джефф Джонс,Гэри Фрэнк","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002785570/140/244a/__Vselennaya_DC._Rebirth._Izdanie_delyuks.jpg","isbn":"978-5-389-14412-5","publisher":"Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графический роман","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"В результате событий Флэшпойнта история пошатнулась. Неведомый враг воспользовался этим сбоем и украл у человечества десять лет жизни. Флэш Уолли Уэст оказался заперт во временной ловушке. Скитаясь внутри Силы Скорости, он увидел, насколько сильно изменилась вся вселенная. Уолли во что бы то ни стало нужно вернуться домой, чтобы спасти мир от очередного нападения незнакомцев. Но есть серьезная проблема: Уолли Уэст забыт! Никто из друзей не узнает его, а отпущенные ему минуты тают на глазах. Совсем скоро он не сумеет назвать даже своего имени и навсегда растворится во времени.  Как заставить хоть кого-нибудь тебя вспомнить, если даже самые близкие не догадываются от твоем существовании?  Делюкс-издание «ВСЕЛЕННАЯ DC: REBIRTH» положило начало одному из наиболее понравившихся критикам перезапусков в истории. Сценарий написал самый продаваемый автор, по версии «New York Times», ДЖЕФФ ДЖОНС («Лига Справедливости»), а иллюстрации создали четыре величайших художника в индустрии комиксов: ИВАН РЕЙС («Аквамен»), ГЭРИ ФРЭНК («Бэтмен: Земля-1»), ИТАН ВАН СКАЙВЕР («Зеленый Фонарь. Возрождение») и ФИЛ ХИМЕНЕС («Бесконечный Кризис»). Последствия развернувшихся в этой книге событий еще долгие годы будут оказывать влияние на всю вселенную DC!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018-12","rating":4,"review":"","added":9999205,"hdCover":""},{"id":"0989364","title":"Вселенная DC. Rebirth. Бэтмен. Книга 2. Я - самоубийца (сборник)","author":"Том Кинг","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002842642/140/ef69/Tom_King__Vselennaya_DC._Rebirth._Betmen._Kniga_2._Ya__samoubijtsa_sbornik.jpg","isbn":"978-5-389-14442-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Бэтмен и его личный отряд самоубийц.  Он – единственный, кому однажды удалось одержать верх над Бэтменом. Он правит островной тюрьмой, в которой когда-то был узником. Он – Бэйн, и у него есть тот, кто нужен Бэтмену, чтобы спасти человека, который нуждается в его помощи. Однако проникнуть в цитадель преступного гения не самая простая задача. Для этого Бэтмену необходима собственная армия злоумышленников, включая Женщину-Кошку. И все бы ничего, но на деле оказывается, что Женщине-Кошке доверять опасно и что собранная в лечебнице Аркхем команда так же неуправляема, как и настоящий Отряд Самоубийц. Раздираемые страстями, подверженные нездоровым привычкам, склонные к безумию и предательству члены отряда Бэтмена рискуют провалить операцию и вернуться с задания не в полном составе…  Лучший сценарист, по мнению «New York Times», Том Кинг («Люди-омега»), а также художники Микель Ханин («Грейсон») и Митч Герадс («Шериф Вавилона») продолжают свою грандиозную сагу о Темном Рыцаре. В сборник вошли выпуски «Бэтмен» #9–15.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018-11","rating":3.5,"review":"","added":9999204,"hdCover":""},{"id":"0989363","title":"Вселенная DC. Rebirth. Бэтмен. Книга 1. Я – Готэм (сборник)","author":"Том Кинг","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002772268/140/adac/Tom_King__Vselennaya_DC._Rebirth._Betmen._Kniga_1._Ya__Gotem_sbornik.jpg","isbn":"978-5-389-14169-8","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Он – Бэтмен, главный защитник Готэма. Но теперь Бэтмен не один. На стражу города встали два новых героя – Готэм и Готэм-Герл, которые могут сравниться по своим силам с самим Суперменом. Однако зло не дремлет – оно способно затуманить рассудок даже самоотверженным храбрецам. Как Готэму и Готэм-Герл понять, на чьей они стороне? Ведь, если они решат, что Темный Рыцарь сам виноват в тех ужасах, которые происходят на улицах Готэма, кто тогда защит город?..  Прославленные Том Кинг («Грейсон») и Дэвид Финч («Чудо-женщина»), а также их не менее звездные коллеги Скотт Снайдер («Бэтмен»), Иван Рейс («Лига справедливости») и Микель Ханин («Грейсон») представляют начало новой саги о Темном Рыцаре «Бэтмен. Книга 1. Я – Готэм», открывающей новую вселенную «DC Universe. Rebirth» и включающей в себя «Бэтмен. Rebirth» № 1 и «Бэтмен» № 1-6.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018-11","rating":4,"review":"","added":9999203,"hdCover":""},{"id":"0989362","title":"Чёрный молот. Том 1. Тайна происхождения","author":"Джефф Лемир","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002607372/140/859b/Dzheff_Lemir__Chjornyj_molot._Tom_1._Tajna_proishozhdeniya.jpg","isbn":"978-5-91339-545-0","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Забытые герои Спираль-Сити оказались за пределами своего супергеройского мира из-за кризиса мультивселенной. Теперь они - раздираемая противоречиями семья, которая живёт на загадочной ферме в маленьком городе и не может вернуться обратно.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018-05","rating":3.5,"review":"","added":9999202,"hdCover":""},{"id":"0989361","title":"Округ Хэрроу. Том 1. Бесчисленные духи","author":"Каллен Банн,Тайлер Крук","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001988486/140/d727/__Okrug_Herrou._Tom_1._Beschislennye_duhi.jpg","isbn":"978-5-91996-099-7","publisher":"XL Media","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Ужасы"],"annotation":"Добро пожаловать в округ Хэрроу!  Эмми с рождения слышала истории о том, что в лесах округа Хэрроу обитают странные чудовища и духи. Но в день своего восемнадцатилетия девушка понимает, что это не выдумки и что ее и призрачных обитателей лесов что-то связывает. Эмми еще не знает, что она — реинкарнация могущественной ведьмы Хестер Бек, убитой давным-давно жителями округа, и что вскоре грядет ее пробуждение, сулящее гибель всему живущему...  Перед вами блестящий образец «южной готики», написанный Калленом Банном (серия The Sixth Gun) и нарисованный Тайлером Круком (серии B.P.R.D. и Witchfinder), страшный и увлекательный, заново переосмысляющий жанр хоррора и удостоившийся хвалебных отзывов.  В первую книгу вошла первая сюжетная арка \"Бесчисленные духи\" и множество дополнительных материалов: наброски персонажей и зарисовки, мини-комиксы, воспоминания создателей, а так же отрывок из повести, легшей в основу комикса.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018-04","rating":4.5,"review":"","added":9999201,"hdCover":""},{"id":"0989360","title":"Максимум резни","author":"Том ДеФалко,Терри Кавана,Дэвид Мишлени,Дж. М. ДеМаттейс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002688743/140/ba09/__Maksimum_rezni.jpg","isbn":"978-5-91339-559-7","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Отродье Венома собирает армию психически неуравновешенных врагов Человека-Паука (Падаль, Демогоблин, Визг и Доппельгангер Человека-Паука), дабы передать своё послание, предвещающее начало правления зла, хаоса и всепоглощающей резни. Оказавшись в меньшинстве, стенолаз должен собрать свою команду, чтобы дать отпор восходящей волне насилия. Его союзниками станут Чёрная Кошка, Плащ и Кинжал, Огненная Звезда, Капитан Америка, Дэтлок и... Веном?! Злейший враг Человека-Паука становится его ненадёжным товарищем в борьбе с безумным и жестоким Карнажем. Но когда начинаются ссоры с партнёрами по команде, желающими прикончить Карнажа и его банду раз и навсегда, Пауку приходится решить, нарушить ли свой личный кодекс чести или же избавить мир от чистого зла. Сможет ли паутиноплёт найти иное решение, пока ещё не слишком поздно? Любой выбор обернётся последствиями.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018-03","rating":4,"review":"","added":9999200,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098935f","title":"Лига Справедливости. Дарксайд: Апофеоз","author":"Грег Пак, Пауло Сикейра, Нето Диас","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002704473/140/06d7/Greg_Pak_Paulo_Sikejra_Neto_Dias__Liga_Spravedlivosti._Darksajd_Apofeoz.jpg","isbn":"978-5-389-13835-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Кто такие Старые и Новые боги, как появилась планета Апоколипс, и какие тайны хранит прошлое одного из ключевых злодеев вселенной DC? Все ответы в истории происхождения могущественного злодея Дарксайда…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3.5,"review":"","added":9999199,"hdCover":""},{"id":"098935e","title":"Лига Справедливости. Тайное Общество: Дикая карта","author":"Джефф Джонс,Симон Кудрански,Стерлинг Гейтс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002188066/140/35b4/__Liga_Spravedlivosti._Tajnoe_Obschestvo_Dikaya_karta.jpg","isbn":"978-5-389-12970-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Перед вами фрагмент масштабной истории, который добавит несколько интересных нюансов в общий сюжет «Лиги справедливости».  В сингле рассказывается история Оулмена, Найтвинга и Джокера с Земли-3, поэтому чтение необходимо начать после знакомства с содержанием комиксов «Вечное зло» и «Вечные герои».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3.5,"review":"","added":9999198,"hdCover":""},{"id":"098935d","title":"Паучок. Первый день","author":"Робби Томпсон,Nick Bradshaw","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002488069/140/c788/__Pauchok._Pervyj_den.jpg","isbn":"978-5-91339-544-3","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Это смесь из сражений, приключений и юмора в равных пропорциях, ведь мы возвращаемся в школу, чтобы посмотреть на первые деньки Пита! Современный талант вместе с ноткой классики Marvel представляет вам ранние годы паутинного чуда в поистине удивительной, поразительной и сенсационной манере. Возвращение хлопот из-за несделанной домашки и смущения, не дающего заговорить с девчонками, и крутящаяся без остановки карусель безумия, состоящая из подборки лучших злодеев в комиксах, каждый из которых невероятнее предыдущего. Вам понравится смотреть на то, как Паучок дерется с Доктором Осьминогом и тонет в Песочном Человеке - ходячем пляже. Увидев кучу знакомых и неожиданных лиц из прошлого Питера, вы вспомните, что на самом деле делает Человека-Паука величайшим героем!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3,"review":"","added":9999197,"hdCover":""},{"id":"098935c","title":"Арчи. Том 3","author":"Марк Уэйд,Джо Эйсма","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002823771/140/4218/__Archi._Tom_3.jpg","isbn":"978-5-04-094338-8","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Комильфо. Арчи (обложка)","genres":["Комиксы","манга","графические романы"],"annotation":"Рыжеволосая хищница Шерил Блоссом совершает свой дебют в перезагруженной вселенной Арчи! Третья книга популярных комиксов \"Арчи\" набита удивительными сюжетными поворотами и непредсказуемыми интригами. Ох уж эта Шерил, вы у нее все будете по струнке ходить! Коварная красотка выходит на авансцену в тот самый момент, когда у Арчи и Вероники начинаются проблемы в отношениях!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3.5,"review":"","added":9999196,"hdCover":""},{"id":"098935b","title":"Харли Квинн. Книга 3. Поцелуй навылет","author":"Аманда Коннер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002341300/140/2179/Amanda_Konner__Harli_Kvinn._Kniga_3._Potseluj_navylet.jpg","isbn":"978-5-389-12538-4","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Работа психиатром, управление многоквартирным домом с кучей надоедливых жильцов и неугомонных домашних питомцев, турниры по роллер-дерби, попытки наладить личную жизнь — у Харли Квинн почти не остается времени творить добро во благо человечества. Пора передать часть полномочий личной команде помощниц!  Но только лучшие заслужат право нести в массы моральные принципы Харли: честь, верность и полное непокорство. Отбор кандидатов обещает быть жестким... и кровавым!  Однако это еще не все! В этой книге Харли отправится вызволять из лечебницы Аркхем свою закадычную подругу Ядовитого Плюща, без памяти влюбится в удалого миллионера Брюса Уэйна и научит нас, как надо справлять праздники.  Приключения всеми обожаемой сумасбродки в большом городе продолжаются в томе «Харли Квинн. Книга 3: Поцелуй навылет», над которым работали знаменитые сценаристы Аманда Коннер и Джимми Пальмиотти и художники Чед Хардин и Джон Тиммс, а также приглашенные художники Бен Колдуэлл, Дарвин Кук, Брэндт Питерс и другие. В книгу вошли выпуски 14–16, первый ежегодник и спецвыпуски к Рождеству и Дню святого Валентина.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":2.5,"review":"","added":9999195,"hdCover":""},{"id":"098935a","title":"Injustice: Боги среди нас. Год второй. Книга 1","author":"Том Тэйлор","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002591671/140/61f2/Tom_Tejlor__Injustice_Bogi_sredi_nas._God_vtoroj._Kniga_1.jpg","isbn":"978-5-389-13607-6","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Прошел год с тех пор, как Супермен объявил полномасштабную войну мировому злу на Земле. И битва только началась.  После тяжелой борьбы, лидер сопротивления Бэтмен сломлен. Чудо-Женщина находится в глубокой коме. Зеленая Стрела мертв. Правительство Соединенных Штатов объявило войну Человеку из Стали и его Лиге Справедливости – и эта война приобретает все более невообразимые масшатбы.  На мрачных улицах Готэма, комиссар Гордон и его дочь, некогда носившая маску Бэтгерл, а ныне компьютерный гений под кодовым именем Оракул, возглавляют команду борцов с преступностью «Хищные Птицы» и организуют сопротивление города диктатуре Супермена.  Тем временем новое вторжение грядет из бескрайних глубин космоса. Бессмертные всемогущие создания, именуемые Стражами, обеспокоены растущей агрессией Супермена, и отправляют целый Корпус Зеленых Фонарей для урегулирования конфликта.  Но прежде чем закончится этот год, Супермен всех заставит считаться со своей властью...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999194,"hdCover":""},{"id":"0989359","title":"Injustice: Боги среди нас. Год первый. Книга 2","author":"Том Тэйлор","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002341264/140/b5f3/Tom_Tejlor__Injustice_Bogi_sredi_nas._God_pervyj._Kniga_2.jpg","isbn":"978-5-389-12959-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Наступила эпоха правления Супермена.  Человек из Стали покончил со смертельной угрозой в лице Джокера, но его бесконечная борьба с несправедливостью приобретает все более жесткий характер. Супермен и его могущественные союзники – Чудо-Женщина, Зеленый Фонарь, Флэш, Шазам и Робин – пресекают мировые конфликты в зародыше и наказывают преступников без всякой пощады.  Однако Бэтмену не по душе столь агрессивные методы. Темный Рыцарь призывает в союзники героев, готовых противостоять Человеку Будущего.  Земля на пороге новой войны. Но на этот раз не по вине политиков. Командовать в ней будут не военные, а на поле брани выйдут не обычные солдаты. Это будет битва супергероев. Битва богов.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4.5,"review":"","added":9999193,"hdCover":""},{"id":"0989358","title":"Injustice: Боги среди нас. Год первый. Книга 1","author":"Том Тэйлор","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002225098/140/25e7/Tom_Tejlor__Injustice_Bogi_sredi_nas._God_pervyj._Kniga_1.jpg","isbn":"978-5-389-11513-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"ВЫ ЗНАЕТЕ ЭТУ ИГРУ, НО ВЫ НЕ ЗНАЕТЕ ВСЕЙ ИСТОРИИ.  Откройте для себя истоки мегапопулярного файтинга от создателей «MORTAL KOMBAT»!  Супермен считался величайшим героем Земли. Но когда Человек из Стали не сумел уберечь тех, кто был ему дороже всего на свете, он оставил попытки спасти человечество… и начал править планетой взял власть над планетой в свои руки .  Отныне последний сын Криптона намерен насаждать мир любыми средствами. И единственный, кто выступает против абсолютной власти Супермена, — Бэтмен. Темный Рыцарь пойдет на все, чтобы не позволить прежнему другу загнать жизнь в уродливые рамки диктатуры сверхлюдей.  Как и вдохновившая ее игра, «Несправедливость. Боги среди нас. Книга 1» насыщена действием и описывает свихнувшийся мир, где богоподобные создания пытаются железной рукой навести порядок. История, написанная Томом Тэйлором («ЗЕМЛЯ-2») и нарисованная Джереми Раапаком («ОБИТЕЛЬ ЗЛА»), Майком С. Миллером («БЭТМЕН: СВИХНУВШИЙСЯ АРКХЕМ») и другими художниками, откроет вам супергероев вселенной DC с совершенно новой стороны!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4.5,"review":"","added":9999192,"hdCover":""},{"id":"0989357","title":"Бэтмен. Земля-1. Книга 2","author":"Джефф Джонс,Гэри Фрэнк","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001466698/140/ed3a/__Betmen._Zemlya1._Kniga_2.jpg","isbn":"978-5-389-10482-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Темный Рыцарь должен ответить на величайшую загадку: кто же такой Бэтмен?  В Готэм пришли перемены. Смерть мэра Освальда Кобблпота и появление так называемого «Бэтмена» проливает свет на темную и прогнившую суть Готэма. Новый мэр Джессика Дент, её брат, окружной прокурор Харви Дент, Темный Рыцарь и детектив Джим Гордон ведут борьбу против Готэмских преступных группировок. Но тут появляется новый враг — враг, играющий со своими жертвами в загадки.  Неправильный ответ — и ты умрешь. Ответишь правильно — и...  Команда, создавшая безусловный шедевр и бестселлер № 1 по версии New York Times «Бэтмен. Земля-1. Книга 1», писатель Джефф Джонс и художник Гэри Фрэнк представляют читателям когорту знаменитых врагов Бэтмена — известных и неожиданных в своей новой интерпретации.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4.5,"review":"","added":9999191,"hdCover":""},{"id":"0989356","title":"Бэтмен. Земля-1. Книга 1","author":"Джефф Джонс,Гэри Фрэнк","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001131166/140/c57c/__Betmen._Zemlya1._Kniga_1.jpg","isbn":"978-5-389-07957-1","publisher":"Азбука, Азбука-Аттикус","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Бэтмен не герой. Он обычный человек. Обозленный, уязвимый, потерянный. В Готэме, где порой бывает трудно отличить друзей от врагов, Брюсу Уэйну скоро предстоит стать Бэтменом. Пожалуй, никогда еще на этом пути его не ожидало столько препятствий. Но отчаянное желание отомстить убийцам родителей и продажным полицейским придает ему сил, и даже Альфред не в силах его образумить. В новом графическом романе от DC Гэри Фрэнк и Джефф Джонс переосмысливают легенду о Темном Рыцаре, продолжая традицию известного бестселлера «Супермен. Земля-1».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4.5,"review":"","added":9999190,"hdCover":""},{"id":"0989355","title":"Защитники. Том 1","author":"Мэтт Фрэкшн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002703151/140/d1b2/Mett_Frekshn__Zaschitniki._Tom_1.jpg","isbn":"978-5-699-99840-1","publisher":"Fanzon","pubDate":"2017","language":"Русский","series":"Комиксы. Кино","genres":["Комиксы","манга","графические романы"],"annotation":"Супергероям-неудачникам придется объединиться, чтобы раскрыть загадочный заговор в самом сердце Вселенной Marvel и узнать, чем грозят миру Машины согласия. Мэтт Фрэкшн (\"Страх во плоти\", \"Могучий Тор\", \"Непобедимый Железный человек\") вновь присоединяется к автору серии \"Невообразимых Людей Икс\" Терри Додсону (\"Потрясающий Человек-Паук\"), чтобы вдохнуть новую жизнь в самых могучих изгоев Marvel! Вашему вниманию предстают совершенно новые, другие и энергичные \"Защитники\"!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":1.5,"review":"","added":9999189,"hdCover":""},{"id":"0989354","title":"Чёрная Пантера: Народ под нашими ногами. Книга 1","author":"Та-Нехаси Коатс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002698273/140/31e7/TaNehasi_Koats__Chjornaya_Pantera_Narod_pod_nashimi_nogami._Kniga_1.jpg","isbn":"978-5-699-98981-2","publisher":"Fanzon","pubDate":"2017","language":"Русский","series":"Комиксы. Кино","genres":["Комиксы","манга","графические романы"],"annotation":"Т’Чалла сталкивается с массовыми волнениями по всей Ваканде, однако эти невзгоды лишь сплотят страну как никогда раньше! Террористическая организация \"Народ\" во главе с суперлюдьми зажигает пламя восстания, и страна, известная на весь мир своими невероятными технологиями и древними воинскими традициями, взрывается подобно пороховой бочке. Но когда от действий террористов-смертников начинают погибать люди, и Т‘Чалла объединяет нацию против врага, выясняется, что всё это дело рук давно знакомого злодея.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":2,"review":"","added":9999188,"hdCover":""},{"id":"0989353","title":"Железный Человек. Том 3. Тайное происхождение Тони Старка. Книга 2","author":"Кирон Гиллен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002267291/140/5b50/Kiron_Gillen__Zheleznyj_Chelovek._Tom_3._Tajnoe_proishozhdenie_Toni_Starka._Knig.jpg","isbn":"978-5-91339-509-2","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Всё началось с рождения! Хотя пришелец 451, ловко манипулирующий людьми, раскрыл свои тайные мотивы, Тони ждал огромный сюрприз на пустынном поле боя начала времён. Теперь всё, что нужно сделать Железному Человеку, — это одолеть робота, который в любой момент может взять его костюм под контроль. а также уйти от самого опасного охотника за головами во вселенной, Черепа! Невероятно сложный выбор на  краю космоса решит судьбу двух миров. Кто  будет жить? Кто  умрёт? Сможет ли Тони обмануть свою судьбу, прежде чем всё пойдёт под откос? Тони и 451 открывают неожиданную истину, и всё изменяется навсегда!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3,"review":"","added":9999187,"hdCover":""},{"id":"0989352","title":"Железный Человек. Том 2. Тайное происхождение Тони Старка (сборник)","author":"Кирон Гиллен,Грег Ленд,Дэйл Иглшэм","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002020877/140/707b/__Zheleznyj_Chelovek._Tom_2._Tajnoe_proishozhdenie_Toni_Starka_sbornik.jpg","isbn":"978-5-91339-458-3","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Представьте: Тони Старк. В баре. С девушками. Что может пойти не так? Даже героически путешествуя по звёздам, Бронированному Мстителю придётся столкнуться с неожиданными последствиями его роли в Мстителях против Людей-Икс! После этого начинается история, которая потрясёт Железного Человека до глубины души! Много лет назад у Говарда и Марии Старк родился ребёнок, но кое-чего вы не знаете. Узнайте правду о Лас-Вегасе и Зоне 52, где сталкиваются два великих мифа Невады. Тем временем в далёкой галактике Тони Старк кричит!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3,"review":"","added":9999186,"hdCover":""},{"id":"0989351","title":"Звёздные войны. Дарт Вейдер и тюрьма-призрак","author":"Хейден Блэкман, Августин Алессио","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001455853/140/af5a/Hejden_Blekman_Avgustin_Alessio__Zvjozdnye_vojny._Dart_Vejder_i_tyurmaprizrak.jpg","isbn":"978-5-17-093398-3","publisher":"АСТ","pubDate":"2015","language":"Русский","series":"Звёздные Войны. Графический роман","genres":["Комиксы","манга","графические романы"],"annotation":"Звёздные Войны» — фантастическая сага Джорджа Лукаса, ставшая каноном жанра космической оперы. История битвы добра со злом, развернувшейся на просторах далёкой-далёкой галактики, покорила сердца не одного поколения. Дарт Вейдер — главный герой саги, коварный и беспощадный личный палач Императора. Трагическая история его судьбы известна фанатам из киноэпопеи и полна противоречий, но мало рассказано о становлении тёмного владыки после падения Республики. «Тюрьма-призрак» проливает свет на эту тайну. Вейдеру предстоит сломить сопротивление в рядах имперской армии, отыскать тайную тюрьму джедаев и даже обзавестись учеником.\nУдивительный Человек-Паук. Том 2. Паучьи миры. Пролог;Кристос Гейдж,Дэн Слотт;2018 г.;3.5;978-5-91339-987-3;Комиксы, манга, графические романы;Комильфо;2017;Русский;;В 2099-м году Отто Октавиус — Совершенный Человек-Паук — идёт по следу из мёртвых пауков по всей мультивселенной. Смерти приводят его к злодею Карну, он вступает с ним в бой, но затем понимает, что тот в разы сильнее! Потерянному во времени Совершенному Паучку придётся собрать армию союзников, но хватит ли их, чтобы разрушить планы Карна? Тем временем настоящий Человек-Паук объединяется с Мисс Марвел в приключении высокого полёта (в случае с Камалой — высокого шагания)! Сможет ли Мисс Марвел выручить Паучка? Плюс: Девушка-Паук из MC2 и Человек-Паук из 1602 становятся жертвами нападения мистических сил, что за гранью Паучьих Миров! И кто такой Паук-Британия? Путь к Паучьим Мирам начинается здесь.\nMortal Kombat X. Книга 3. Кровавый остров;Шон Киттелсен;2018 г.;3.5;978-5-389-11978-9;Комиксы, манга, графические романы;Азбука;2016;Русский;Графические романы;Путь кинжалов Камидогу продолжается…  Бог грома Рейден и его избранные чемпионы хранят Земное царство от вторжения одного из Старших богов – злобного Шиннока с его армией мертвецов. Но от берегов острова Шан Цуна расходятся волны новой угрозы: Хавик, жрец Хаоса, в союзе с генералом Рейко, одержимом магией кинжалов Камидогу, вознамерился завладеть Амулетом Шиннока. Магия крови подчинила себе уже многих, среди них и дочь Сони Блейд и Джонни Кейджа, ее подруга Джакс, – и даже сам Рейден… Предотвратить превращение Рейко в Бога Крови и помешать Хавику добраться до Амулета, величайшие бойцы Земного царства и Внешнего мира должны смирить старую ненависть и объединить силы. Но даже объединенный усилий Коталь Кана, Милины, Джонни Кейджа, Сони Блейд и Ермака недостаточно для победы над столь могущественными врагами. Все надежды Земли на спасение теперь возложены на юного Такеду, ученика погибшего Скорпиона…\nMortal Kombat X. Книга 2. Кровавые боги;Шон Киттелсен;2018 г.;3.5;978-5-389-11163-9;Комиксы, манга, графические романы;Азбука, Азбука-Аттикус;2016;Русский;Графические романы;Великие перемены грядут как для Внешнего мира, так и для Земного царства. Стремятся ли герои, вовлеченные в конфликт, защитить мир богов и людей, или рвутся властвовать на ним, – кровавая развязка неизбежна. Надеясь отвратить надвигающееся зло, бог грома Рейден отправляет Ханзо Хасаши – Скорпиона – и его ученика Такеду Такахаши, собрать мистические кинжалы Камидогу. Этот путь сводит Скорпиона со старым врагом, который похитил один из проклятых клинков. Куай Лян, ниндзя, больше известный как Саб-Зиро, одержим магией крови, заключенной в кинжалах Камидогу, а Скорпион одержим местью! Эти двое встретятся для решающего поединка.  А где-то в другом месте император Коталь Кан принимает вызов, брошенный его власти племенем шоканов. Король Горбак возглавляет армию шоканов и воинов-они, армию достаточно могучую, чтобы свергнуть императора Внешнего мира. А Коталь Кан не желает снова использовать магию крови, пока под его покровительством находятся земляне – Джонни Кейдж и Соня Блейд – решительно настроенные вырвать свою похищенную дочь из лап злодея Рейко. Но сначала им придется помочь Коталь Кану защитить трон… Что означает союз с Кано и Черным Драконом!  Сценарист Шон Киттелсен продолжает свой эпический дебют с помощью таких художников как Декстер Сой («ВСЕЛЕННАЯ DC ПРОТИВ ПОВЕЛИТЕЛЕЙ ВСЕЛЕННОЙ»), Игор Виторино («Зеленый Шершень») и Дэниел Сампере («Бэтгерл»), нарисовавших эту пропитанную кровью историю, которая возникла на феномене видеоигры MORTAL KOMBAT X: КРОВАВЫЕ БОГИ! (Издание включает выпуски 5-8).\nMortal Kombat X. Книга 1. Кровавые узы;Шон Киттелсен,Декстер Сой,Вероника Гандини;2018 г.;4;978-5-389-09931-9;Комиксы, манга, графические романы;Азбука, Азбука-Аттикус;2015;Русский;Графические романы;Хрупкий мир между сферами держался много лет. Достаточно долго, чтобы ушли прежние чемпионы и подросло новое поколение. Но мир не может длиться вечно во вселенной Mortal Kombat! Бог грома Рейден поражен видениями великого зла, входящего в наш мир, зла настолько могущественного, что его появление изменит лицо мироздания. Надежда остановить эту зловещую силу заключена в древних реликвиях, мистических клинках, пропитанных кровью Единой Сущности, — кинжалах Камидогу. Но магия крови в этих всесильных лезвиях слишком опасна — она насылает кровожадное безумие на тех, кто пытается завладеть ими. И в то время как одни будут стремиться использовать лезвия для защиты своих миров, другие намерены использовать их огромную силу в своекорыстных целях. А кинжалы Камидогу не только содержат божественную кровь, они также имеют власть создавать богов... К полюбившимся персонажам — Скорпиону, Саб-Зиро, Горо и другим — присоединяются совершенно новые бойцы, чтобы решить будущее нашего мира в этом докрасна раскаленном дебюте сценариста Шона Киттелсена, при участии художников Декстера Соя («Вселенная DC против Повелителей Вселенной») и Вероники Гандини («Лига Справедливости за пределами 2.0»). Эти люди открыли новую футуристическую главу кровавой саги Mortal Kombat!\nДэдпул. Минибус;Каллен Банн,Далибор Таладжич,Маттео Лолли,Рамон Росаньес,Сальвадор Эспин,показать всех;2018 г.;3;978-5-91339-556-6;Комиксы, манга, графические романы;Комильфо;2017;Русский;;Всё началось с истории, которая называлась не иначе как Дэдпул уничтожает вселенную Marvel\". (Спойлеры!) Представьте себе мир, в котором опасный новый голос проникает в сознание Уэйда Уилсона. Голос, который заставляет его убить всех героев и злодеев в трико... даже очень популярных со свими сольными фильмами! Но жажду крови Дэдпула так просто не удовлетворить. Ведь мир идей полон знаменитых представителей классической литературы... ну, тех, о которых ваши предки узнавали из книжек. И ведь существует несметное множество реальностей, в которых находятся всевозможные версии его самого. Красочный фестиваль Дэдпулов, миллион болтливых наёмников. Но прежде, чем работа Дэдпула будет окончена, каждый из них должен замолчать... навечно! А если и этой убийственной трилогии вам мало, то что насчёт ходячего Дэдпула в роли последнего героя, противостоящего зомби-аппокалипсису? И отгадайте, что такое чёрное, красное, заканчивается смертью? Дэдпул против Карнажа, конечно! За баранкой сам Каллен Банн, так что готовьтесь к поездке, которую вы запомните надолго. \"Дэдпул. Минибус\" - самый дэдпульный комикс из тех, что вы читали! Не верите? Посчитайте, сколько мы за эти пару абзацев упомянули имя Дэдпула! Дэдпул!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3.5,"review":"","added":9999185,"hdCover":""},{"id":"0989350","title":"Дэдпул. Том 5. Что происходит в Вегасе","author":"Дэниел Уэй,Карло Барбери","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002137579/140/4ea6/__Dedpul._Tom_5._Chto_proishodit_v_Vegase.jpg","isbn":"978-5-91339-463-78","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Выходные в Вегасе в стиле Дэдпула — это куча взрывов, третьесортные злодеи и ограбление казино, которым гордился бы сам Джордж Клуни! Взяв за горло болтливого владельца клуба, Дэдпул вызывает гнев боссов самых крупных казино Лас-Вегаса и их нового наёмного защитника, Казино–охранника в разномастном суперкостюме, вооружённого до зубов, у которого с человеком в красном и чёрном есть свои счёты. Дело в том, что человек в костюме — не кто иной, как…  Здесь мы тебе этого не расскажем, лоботряс! Прочитай книгу, чтобы узнать, кто восстал из прошлого Дэдпула, чтобы надрать ему задницу, и как Дэдпул нашёл себе постоянную работу! Без шуток.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3,"review":"","added":9999184,"hdCover":""},{"id":"098934f","title":"Что Если Веном завладел бы Дэдпулом?","author":"Рик Ремендер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002188070/140/08b8/Rik_Remender__Chto_Esli_Venom_zavladel_by_Dedpulom.jpg","isbn":"978-5-9909387-3-1","publisher":"Другое издательство","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Встречайте, легендарные Веном и Дэдпул в одном выпуске! Они были созданы в одну эпоху, но при этом являются полными противоположностями. Изначально единственной целью Венома было съесть мозги Человека-Паука, но теперь ему повстречался Дэдпул, который годами доказывал нам, что мозгов у него нет.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3,"review":"","added":9999183,"hdCover":""},{"id":"098934e","title":"Дэдпул. Том 4. Дэдпул против З.А.Щ.И.Т.Ы","author":"Джерри Дагган, Брайан Посен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002229821/140/c7d4/Dzherri_Daggan_Brajan_Posen__Dedpul._Tom_4._Dedpul_protiv_Z.A.Sch.I.T.Y.jpg","isbn":"978-5-91339-457-1","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Дэдпул единолично объявляет войну международному миротворческому агентству. Но вдобавок к маниакальному наемнику, страждущему расплаты, З.А.Щ.И.Т.А. узнает, что в их ряды затесался предатель – и похоже, что это Агент Престон! Дэдпул прилетает на Авианосец, намереваясь любым способом получить свои деньги… и в итоге сталкивается лицом к лицу с Агентом Филом Колсоном! Какая жалость, что Колсон – фанат Кэпа. А также: очередное путешествие прямиком в тайное прошлое Дэдпула, в котором Болтливый Наемник начнет сеять хаос космических масштабов!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3.5,"review":"","added":9999182,"hdCover":""},{"id":"098934d","title":"Дэдпул. Том 3. Хороший, плохой, злой","author":"Джерри Дагган, Брайан Посен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002076542/140/b959/Dzherri_Daggan_Brajan_Posen__Dedpul._Tom_3._Horoshij_plohoj_zloj.jpg","isbn":"978-5-91339-459-0","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"УМОРИТЕЛЬНОЕ, БЕЗУДЕРЖНОЕ ПЕРЕЛОПАЧИВАНИЕ ИСТОРИИ БОЛТЛИВОГО НАЁМНИКА ОТ ДЖЕРРИ ДАГГАНА И БРАЙАНА ПОСЕНА ПРОДОЛЖАЕТСЯ!  А начинается всё с одного из забытых приключений Дэдпула прямиком из тусовых 70-х, когда он патрулировал улицы с Силачом и Железным Кулаком! Но неожиданно противник Трио по Найму появился в нашем времени, и теперь Дэдпул должен найти своих старых друзей, дабы вновь дать ему бой! Затем возвращается прошлое Дэдпула, а именно программа «Оружие Икс». По этой причине он приходит к товарищам по «Оружию Плюс», не желающим помогать ему, — Росомахе и Капитану Америка!  Находясь прямо в лапах врага, эта троица погружается всё глубже в тайны, окутывающие это место. но когда герои поймут, что нечто, случившееся с Дэдпулом в прошлом,привело к созданию множества других оружий, успеют ли они вовремя устранить грядущую угрозу?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999181,"hdCover":""},{"id":"098934c","title":"Дэдпул. Том 1. Мертвые президенты","author":"Тони Мур,Джерри Дагган, Брайан Посен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001488756/140/a07e/__Dedpul._Tom_1._Mertvye_prezidenty.jpg","isbn":"978-5-91339-354-8","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Команда мёртвых американских президентов — начиная от Вашингтона, и заканчивая Фордом — была поднята из могил и начала терроризировать своих сограждан. Величайшие герои Marvel не могли позволить открыто охотиться на американских патриотов, подставив собственный имидж под удар. Лишь человек, обладающий уже вконец запятнанной репутацией, по сути своей являющийся вооружённым до зубов безумцем, способен справиться со столь отвратительным заданием. Но кто во вселенной Marvel станет пачкать руки, убивая глав государства? Пришло время Дэдпула!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999180,"hdCover":""},{"id":"098934b","title":"Ночь живого Дэдпула","author":"Каллен Банн,Рамон Росаньес","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001550460/140/46e3/__Noch_zhivogo_Dedpula.jpg","isbn":"978-5-91339-384-5","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Дэдпул очнулся от сытой комы и понял, что Нью-Йорк захватили полоумные зомби! И им не особо-то нравится вся эта жажда человеческой плоти. Съедят ли Болтливого Наёмника болтливые зомби? Вас повергнет в ужас один только вид этого отвратительного гниющего монстра, бродящего по округе... а про зомби, с которыми он дерётся, мы вообще молчим! (Дошло? Типа первая часть была про самого Дэдпула. Почему бы не добавить в хоррор-комикс про зомби немного юмора?)  Каллен Банн, автор сценария полюбившихся многим \"Уничтожительных приключений Дэдпула\", расскажет вам самую мрачную историю из когда-либо написанных... и мы так говорим не потому, что она будет чёрно-белой (и красной)! Мы вас предупредили, друзья! Так что звоните в гонг и запирайте дверь на засов - Дэдпул вышел на охоту за нежитью.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999179,"hdCover":""},{"id":"098934a","title":"Отряд Икс. Книга 1","author":"Рик Ремендер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002041984/140/eee0/Rik_Remender__Otryad_Iks._Kniga_1.jpg","isbn":"978-5-9908127-3-4","publisher":"Jellyfish Jam","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Росомаха, Псайлок, Архангел, Дэдпул и Фантомекс. Вместе они - Отряд Икс, мутанты с лицензией на убийство. Их первое задание: расправиться с ужасным Апокалипсисом, переродившимся в теле невинного ребенка. Пока Отряд Икс пытается смириться со своими решениями, из будущего прибывают киборги Дэтлоки с поразительно знакомыми лицами... их цель - казнить Фантомекса! Но и это ещё не все - ведь затем Архангел раскрывает свою сущность и продолжает дело Апокалипсиса, потому ради его спасения Отряд Икс отправляется в другую реальность: Эру Апокалипсиса! Победа Темного Ангела ознаменует конец всей жизни на Земле, но сможет ли даже команда заматерелых убийц покончить со своим товарищем?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4.5,"review":"","added":9999178,"hdCover":""},{"id":"0989349","title":"Скотт Пилигрим против вселенной","author":"Брайан Ли О''Мэлли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003227367/140/6b20/Brajan_Li_O039Melli__Skott_Piligrim_protiv_vselennoj.jpg","isbn":"978-5-91339-674-7","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Скотт Пилигрим","genres":["Комиксы","манга","графические романы"],"annotation":"Скотт готов к лету, но расслабляться ему некогда.  Скотт Пилигрим отметил двадцать четвертый день рождения, но следующего может и не быть. Ему пора сразиться с двумя злыми бывшими Рамоны - да, с двумя сразу - и они натравили на Скотта роботов! Неважно, портят ли они вечеринку Джули или срывают первый концерт Sex Bobomb за несколько месяцев, Скотту надо с ними разобраться. Но получится ли у него победить злых роботов и не испортить отношения с Рамоной? Успеет ли он победить её злых бывших до того, как Рамона - О БОЖЕ - его бросит? Ответы на эти вопросы Скотт найдёт внутри книги... если выживет!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3.5,"review":"","added":9999177,"hdCover":""},{"id":"0989348","title":"Говард Утка. Том 0. Какого гуся","author":"Чип Здарски","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001489464/140/0af3/Chip_Zdarski__Govard_Utka._Tom_0._Kakogo_gusya.jpg","isbn":"978-5-91339-355-5","publisher":"Комильфо, Marvel Worldwide","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Говард Утка вернулся! Станьте свидетелем того, как он берётся за странные дела, которые способен раскрыть лишь частный детектив вселенной Marvel... если, конечно, он говорящая утка! Первое дело Говарда начинается со встречи с Чёрной Кошкой, а заканчивается в космосе, в руках Коллекционера! Но он не один. Его сокамерник - Реактивный Енот! Смогут ли эти двое антропоморфных животных изменить ход игры и вырваться на свободу?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":2,"review":"","added":9999176,"hdCover":""},{"id":"0989347","title":"Человек-Паук 2099. Том 1. Вне времени","author":"Питер Дэвид,Рик Леонарди","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002533811/140/ce75/__ChelovekPauk_2099._Tom_1._Vne_vremeni.jpg","isbn":"978-5-9909387-9-3","publisher":"Другое издательство","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В 2099 году Мигель О’Хара получил паучьи способности в результате сорванного эксперимента в лаборатории “Алкемакс”, злобной корпорации, которая пыталась создать супер-солдат. Мигель боролся с компанией с тех самых пор, как узнал об их истинных мотивах, пока не застрял в настоящем! Но здесь, “Алкемакс”, зловещая корпорация из будущего, только начинает свой путь, и у Мигеля есть шанс остановить ее разложение прежде, чем оно успеет начаться! Однако Человек-Паук 2099 вскоре узнает, что он не единственный, кто надеется на лучшее завтра. Когда из-за непростого соглашения с “Алкемакс” Мигель оказывается на территории военных действий, ему приходится сражаться за жизнь своего деда… Переживая нападение Скорпиона и появление охотящегося на пауков Морлана, Мигель оказывается на грани столкновения с Паучьими Мирами! Присоединяйтесь к создателям Человека-Паука 2099 Питеру Дэвиду и Рику Леонарди, а также художнику Уиллу Слайни (Совершенный Человек-Паук: Работа в команде) в самом захватывающем приключении, которое только можно найти по эту сторону 22-го века!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3,"review":"","added":9999175,"hdCover":""},{"id":"0989346","title":"Что если? Гражданская война","author":"Larry Stroman,Дэвид Хайн,Эд Брубейкер,Марко Джурджевич,Грег Пак,Кристос Гейдж,Пол Тобин,Кевин Гревье,Рафа Сандовал,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002425226/140/cb6a/__Chto_esli_Grazhdanskaya_vojna.jpg","isbn":"978-5-9909387-5-5","publisher":"Другое издательство","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":2,"review":"","added":9999174,"hdCover":""},{"id":"0989345","title":"Львы Багдада","author":"Брайан К. Вон,Нико Анришон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001572232/140/f03d/__Lvy_Bagdada.jpg","isbn":"978-5-389-10060-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"В апреле 2003 года прайд львов выбрался из  Багдадского зоопарка во время бомбардировки города американцами.  Растерянные и голодные, но наконец свободные,  четыре гигантские кошки скитаются по безлюдным улицам Багдада, отчаянно сражаясь за жизнь.  Вдохновленные реальными событиями, писатель Брайан К. Вон и художник Нико Анришон открыли необыкновенное окно в жизнь природы во время войны и показали цену выживания на фоне поразительно правдоподобной истории войны в Ираке. Описывая бедствия, свалившиеся на багдадских львов, эта непростая история затрагивает саму суть понятия «свобода». Можно ли получить ее из чужих рук, или ее можно добыть лишь собственными силами и самопожертвованием?  «Vertigo» и «DC Comics» с гордостью представляют совершенно новое люксовое издание высоко оцененного критиками графического романа, содержащее дополнительные материалы из ранее не издававшихся текста и рисунков от создателей «Львов Багдада».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999173,"hdCover":""},{"id":"0989344","title":"Тёмные мстители. Полное издание","author":"Брайан Майкл Бендис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002904118/140/c0d9/Brajan_Majkl_Bendis__Tjomnye_mstiteli._Polnoe_izdanie.jpg","isbn":"978-5-04-098493-0","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Герои Marvel (обложка)","genres":["Комиксы","манга","графические романы"],"annotation":"Выпускайте плохишей! Вот и они, новая команда Величайших Героев Земли, — лучи солнца освещают их улыбающиеся лица, а восторженная толпа готова скандировать их имена, пока те выходят на сцену! Человек-Паук, Росомаха, Мисс Марвел, Хоукай — вы их знаете, вы их любите! Это ваши Мстители, и они здесь, чтобы защитить вас! Только… всё не то, чем кажется. Если настоящие Мстители в подполье, то кто же эти герои, так похожие на них? Почему их собрали? Тёмное Правление только началось, а Тёмные Мстители уже попали в эпицентр безумных планов Нормана Озборна на вселенную Marvel! В сборнике: \"Тёмные Мстители\" #1–6, #9–16 и Ежегодник #1. Автор сценария Брайан Майкл Бендис, художники Майк Деодато, Грег Хорн и Крис Бачало.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999172,"hdCover":""},{"id":"0989343","title":"Удивительный Человек-Паук. Заговор Клонов","author":"Кристос Гейдж,Дэн Слотт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002879549/140/3ff5/__Udivitelnyj_ChelovekPauk._Zagovor_Klonov.jpg","isbn":"978-5-04-098201-1","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"В названии книги есть эмоции","genres":["Комиксы","манга","графические романы"],"annotation":"СМЕРТИ БОЛЬШЕ НЕТ! БУДУЧИ ЧЕЛОВЕКОМ ПАУКОМ, Питер Паркер потерял многих — любимых, друзей и даже врагов. Но что случится, если те, по кому он скорбил, вдруг восстанут из могил? Вы узнаете это, когда он встретится с близкими, которых уже и не мечтал увидеть вновь — равно как и с опасными врагами, которых он предпочёл бы считать мёртвыми. Потому что на каждую Гвен Стейси найдётся Доктор Осьминог! Гений, стоящий за этими воскрешениями — злодей, что уже однажды клонировал Человека-Паука: безумный Шакал! И пока команда героев в лице Шёлк, Мародёра и Алого Паука пытается что-то предпринять, Паучок сталкивается с самой большой проблемой в своей жизни. Если Шакал победит смерть, будет ли жизнь прежней?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3.5,"review":"","added":9999171,"hdCover":""},{"id":"0989342","title":"Грут","author":"Джефф Лавнесс,Брайан Кесинджер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002607868/140/6d24/__Grut.jpg","isbn":"978-5-9909878-3-8","publisher":"Jellyfish Jam","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Сольные приключения самого удивительного Стража Галактики! Когда загадочные наемники похищают Реактивного Енота, его лучший друг Грут спешит на помощь. И всем, кто встанет на его пути можно не позавидовать. Тем более что пусть Стражи в комиксе не появляютя, других специальных гостей полно - и в том числе сам Серебряный Серфер!  Законченная история, которую можно читать независимо от других комиксов.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999170,"hdCover":""},{"id":"0989341","title":"Супермен. Земля-1. Книга 1","author":"Джей Майкл Стражински,Шэйн Дэвис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000658831/140/e4d2/__Supermen._Zemlya1._Kniga_1.jpg","isbn":"978-5-389-05144-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2013","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Кларк Кент не такой, как все. Он умеет летать. Видит сквозь стены. Испепеляет взглядом. Он — бог среди смертных. Но он одинок и не понимает, в чем его предназначение.  Как и большинство двадцатилетних, он не знает, как распорядиться своей судьбой. Выбрать он может все, что угодно: спорт, науку, финансы или СМИ. Все будет подвластно ему... главное — скрывать от остальных, кто он такой и на что способен.  Но когда небо потемнеет от кораблей, прилетевших с далеких планет и само существование Земли окажется под угрозой, Кларку придется принять самое важное в его жизни решение: раскрыться миру, пожертвовав шансом на нормальную жизнь... или остаться в тени, бросив мир на верную погибель.  Сценарист Дж. Майкл Стражински пересказывает на современный лад историю об уцелевшем одиночке с планеты Криптон и о его битве за спасение человечества с теми, кто был повинен в уничтожении его родного мира. Вместе с художником Шейном Дэвисом («Зеленый фонарь») Стражински покажет вам такого Супермена, какого вы еще не видели!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999169,"hdCover":""},{"id":"0989340","title":"Танос. Начало","author":"Джейсон Аарон,Симоне Бьянки","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002000114/140/1be6/__Tanos._Nachalo.jpg","isbn":"978-5-9908126-2-8","publisher":"Jellyfish Jam","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Лорд Танос, безумный титан, по праву считается одним из величайших злодеев вселенной Marvel. Но откуда он родом? Как прошло его детство? Что сделало его тем, кем он стал - могущественным покровителем смерти и разрушения? И, что самое важное, каковы его мотивы? Все ответы - в этом комиксе! Перед вами - история трагедии, лжи и судьбоносного жребия. история того, как Танос, воплощение космической кары, пришёл к власти в роли несравненного злодея. Реки крови прольются во имя истинной любви на том пути, что изменит не только жизнь одного мальчика, но и судьбу всей галактики - и даже самой вселенной Marvel!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3,"review":"","added":9999168,"hdCover":""},{"id":"098933f","title":"Ходячие мертвецы. Полное собрание. Том 2","author":"Роберт Киркман, Чарли Адлард, Клифф Ратбёрн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002855048/140/68bb/Robert_Kirkman_Charli_Adlard_Kliff_Ratbjorn__Hodyachie_mertvetsy._Polnoe_sobrani.jpg","isbn":"978-5-91339-698-3","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"Сколько часов в день вы не тратите, просиживая перед телевизором? Когда в последний раз кто-нибудь из нас на самом деле старался, чтобы получить желаемое? Давно ли кто-то из нас действительно нуждался в том, что постоянно хочет? Мир, который мы знали, исчез. На смену миру торговли и пустого потребительства пришёл мир выживания и ответственности. Эпидемия апокалиптических масштабов прокатилась по планете, пробудив мёртвых, которые начали пожирать живых. За несколько месяцев человеческое общество было разрушено. Исчезли правительства, магазины, доставка почты, кабельное телевидение. В мире, где правят мёртвые, мы наконец вынуждены начать жить.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-10","rating":5,"review":"","added":9999167,"hdCover":""},{"id":"098933e","title":"Бэтмен. Долгий Хэллоуин","author":"Джеф Лоэб","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001434828/140/8eab/Dzhef_Loeb__Betmen._Dolgij_Hellouin.jpg","isbn":"978-5-389-08859-7","publisher":"Азбука","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Происходящий во времена первых шагов Бэтмена на дороге борьбы с преступностью «Долгий Хэллоуин» повествует о загадочном убийце по прозвищу Праздник, отмечающем красные даты календаря кровью очередной жертвы. Работая бок о бок с комиссаром полиции Джеймсом Гордоном и окружным прокурором Харви Дентом, Бэтмен пытается предотвратить очередное преступление, но это все равно что пытаться обогнать время. Закрученный сюжет заставляет читателя постоянно гадать, кто же этот таинственный злодей, подозрения падают и на врагов, и на друзей Бэтмена. Описав полный круг, история замкнется. Кто-то умрет, а кто-то изменится навсегда...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-10","rating":5,"review":"","added":9999166,"hdCover":""},{"id":"098933d","title":"Лига Справедливости. Война Троицы","author":"Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001912212/140/ffbc/Dzheff_Dzhons__Liga_Spravedlivosti._Vojna_Troitsy.jpg","isbn":"978-5-389-11202-5","publisher":"Азбука","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Много веков назад ничего не подозревающая девушка наткнулась на зловещий артефакт: шкатулку в виде трехглазого черепа. Она открыла ее... и на свет вырвались Семь Смертных Грехов.  Тысячелетия спустя Шкатулка Пандоры вновь становится источником многих бед. Перед ее разрушительной силой не способен устоять даже Супермен. Укротить эту силу способен лишь тот, чья душа совершенно чиста, либо же тот, чья душа полностью погрязла во зле. Три загадочных существа бродят по свету в поисках ответов. Три команды героев сойдутся в схватке, в которой решится судьба мира. А в тени зла таится еще более великое зло...  «Лига Справедливости. Война Троицы» объединяет величайшие таланты индустрии комиксов. В создании принимали участие такие звезды как Джефф Джонс, Джефф Лемир, Рэй Фокс, Иван Рейс, Дуг Манки, Микель Ханин и другие — для того, чтобы поведать нам историю о мифах, магии и противостоянии, которое изменит мир New 52 навсегда!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-08","rating":4,"review":"","added":9999165,"hdCover":""},{"id":"098933c","title":"Лига справедливости. Книга 2. Путь злодея (сборник)","author":"Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001420425/140/93c2/Dzheff_Dzhons__Liga_spravedlivosti._Kniga_2._Put_zlodeya_sbornik.jpg","isbn":"978-5-389-09801-5","publisher":"Азбука","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Лига Справедливости – величайшая сила на стороне добра, какую когда-либо видел мир. Но так считают не все. Их нескончаемая битва со злом приводит к жертвам – жертвам среди мирного населения. Как ни старается Лига уберечь невинные жизни, герои не могут спасти всех. Величайшие победы преданных защитников Земли несут в себе и семена сокрушительных поражений. Ведь горе и испытания рождают не только героев, такой же путь проходят и злодеи.  К самой популярной по версии «Нью-Йорк Таймс» команде в лице Джеффа Джонса и Джима Ли присоединились художники Джин Ха и Карлос д’Анда, и в результате появилась «Лига Справедливости: Путь злодея», куда вошли выпуски серии с седьмого по двенадцатый.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-08","rating":4.5,"review":"","added":9999164,"hdCover":""},{"id":"098933b","title":"Бэтмен. Темная победа","author":"Джефф Лоэб,Тим Сейл","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002036557/140/f955/__Betmen._Temnaya_pobeda.jpg","isbn":"978-5-389-10782-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"На заре своей карьеры Темный Рыцарь пытается выследить неуловимого убийцу копов по кличке Палач, прежде чем тот нанесет очередной удар. Единственный намек на личность преступника — листок с детской игрой, приколотый к телам жертв. В качестве главных подозреваемых выступает целая галерея злодеев: Двуликий, Джокер, Загадочник, Женщина-Кошка. Даже полиции во главе с недавно назначенным комиссаром Гордоном доверять нельзя.  Чтобы разрешить загадку, Бэтмену придется заручиться помощью с самой неожиданной стороны. Он возьмет в напарники осиротевшего мальчика, который навсегда изменит его жизнь. Они станут известны как Бэтмен и Робин. Их история перед вами.  Авторы книги – знаменитый тандем лауреатов премии Айснера Джеф Лоэб и Тим Сэйл («Супермен на все времена», «Бэтмен: Долгий Хэллоуин»). Абсолютное издание включает оригинальную серию из 0–13 выпусков, интервью Джефа Лоэба, вступительные статьи Тима Сэйла и сценариста кинотрилогии о Бэтмене Дэвида С. Гойера, а также множество набросков и эскизов.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-07","rating":5,"review":"","added":9999163,"hdCover":""},{"id":"098933a","title":"Рик и Морти (сборник)","author":"Зак Горман,Том Фаулер,Памела Рибон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002290906/140/ca1c/__Rik_i_Morti_sbornik.jpg","isbn":"978-5-91339-518-4,  978-5-91339-620-4","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Научная фантастика"],"annotation":"Если вы следите за невероятными приключениями бедолаги Морти и его деда-алкоголика, учёного и по совместительству межгалактического преступника Рика Санчеза и устали ждать выхода третьего сезона, то эта книга определенно поможет вам скоротать время в ожидании. Приготовьтесь к новой порции безумия, но теперь уже в комиксах, потому что таких историй вы ещё не слышали и не видели! Сюжет комикса не дублирует мультсериал и не оставит равнодушным ни одного любителя отборного интеллектуально-трешёвого юмора и научной фантастики.  Книга включает в себя выпуски комиксов #1-15, а также дополнительные материалы, а это около 400 страниц!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-06","rating":4,"review":"","added":9999162,"hdCover":""},{"id":"0989339","title":"Ходячие мертвецы. Полное собрание. Том 1 (сборник)","author":"Роберт Киркман,Тони Мур,Клифф Ратбёрн,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002853093/140/7b8d/__Hodyachie_mertvetsy._Polnoe_sobranie._Tom_1_sbornik.jpg","isbn":"978-5-91339-677-8","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"Сколько часов в день вы не тратите, просиживая перед телевизором? Когда в последний раз кто-нибудь из нас на самом деле старался, чтобы получить желаемое? Давно ли кому-то из нас действительно было нужно то, чего мы постоянно хотим? Мир, который мы знали, исчез. На смену миру торговли и пустого потребительства пришел мир выживания и ответственности. Эпидемия апокалиптических масштабов прокатилась по планете, пробудив мёртвых, которые начали пожирать живых. За несколько месяцев человеческое общество было разрушено. Исчезли правительства, магазины, доставка почты, кабельное телевидение. В мире, где правят мёртвые, мы наконец вынуждены начать жить","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-06","rating":5,"review":"","added":9999161,"hdCover":""},{"id":"0989338","title":"Отряд самоубийц. Книга 5. Замурованные","author":"Мэтт Киндт,Патрик Зерчер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002112553/140/43e0/__Otryad_samoubijts._Kniga_5._Zamurovannye.jpg","isbn":"978-5-389-12609-1","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"А ЕСЛИ ОТРЯД САМОУБИЙЦ ОСТАНЕТСЯ ПОСЛЕДНЕЙ КОМАНДОЙ СУПЕРГЕРОЕВ НА ЗЕМЛЕ?  Разумеется, никому и в голову не придет называть Отряд Самоубийц командой супергероев. Эти опасные преступники под руководством Аманды Уоллер по меньшей мере непредсказуемы... А теперь, когда их не сдерживают вживленные бомбы, они и вовсе неуправляемы.  Но нагрянуло ВЕЧНОЕ ЗЛО, все величайшие герои Земли сгинули, и другого выбора не осталось: отныне судьба всего человечества в руках психопатов из Отряда Самоубийц!  Итак, Уоллер отправляет команду, в которую входят Дэдшот, Харли Квинн и Капитан Бумеранг, на новое задание — не дать Мозговику завладеть невообразимым по своей мощи оружием. Но есть проблема: Мозговик собрал собственный Отряд Самоубийц, призвав Пауэр Герл, Сталь и Неизвестного Солдата... и в их сверхспособностях сомневаться не приходится.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-06","rating":2.5,"review":"","added":9999160,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989337","title":"Отряд Самоубийц. Книга 4. Надзирать и наказывать","author":"Мэтт Киндт,Патрик Зерчер,Алеш Кот","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002050533/140/6c7a/__Otryad_Samoubijts._Kniga_4._Nadzirat_i_nakazyvat.jpg","isbn":"978-5-389-12236-9","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Вернувшись на базу в тюрьме «Белль-Рив» с очередного провального задания, Аманда Уоллер приходит к выводу, что ее спецназ из отбросов и врагов общества нуждается в свежей крови. Ведь ее Отряд Самоубийц не случайно оказался на грани самоуничтожения.  Вместе с кардинальными переменами члены Отряда получают цель, в которую они действительно верят, и нового командира — безбашенного серийного убийцу, с разумом столь же гениальным, сколь и патологическим. Ну а кто еще поднимет командный дух, как не съехавший с катушек душегуб с неисповедимой логикой? Именно такой командир поможет Отряду сплотиться в решении общей задачи. Он незаменим в предстоящих операциях против гигантского трупомонстра, зомбированных анархистов и некоего персонажа из прошлого Аманды Уоллер, которого она не чаяла встретить снова...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-06","rating":2.5,"review":"","added":9999159,"hdCover":""},{"id":"0989336","title":"Боун. Том 6. Пещера старика","author":"Джефф Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002371859/140/2fc5/Dzheff_Smit__Boun._Tom_6._Peschera_starika.jpg","isbn":"978-5-99065-299-6,  978-5-9906529-3-4","publisher":"Рамона","pubDate":"2017","language":"Русский","series":"Боун/ Bone","genres":["Комиксы","манга","графические романы"],"annotation":"Крысьи создания вторглись в долину, уничтожая все на своем пути. Местные жители во главе с бабушкой Бен и Луцием объединились с воинами Вени-Ян. Укрепившись в пещере Старика, они готовятся дать врагу решающий бой.  Тем временем человек в капюшоне собирается освободить Повелителя Саранчи при помощи жертвоприношения. Осталось лишь поймать саму жертву в лице Фоуни Боуна... или Торн.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-05","rating":4.5,"review":"","added":9999158,"hdCover":""},{"id":"0989335","title":"Отряд Самоубийц. Книга 3. Смерть - удел слабаков","author":"Адам Гласс,Хенрик Йонссон,Санду Флореа","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001906306/140/d0fb/__Otryad_Samoubijts._Kniga_3._Smert__udel_slabakov.jpg","isbn":"978-5-389-11686-3","publisher":"Азбука","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Смертельная схватка с Регулусом — лидером крупной террористической группировки «Василиск» — изрядно потрепала Отряд Самоубийц. Дэдшот, командир группы, пожертвовал собой ради спасения своей тайной возлюбленной Харли Квинн, в то время как Йо-Йо и Вольтаика уничтожили их же товарищи по команде.  Но некоторые агенты представляют собой слишком ценные кадры, чтобы покоиться с миром. А злодеи вроде Регулуса слишком опасны, чтобы исчезнуть без следа.  Мало того: Харли Квинн предстоит свидание с прежней любовью — дерзким психопатом, известным под именем Джокер. Уже год его считают покойником, однако он возвращается, чтобы вновь бросить вызов Бэтмену... и наказать Харли за неверность. Кто же теперь возглавит Отряд, который в очередной раз собирается из осколков в единое целое?  Автором сборника выступил Адам Гласс (исполнительный продюсер и сценарист телесериала «Сверхъестественное»), художниками — Хенрик Йонссон («Бэтмен: Detective Stories») и Санду Флореа («Лига справедливости»).  В сборник вошли выпуски №№ 14–19, галерея набросков и примечания.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-05","rating":2.5,"review":"","added":9999157,"hdCover":""},{"id":"0989334","title":"Отряд Самоубийц. Книга 2. Восход Василиска","author":"Адам Гласс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001572262/140/f03d/Adam_Glass__Otryad_Samoubijts._Kniga_2._Voshod_Vasiliska.jpg","isbn":"978-5-389-11191-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Пока выжившие члены оперативной группы Икс, также известной под названием «Отряд Самоубийц», зализывают раны после провальной операции в Готэме, становится очевидным то, что до сих пор зрело подобно гнойному нарыву — в их рядах предатель! Взращенный и обученный Регулусом, предводителем тайной организации «Василиск», диверсант получает приказ убить Аманду Уоллер и разоблачить Отряд. Неужели это Харли Квинн, сумасшедшая подружка Джокера, чье раздвоение личности уже само по себе представляет угрозу для команды? Или, быть может, это Дэдшот, чьи суицидальные порывы мог использовать в своих целях Регулус?  С предателем на борту, Отряд отправляется на особое задание — захват Митча Шелли, Воскресшего, что в свою очередь, является частью грандиозного плана Аманды Уоллер по полному искоренению организации «Василиск»!  В издание вошел стартовый выпуск № 0, проливающий свет на таинственную личность Аманды Уоллер и истинные причины ее давней вражды с Регулусом.  ОТРЯД САМОУБИЙЦ: ВОСХОД ВАСИЛИСКА включает выпуски № 0 и № 8 — 13 «Отряда Самоубийц» и выпуск № 9 «Воскресший». Это дерзкая и кипящая энергией история, рассказанная Адамом Глассом (исполнительный продюсер и сценарист телесериала «Сверхъестественное») и запечатленная в иллюстрациях Фернандо Дагнино («Action Comics») и других художников.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-05","rating":2,"review":"","added":9999156,"hdCover":""},{"id":"0989333","title":"Отряд самоубийц. Книга 1. Пинок в зубы","author":"Адам Гласс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001516660/140/8908/Adam_Glass__Otryad_samoubijts._Kniga_1._Pinok_v_zuby.jpg","isbn":"978-5-389-10768-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Что такое Отряд самоубийц? Суперзлодеи, завербованные в тюрьмах и отправленные на секретное, смертельно опасное задание, за которое обещано досрочное освобождение. В шеях у них нанобомбы, удерживающие преступников на коротком поводке. Любым из них пожертвуют, не раздумывая. За это никто не будет призван к ответу. И жестокость и разрушения – всего лишь детали очередного рабочего дня.  Первое задание Отряда сведет вместе шестерых – Дэдшота, Харли Квинн, Эль Дьябло, Вольтаика, Черного Паука и Короля-Акулу, - которым будет противостоять 60 000 крайне опасных врагов. Контролирующая Отряд хладнокровная Аманда Уоллер ведет свою банду убийц от задания к заданию, стремясь предотвратить угрозу мирового масштаба, которую могут остановить только эти негодяи… если, конечно, прежде не перебьют друг друга.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-05","rating":2.5,"review":"","added":9999155,"hdCover":""},{"id":"0989332","title":"Боун. Том 5. Кремень, хозяин восточной границы","author":"Джефф Смит","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002190959/140/7282/Dzheff_Smit__Boun._Tom_5._Kremen_hozyain_vostochnoj_granitsy.jpg","isbn":"978-5-9906529-8-9","publisher":"Рамона","pubDate":"2017","language":"Русский","series":"Боун","genres":[],"annotation":"Провожая детёныша крысьих созданий в горы, Фоун Боун и Смайли Боун встречают хитрого и могучего горного льва по имени Кремень. Кремень называет себя хозяином восточной границы и не очень жалует объявившихся в его владениях незваных гостей. Всё становится ещё сложнее, когда наши герои находят развалины древнего храма.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-04","rating":4.5,"review":"","added":9999154,"hdCover":""},{"id":"0989331","title":"Боун. Том 4. Охотник на Драконов","author":"Джефф Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002020905/140/7fde/Dzheff_Smit__Boun._Tom_4._Ohotnik_na_Drakonov.jpg","isbn":"978-5-9906529-7-2","publisher":"Рамона","pubDate":"2016","language":"Русский","series":"Боун","genres":["Комиксы","манга","графические романы"],"annotation":"Сюжет «Боуна» начинается незамысловато, но по мере развития серии раскручивается до масштабного эпика в духе «Властелина Колец».  Изгнанная из Боунвиля троица двоюродных братьев (Фоун Боун, Фоуни Боун и Смайли Боун) разделилась и заблудилась в бескрайней неизведанной пустыне. Независимо друг от друга, они находят свой путь в таинственную, покрытую лесом долину, заселённую прекрасными и ужасными созданиями.  Что делать, если коварнейшим врагом наших героев является ни кто иной, как сам Фоуни Боун? Этому прохвосту удаётся обмануть всех жителей посёлка и выдать себя за могучего охотника на драконов.  Человек в капюшоне готовит свою огромную армию к полномасштабной войне. Кто-то продолжает преследовать Торн во снах. Мудрая бабушка Бен внезапно исчезает. А Фоуна Боуна и его спутников ждёт страшная встреча с Кингдоком...  На данный момент этот комикс собрал 44 международные награды, не говоря уже о 10 премиях Айснера и 11 премиях Харви, и продолжает попадать в топы рекомендованных комиксов для всех возрастов. «Боун» издаётся в 28 странах, только в США было распродано более 6 миллионов экземпляров.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-04","rating":4.5,"review":"","added":9999153,"hdCover":""},{"id":"0989330","title":"Лига справедливости. Книга 1. Начало","author":"Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001202163/140/adf1/Dzheff_Dzhons__Liga_spravedlivosti._Kniga_1._Nachalo.jpg","isbn":"978-5-389-09719-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Величайшие герои мира… впервые объединяются в команду! Мир стоит на пороге новой эры – эры супергероев. Но человечество пока не привыкло к этой мысли. Далеко не всем это нравится, что среди нас живут люди, обладающие невероятными способностями. Но однажды Земля сталкивается с угрозой слишком серьезной, можно было обойтись без помощи супергероев...  Супермен, Бэтмен, Чудо-женщина, Зеленый Фонарь, Флэш, Аквамен, Киборг... Пусть они еще неопытные, дерзкие и самонадеянные, каждый из них – могучая сила, способная противостоять злу. Но чтобы защитить нашу планету от инопланетного вторжения, им придется объединиться. И тогда они станут… Лигой Справедливости!  В первой книге «Начало» (в нее вошли выпуски 1–6) звездный автор Джефф Джонс и не менее звездный художник Джим Ли (известный нашим читателям по бестселлеру «Бэтмен: Тихо!»), представляют совершенно новый взгляд на вселенную DC и ее супергероев!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-04","rating":4.5,"review":"","added":9999152,"hdCover":""},{"id":"098932f","title":"Бэтмен. Тихо!","author":"Скотт Уильямс,Джеф Лоэб,Джим Ли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002054468/140/56f2/__Betmen._Tiho.jpg","isbn":"978-5-389-04715-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2014","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"«Бэтмен. Тихо!» вдохнул новую жизнь в приключения Темного Рыцаря. Рассказывать о его похождениях взялись два самых ярких таланта индустрии комиксов — Джеф Лоэб («Бэтмен. Темная победа», телесериал «Тайны Смолвиля») и Джим Ли («Дикие К.О.Т.ы», «Супермен», «Люди Икс»). Вместе они поведали читателям захватывающую историю о дружбе, доверии и предательстве длиной в целую жизнь. В это издание вошел не только весь графический роман, но и наброски, обложки выпусков, комментарии.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-04","rating":4.5,"review":"","added":9999151,"hdCover":""},{"id":"098932e","title":"Атака на титанов. Книга 5","author":"Хадзимэ Исаяма","type":"Манга","cover":"https://s1.livelib.ru/boocover/1002115405/140/147d/Hadzime_Isayama__Ataka_na_titanov._Kniga_5.jpg","isbn":"978-5-389-12279-6","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Манга"],"annotation":"Разведкорпус с помощью Эрена смог захватить  загадочную женщину-титана. Наконец бойцы узнают, кто противостоял им в облике смертоносной великанши. Не успев толком справиться с этим потрясением, люди сталкиваются с новой загадкой – тайна великих стен оказывается не менее шокирующей. И в разгар всеобщего смятения приходит известие, которое способно до основания потрясти заключенный внутри стен человеческий мир...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-04","rating":4.5,"review":"","added":9999150,"hdCover":""},{"id":"098932d","title":"Боун. Том 3. Глаза бури","author":"Джефф Смит,Дж. Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001614100/140/44e9/__Boun._Tom_3._Glaza_buri.jpg","isbn":"","publisher":"Рамона","pubDate":"2016","language":"Русский","series":"Боун","genres":["Комиксы","манга","графические романы"],"annotation":"Дела Боунов и их новых друзей становятся хуже день за днём. Луций, Смайли и Фоуни на своём пути в таверну \"Баррелхейвен\" попадают в засаду крысьих созданий.  Между тем на ферме Фоун Боун и Торн видят странные сны. Узнав об этом, бабушка Бен решает раскрыть им древние тайны и предупредить о надвигающейся угрозе. Возможно, нашим героям придётся покинуть ферму навсегда.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-03","rating":4.5,"review":"","added":9999149,"hdCover":""},{"id":"098932c","title":"Боун. Том 2. Великие коровьи бега","author":"Джефф Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001480815/140/2958/Dzheff_Smit__Boun._Tom_2._Velikie_korovi_bega.jpg","isbn":"978-5-9906529-5-8","publisher":"Рамона","pubDate":"2015","language":"Русский","series":"Боун","genres":["Комиксы","манга","графические романы"],"annotation":"Во втором томе своих удивительных приключений Боуны пытаются вернуться в родной Боунвиль. Что же может пойти не так? Практически все! Фоуни Боун рискует всем, решив быстренько навариться на ежегодно проходящих в поселке Коровьих бегах. Тем временем, все очевиднее становятся зловещие признаки назревающей войны.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-03","rating":4.5,"review":"","added":9999148,"hdCover":""},{"id":"098932b","title":"Боун. Том 1. Изгнанники Боунвиля","author":"Джефф Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001390824/140/d457/Dzheff_Smit__Boun._Tom_1._Izgnanniki_Bounvilya.jpg","isbn":"978-5-9906529-4-1","publisher":"Рамона","pubDate":"2015","language":"Русский","series":"Боун","genres":["Комиксы","манга","графические романы"],"annotation":"Откройте для себя невероятную красочную сагу о необычном герое, который должен спасти идиллическую долину от сил зла!  Изгнанная из Боунвиля троица двоюродных братьев: Фоун Боун, Фоуни Боун и Смайли Боун, разделилась и заблудилась в бескрайней неизведанной пустыне. Независимо друг от друга, они находят свой путь в таинственную, покрытую лесом долину, заселённую прекрасными и ужасными созданиями.  В конце концов, наши герои воссоединяются на ферме бабушки Бен и её бойкой внучки Торн. Однако, Боунам пока неизвестно, что против них собираются тёмные силы. Приключения только начинаются!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-03","rating":4.5,"review":"","added":9999147,"hdCover":""},{"id":"098932a","title":"Бэтмен. Книга 6. Эндшпиль","author":"Дэнни Мики,Скотт Снайдер,Грег Капулло,FCO Плаченциа","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002224951/140/8e9a/__Betmen._Kniga_6._Endshpil.jpg","isbn":"978-5-389-12474-5","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"ХА. ХА. ХА.  ОН ВЕРНУЛСЯ. И НА ЭТОТ РАЗ ОН НЕ ШУТИТ!  Бэтмен и Джокер. Темный Рыцарь и Бледный Человек. Долгие годы они противостояли друг другу. Всякий раз, когда злодей погружался во все более глубокие пучины зла, герой рвался к новым вершинам, стремясь остановить его.  Воистину, они были \"лучшими врагами\". До недавних пор.  Больше никаких игр разума. Никаких извращенных шуток. Безумный убийца, который возвел зло в ранг высокого искусства, готовится создать свой шедевр. Полностью уничтожить Бэтмена и все, что ему дорого. Он обратит против Бэтмена Лигу Справедливости. Превратит жителей Готэма в хихикающих психопатов. И это только начало. Кульминация будет ужасающей.  Бэтмен верит, что его роковой противник – всего лишь человек. Безумный, но смертный. Но что, если Джокер – это извечное зло? Сможет ли Темный Рыцарь оборвать шутку, длящуюся уже столько лет?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":3,"review":"","added":9999146,"hdCover":""},{"id":"0989329","title":"Дядюшка Скрудж и Дональд Дак: Сын солнца","author":"Дон Роса","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002089873/140/1c6a/Don_Rosa__Dyadyushka_Skrudzh_i_Donald_Dak_Syn_solntsa.jpg","isbn":"978-5-17-100446-0","publisher":"АСТ, Mainstream","pubDate":"2017","language":"Русский","series":"Disney comics. Утиные истории","genres":["Комиксы","манга","графические романы"],"annotation":"Добро пожаловать в Даксбург! Встречайте Самого Богатого Селезня в мире вместе с его шумным племянником Дональдом, вундеркиндами Билли, Вилли и Дилли и коварным Флинтхартом Гломгольдом! Перед вами первый полный сборник Утиных приключений от любимого автора Дона Росы. Роса продолжает традиции легенды комиксов Disney Карла Баркса, но делает это в своём собственном стиле! Известный своим циклом «Жизнь и Времена Скруджа Макдака», Роса на протяжении двух десятков лет сочинял фантастические истории о Скрудже и Дональде. Помимо «Сына Солнца», эпической битвы за сокровища инков, в сборник также вошли истории «Денежный Поток» (об атаке Братьев Гавс на законы физики) и «Последние Сани до Доусона» с участием старого романтического увлечения Скруджа по имени Золотце Голди! Эти легендарные даксбургские истории впервые собраны в одном издании вместе с коллекцией нарисованных Росой обложек и с интересными фактами о процессе создания комиксов. Все истории расположены в хронологическом порядке. Премия Билла Фингера за выдающееся мастерство в работе над комиксами.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":3.5,"review":"","added":9999145,"hdCover":""},{"id":"0989328","title":"Лига Справедливости. Книга 5. Лига несправедливости (сборник)","author":"Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002511420/140/72fa/Dzheff_Dzhons__Liga_Spravedlivosti._Kniga_5._Liga_nespravedlivosti_sbornik.jpg","isbn":"978-5-389-13084-5","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Преступный Синдикат едва не уничтожил наш мир, но Лекс Лютор возглавил сопротивление против захватчиков, прибывших с Земли-3. И теперь, оказавшись в центре всеобщего внимания, бывший заклятый враг Супермена решил во что бы то ни стало продолжать сражаться на благо человечества, став членом Лиги Справедливости.  Однако все ли намерения Лекса благие? И даже если он перешел на светлую сторону, сможет ли Лютор сработаться с теми, кого преследовал в прошлом?  Сценарист-суперзвезда Джефф Джонс («БЭТМЕН: ЗЕМЛЯ-1», «ЗЕЛЕНЫЙ ФОНАРЬ». «АКВАМЕН»), а также команда величайших художников в индустрии комиксов, включая Дуга Манки, Джейсона Фейбока, Ивана Рейса и Скотта Колинса, представляют: «ЛИГА СПРАВЕДЛИВОСТИ: ЛИГА НЕСПРАВЕДЛИВОСТИ». Это незабываемая история о врагах, союзниках и о тонкой грани между ними. В издание вошли выпуски 30–39.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":4.5,"review":"","added":9999144,"hdCover":""},{"id":"0989327","title":"Лига Справедливости. Вечное зло","author":"Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002167927/140/ad2a/Dzheff_Dzhons__Liga_Spravedlivosti._Vechnoe_zlo.jpg","isbn":"978-5-389-12642-8","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Лига Справедливости пала. Преступный Синдикат, ее темное отражение, выследил и нейтрализовал почти всех борцов с преступностью на нашей планете. И в обстоятельствах, когда не осталось ни одного героя, спасать мир придется злодеям! Лекс Лютор ведет Капитана Холода, Черную Манту, Бизарро, Черного Адама и Синестро на битву против Синдиката. Но сумеет ли злейший враг Супермена со своими соратниками победить банду могущественных тиранов, одолевших даже Лигу Справедливости?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":5,"review":"","added":9999143,"hdCover":""},{"id":"0989326","title":"Лига Справедливости. Книга 4. Вечные герои","author":"Джефф Джонс,Иван Рейс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002168053/140/8a16/__Liga_Spravedlivosti._Kniga_4._Vechnye_geroi.jpg","isbn":"978-5-389-11194-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Ультрамен. Оулмен. Супервумен. Вторгшиеся на нашу Землю из разоренной параллельной вселенной, эти беспощадные создания с помощью Тайного Общества суперзлодеев рвутся к мировому господству. Каждый из них — искаженная версия одного из героев Лиги Справедливости, заточенных ныне в огненной тюрьме, и каждый член Преступного Синдиката втайне лелеет собственный план. В этом единственная надежда Лиги и всего человечества.  Пока жестокие завоеватели сражаются с демонами своего прошлого, Вик Стоун — в прошлом обычный человек, который благодаря невероятным технологиям стал Киборгом, — должен действовать. Только Киборг может противостоять Сети — разумному компьютерному вирусу, укравшему кибертело Вика и захватившему власть над коммуникациями во всем мире.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":4.5,"review":"","added":9999142,"hdCover":""},{"id":"0989325","title":"Лига справедливости. Книга 3. Трон Атлантиды (сборник)","author":"Пол Пеллетьер,Тони С. Дэниел,Джефф Джонс,Иван Рейс,Джо Прадо,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001547199/140/3ffe/__Liga_spravedlivosti._Kniga_3._Tron_Atlantidy_sbornik.jpg","isbn":"978-5-389-10767-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Прежде чем стать Акваменом, Артур Карри был правителем Атлантиды. Но суеверные атланты, с их ненавистью к обитателям суши, не смогли принять царя-получеловека.  Вступив в Лигу Справедливости, Артур покинул морское царство и передал власть над Атлантидой своему единоутробному брату Орму, Повелителю Океана. Некоторое время подводное царство поддерживало неустойчивый мир с поверхностью.  До сих пор.  Пока супергерои Земли заняты другими заботами, загадочная сила подталкивает Атлантиду и мир на поверхности к войне друг с другом. Жертв становится все больше, полномасштабное вторжение выглядит все более вероятным, и теперь только Лига Справедливости способна предотвратить кровавое столкновение, сулящее похоронить под водой добрую половину цивилизации.  Берегитесь: тот, кто владеет троном Атлантиды, решает судьбу мира…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":4.5,"review":"","added":9999141,"hdCover":""},{"id":"0989324","title":"Харли Квинн. Книга 2. Полная отключка","author":"Аманда Коннер,Пальмиотти Джимми","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002006706/140/937d/__Harli_Kvinn._Kniga_2._Polnaya_otklyuchka.jpg","isbn":"978-5-389-11295-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"После того, как Джокер кинул Харли Квинн — кинул буквально, в чан с хлоркой, — она решила, что тут-то ей и конец. О, как же она ошибалась!  Когда Джокер бросил ее — в смысле сбежал — безутешная Харли переехала на Кони-Айленд, чтобы вкусить от Большого Яблока и утешиться уже, в конце концов. И жизнь ее превратилась в сплошной аттракцион. Стриптиз-шоу, подпольные бойцовские клубы, ночные купания нагишом с лучшими подружками — то ли еще будет, Харли!  И правда, судьба готовит ей очередной сюрприз — да еще какой! Однажды поздней ночью возле дома Харли падает настоящая звезда — доблестная Пауэргерл, девушка с благородным сердцем и напрочь отшибленной памятью. И у нашей лиходейки тут же рождается дерзкий план: убедить могучую Пэ Гэ, что она и Харли представляют собой сногсшибательный дуэт борцов с преступностью!  Отличный план. И что могло пойти не так? Очень скоро Харли предстоит это выяснить…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":2.5,"review":"","added":9999140,"hdCover":""},{"id":"0989323","title":"Харли Квинн. Книга 1. Красотка в городе","author":"Джимми Палмиотти,Аманда Коннер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001610341/140/8a54/__Harli_Kvinn._Kniga_1._Krasotka_v_gorode.jpg","isbn":"978-5-389-10980-3","publisher":"Азбука","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В Нью-Йорке дух захватывает не только от небоскребов... По крайней мере, с тех пор, как в городе появляется Харли Квинн. Унаследовав целое здание неподалеку от знаменитого Променада, всеми любимая готэмская социопатка чувствует себя как дома в окружении фриков. Но к несчастью, о новом месте жительства Харли становится известно целой армии наемных убийц, жаждущих получить вознаграждение за ее голову. Кому же, как не Харли Квинн, принимать вызовы, брошенные бруклинским преступным миром, русскими шпионами, престарелыми гражданами и соперничающей командой роллеров? Хлопот столько, что наша героиня едва успевает перекусить парой дюжин хотдогов, что тоже своего рода вызов!  Сенсационная серия создана авторами Джимми Пальмиотти и Амандой Коннер, художником Чедом Хардином и звездной командой комикс-индустрии — Брюсом Тиммом, Джимом Ли, Адамом Хьюзом и другими. В сборник вошли выпуски с нулевого по восьмой.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":3,"review":"","added":9999139,"hdCover":""},{"id":"0989322","title":"Дэдпул уничтожает Дэдпула","author":"Банн Каллен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001515929/140/fb78/Bann_Kallen__Dedpul_unichtozhaet_Dedpula.jpg","isbn":"978-5-91339-368-5","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Дэдпул открыл охоту на главную дичь: самого себя! Бесконечное числа реальностей оказывается в опасности, когда постигшая высшее самосознание версия Дэдпула решает уничтожить весь выдуманный мир, убив его прародителей - всех остальных Дэдпулов! Началась Мировая Война Уэйдов Уилсонов, и каждая версия Красного Комедианта должна выбрать сторону в кровавой бойне самой реальностью.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":3,"review":"","added":9999138,"hdCover":""},{"id":"0989321","title":"Дэдпул уничтожает литературу","author":"Каллен Банн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001442905/140/ae7a/Kallen_Bann__Dedpul_unichtozhaet_literaturu.jpg","isbn":"978-5-91339-337-1","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Болтливый наёмник истребил всю вселенную Marvel, и теперь его цель - герои литературной классики! Капитан Ахав и Измаил огребли! Дон Кихот - Дон Капут! Томом Сойером покрасили забор! Скрудж испустил дух! Гулливеру мало не показалось! Мушкетеров уже не три! Шерлок Холмс дал свой последний обет! Рукописи не горят, а вот персонажи - очень даже! В книге собрана мини-серия Deadpool Killustrated (№1-4) сценариста Каллена Банна и художника Маттео Лолли.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":3.5,"review":"","added":9999137,"hdCover":""},{"id":"0989320","title":"Испытание огнем","author":"Джеймс Дэшнер","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001391688/140/d3f3/Dzhejms_Deshner__Ispytanie_ognem.jpg","isbn":"978-5-17-092413-4","publisher":"АСТ","pubDate":"2015","language":"Русский","series":"Бегущий в лабиринте","genres":["Зарубежная фантастика","Книги для подростков"],"annotation":"Лабиринт пройден, но Томасу, Терезе, Минхо и прочим глэйдерам не приходится расслабляться. Таинственное руководство ПОРОКА – секретной организации, устроившей гонки на выживание – назначает ребятам новые, смертельно опасные испытания. На сей раз их ждет переход по раскаленной пустыне и встреча с жертвами неизлечимой болезни, которые отличаются буйным нравом и непредсказуемым поведением. И словно этого недостаточно, глэйдеры оказываются в сетях предательства. Кому верить, если лучший друг ни с того ни с сего начинает тебя ненавидеть?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":4,"review":"","added":9999136,"hdCover":""},{"id":"098931f","title":"Фантастическая Четверка. Том 1. Плоть и камень","author":"Рафаэль Марин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000478854/140/70c8/Rafael_Marin__Fantasticheskaya_Chetverka._Tom_1._Plot_i_kamen.jpg","isbn":"978-5-9038-9625-7","publisher":"Комикс ЛТД","pubDate":"2009","language":"Русский","series":"Лучшие сюжеты","genres":["Детские книги","Комиксы","манга","графические романы"],"annotation":"Вы, конечно, знаете Фантастическую Четверку, отважных супергероев с удивительными способностями. Они - не просто команда, но еще и крепкая, дружная семья! Мистер Фантастик - гениальный ученый. Умеет растягивать свое тело, принимая любую форму по желанию! Невидимая Леди - его любящая жена, может становиться невидимкой и создавать мощные силовые поля! Человек-Факел - ее брат и штатная горячая голова команды. Может воспламеняться, метать огненные шары и раскаляться до температуры сверхновой звезды! И Существо - друг детства Мистера Фантастика, душа и совесть команды. Его тело состоит из прочного камня, под которым бьется чуткое и ранимое сердце.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":3.5,"review":"","added":9999135,"hdCover":""},{"id":"098931e","title":"Человек-Паук. Том 3. Доктор Октопус","author":"Брайан Майкл Бендис, Марк Багли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000479895/140/6c8c/Brajan_Majkl_Bendis_Mark_Bagli__ChelovekPauk._Tom_3._Doktor_Oktopus.jpg","isbn":"978-5-9038-9659-2","publisher":"Комикс ЛТД","pubDate":"2010","language":"Русский","series":"Человек-Паук. Лучшие сюжеты","genres":["Детские книги","Комиксы","манга","графические романы"],"annotation":"«С великой силой приходит великая ответственность». Эту непростую истину довелось постичь 15-летнему Питеру Паркеру. Ради безопасности семьи и друзей он вынужден скрывать, что его второе «я» - супергерой Человек-паук. Защитив школу от злобного зеленого гоблина, он бросил вызов главарю Нью-Йоркской мафии безжалостному Кингпину и смог отправить его за решетку! Но теперь ему предстоит встретиться с врагом не только сильным, но и умным - Доктором Октопусом.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":4,"review":"","added":9999134,"hdCover":""},{"id":"098931d","title":"Гражданская война","author":"Марк Миллар,Стив МакНивен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001572180/140/1636/__Grazhdanskaya_vojna.jpg","isbn":"978-5-9908127-0-3","publisher":"Jellyfish Jam","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"После несчастного случая с участием новичков супергероев введен закон о регистрации людей со сверхспособностями. Этот закон предполагает чтобы супергерои служили государству и были квалифицированно подготовлены. Но закон о регистрации сверхлюдей разбил супергероев на два лагеря: те кто за него, во главе с Железным Человеком, и кто против - во главе с Капитаном Америка.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":3.5,"review":"","added":9999133,"hdCover":""},{"id":"098931c","title":"Доктор Стрэндж. Начало","author":"Грег Пак,Эмма Риос","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002031915/140/5daa/__Doktor_Strendzh._Nachalo.jpg","isbn":"978-5-91339-462-0","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Эта история о том, как Доктор Стрэндж и Вонг только познакомились, и, противостоя силам зла, объездили весь мир с их новой спутницей. Их ждут удивительные приключения, а также множество магии, и, конечно же, раньше Стефан был талантливым хирургом. Врагом доктора в этом комиксе может стать кто угодно. Например, Дормамму. А может, и не только он.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":2.5,"review":"","added":9999132,"hdCover":""},{"id":"098931b","title":"Люди Икс. Том 4. Геенна огненная","author":"Марк Миллар,Адам Куберт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000466513/140/d663/__Lyudi_Iks._Tom_4._Geenna_ognennaya.jpg","isbn":"978-5-903896-68-4,  978-5-903896-77-6","publisher":"Комикс ЛТД","pubDate":"2010","language":"Русский","series":"Лучшие сюжеты","genres":["Детские книги","Комиксы","манга","графические романы"],"annotation":"У них необычная внешность и странные способности... Но в груди каждого из Людей Икс бьется сердце настоящего героя - доброго, отважного и преданного! Персонажи комиксов \"Люди Икс\" завоевали любовь миллионов поклонников по всему миру, они - звезды трех популярных кинофильмов и множества мультсериалов. Вы держите в руках книгу с абсолютно новым сюжетом, созданным уже в XXI веке лучшими мастерами Marvel! Джину Грей мучают видения: огромная огненная птица Феникс уничтожает Землю... Пока девушка пытается понять, что это значит, в Институт Хавьера прибывает новая студентка - Китти Прайд. И буквально тут же оказывается в центре опаснейшего приключения!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2016","rating":3.5,"review":"","added":9999131,"hdCover":""},{"id":"098931a","title":"Мировая война: Халк","author":"Грег Пак,Джон Ромита-мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000495533/140/a9a1/__Mirovaya_vojna_Halk.jpg","isbn":"978-5-903896-62-2","publisher":"Комикс ЛТД","pubDate":"2010","language":"Русский","series":"Великие супергерои","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Самый могучий супергерой в мире комиксов Marvel, герой двух фильмов и множества компьютерных игр, наконец, предстает перед нашими читателями во всей красе! Недавно команда влиятельных супергероев \"Иллюминаты\" (Железный Человек, Мистер Фантастик, Профессор Хавьер, Черный Гром и Доктор Стрэндж) выслала Халка с Земли. На далекой планете Сакаар он нашел новых друзей и встретил свою любовь, но произошла ужасная трагедия - планета была взорвана, и Халк винит в этом \"Иллюминатов\", теперь он возвращается вместе со своими друзьями, чтобы отомстить! Такого Халка Земля еще не видела!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2015","rating":3.5,"review":"","added":9999130,"hdCover":""},{"id":"0989319","title":"Палестина","author":"Джо Сакко","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001514596/140/e926/Dzho_Sakko__Palestina.jpg","isbn":"978-5-906331-27-4","publisher":"Бумкнига","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Джо Сакко- художник и журналист, обладатель многих премий в области комиксов и литературы. Его графический роман \"Палестина\" положил начало новому жанру- графическая журналистика, а имя автора стало синонимом этого направления.  В начале 90-х годов Джо Сакко провёл два месяца на Западном берегу реки Иордан и в секторе Газа, путешествовал и делал заметки. Он взял более ста интервью у палестинцев и израильтян. Результатом этой поездки и стал комикс \"Палестина\". Сакко исследует в нем политически сложную и эмоционально тяжёлую ситуацию в регионе, которая длится уже больше века.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999129,"hdCover":""},{"id":"0989318","title":"Кричащая планета. Сага Аландора","author":"Алехандро Ходоровский","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1012084112/140/2d9f/Alehandro_Hodorovskij__Krichaschaya_planeta._Saga_Alandora.jpg","isbn":"978-5-04-192855-1","publisher":"Fanzon","pubDate":"2024","language":"Русский","series":"Fanzon. Графический роман. От создателей Метабаронов","genres":["Комиксы","манга","графические романы"],"annotation":"«Кричащая планета» — сборник фантастических историй, которые публиковались в легендарном журнале Métal hurlant. Над антологией работали самые разные художники комикс-индустрии, каждый в своем собственном стиле.  «Сага Аландора» — фантастический мир бесконечной сложности и богатства, рожденный «взрывным» воображением Ходоровски и обрамленный причудливой графикой Кадело.  Астероид, обломок древней планеты, дитя ее разрушения, мчится сквозь пустоту космоса. В своем стремлении к вечности он сталкивается с обитаемыми мирами и испускает волны, которые приводят к преображениям или катастрофам. Из этих ужасающих встреч, подобно бабочкам, выпорхнувшим из своих куколок, рождаются истории… твердые и острые, как минералы, и сияющие, как кометы.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999128,"hdCover":""},{"id":"0989317","title":"Метабарон. Том 2","author":"Алехандро Ходоровский,Джерри Фриссен,Валентен Сеше,Пит Вудс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1008913129/140/1f93/__Metabaron._Tom_2.jpg","isbn":"978-5-04-187063-8","publisher":"Fanzon","pubDate":"2023","language":"Русский","series":"Комиксы. Современная классика. Метабароны и Техносвященники","genres":["Комиксы","манга","графические романы"],"annotation":"Возвращение в грандиозную вселенную, созданную признанным гением Алехандро Ходоровски.  Получив контроль над эпифитом, Империя становится еще более жестокой и могущественной. Для спасения собственной планеты Метабарон отправляется за запасами эпифита в параллельную вселенную, где кроме топлива встречает Метахранительницу Рину. Между ними вспыхивает страсть.  Спустя годы, Адаль и Даргона, не знающие друг о друге дети Метабарона, начинают собственную одиссею, и их пути в конце концов пересекутся…  Продолжение величественной саги о династии совершенных воинов, признанной классикой жанра и завоевавшей премию Eagle Award как лучший европейский графический роман.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999127,"hdCover":""},{"id":"0989316","title":"Глаза кошки","author":"Алехандро Ходоровский,Мёбиус","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1012669342/140/261f/__Glaza_koshki.jpg","isbn":"978-5-389-27142-5","publisher":"Азбука","pubDate":"2025","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Приключения"],"annotation":"В 1974 году Жан Жиро – настоящее имя Мёбиуса – вместе с режиссером Алехандро Ходоровски приступил к созданию фильма «Дюна». Однако проекту не суждено было выйти на экраны. Алехандро впал в глубокую депрессию и на этом фоне начал писать сюжет графического романа, к которому Жан Жиро создал потрясающие иллюстрации. Так на свет появились «Глаза кошки».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999126,"hdCover":""},{"id":"0989315","title":"Королевская кровь","author":"Алехандро Ходоровский","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1012621396/140/aef4/Alehandro_Hodorovskij__Korolevskaya_krov.jpg","isbn":"978-5-04-213304-6","publisher":"Fanzon","pubDate":"2025","language":"Русский","series":"Fanzon. Знаменитые графические романы. Подарочное издание","genres":["Графические романы"],"annotation":"Король, преданный во время войны. Трон, потерянный и захваченный. Коварная королева и безумный принц-бастард. Ужасная любовь, которой не должно быть!  Алехандро Ходоровски рассказывает мрачную историю о короле, что был предан и брошен на погибель. Его ждут годы без памяти, презрение и ненависть. Его ждет месть и возвращение трона. А также любовь, которая обернется настоящим проклятьем.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999125,"hdCover":""},{"id":"0989314","title":"Prodigy Volume 1: The Evil Earth","author":"Марк Миллар","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007042407/140/9d1e/Mark_Millar__Prodigy_Volume_1_The_Evil_Earth.jpg","isbn":"978-1534312364","publisher":"Image Comics","pubDate":"2019","language":"","series":"","genres":[],"annotation":"Edison Crane''s not content being the world''s smartest man and most successful businessman -- his brilliant mind needs constantly challenged. He''s a Nobel Prize-winning scientist, genius composer, Olympic athlete and an expert in the occult, and now international governments are calling on him to fix problems they just can''t handle.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999124,"hdCover":""},{"id":"0989313","title":"American Jesus Volume 2: The New Messiah","author":"Марк Миллар,Peter Gross","type":"Книга","cover":"https://s1.livelib.ru/boocover/1012776196/140/b5fb/__American_Jesus_Volume_2_The_New_Messiah.jpg","isbn":"1534315128","publisher":"Image Comics","pubDate":"2020","language":"","series":"","genres":[],"annotation":"AMERICAN JESUS returns with THE NEW MESSIAH. A virgin pregnancy in ''70s New York leads a young couple to flee for their lives, as evil forces close in to destroy them. Yet more bloodshed lies ahead for their daughter, Catalina, who refuses to accept her destiny as the savior of mankind.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999123,"hdCover":""},{"id":"0989312","title":"Trouble","author":"Mark Millar","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001528735/140/4456/Mark_Millar__Trouble.jpg","isbn":"978-0785150862","publisher":"MARVEL - US","pubDate":"2011","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"It''s one of the most controversial stories Marvel has ever produced! When friends May and Mary take on a summer job after high school, they meet brothers Ben and Richard--and summer lovin'' ensues! Prepare for sand, sun...and lots of sex! High drama, infidelity and a pregancy! Innovative work by Mark Millar and Terry Dodson!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999122,"hdCover":""},{"id":"0989311","title":"American Jesus Volume 3: Revelation","author":"Марк Миллар,Peter Gross","type":"Книга","cover":"https://s1.livelib.ru/boocover/1012776199/140/332b/__American_Jesus_Volume_3_Revelation.jpg","isbn":"1534324992","publisher":"Image Comics","pubDate":"2023","language":"","series":"","genres":[],"annotation":"In American Jesus Volume 3, antichrist Jodie Christianson is now the President of the United States and organizing the collapse of the global economy via wars and pandemics as he ushers in the microchipping of the human population and his father''s infernal New World Order.  Christ has returned in the form of Catalina, but what chance does she have with the whole world against her?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999121,"hdCover":""},{"id":"0989310","title":"American Jesus Volume 1: Chosen","author":"Марк Миллар,Peter Gross","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007432563/140/d409/__American_Jesus_Volume_1_Chosen.jpg","isbn":"978-1607060062","publisher":"Image Comics","pubDate":"2009","language":"","series":"","genres":[],"annotation":"From the writer of the Universal hit, \"Wanted\", comes his next graphic novel on the way to becoming a feature film! \"American Jesus Volume 1: Chosen\" follows a twelve-year-old boy who suddenly discovers he''s returned as Jesus Christ. He can turn water into wine, make the crippled walk, and, perhaps, even raise the dead! How will he deal with the destiny to lead the world in a conflict thousands of years in the making?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999120,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098930f","title":"Huck","author":"Mark Millar","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001709175/140/904f/Mark_Millar__Huck.jpg","isbn":"1632157292","publisher":"Image Comics","pubDate":"2016","language":"Английский","series":"","genres":[],"annotation":"In a quiet seaside town, a gas station clerk named Huck secretly uses his special gifts to do a good deed each day. When his story leaks, a media firestorm erupts, bringing him uninvited fame. As pieces of Huck''s past begin to resurface, it''s no longer clear who his friends are – or whose lives may be in danger.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999119,"hdCover":""},{"id":"098930e","title":"Nemesis: Reloaded","author":"Марк Миллар","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1008773344/140/8e47/Mark_Millar__Nemesis_Reloaded.jpg","isbn":"978-1534399907","publisher":"Image Comics","pubDate":"2023","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"The world''s most evil comic book character is back! Who is Nemesis and why does this eccentric billionaire who dresses up in a mask and cape want to terrorise people instead of helping them? Isn''t that how this is supposed to go? Trigger warning: Too violent and just too cool for some! Don''t say we didn''t warn you. Collecting the entire arc by superstar creative team Mark Millar and Jorge Jiménez.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999118,"hdCover":""},{"id":"098930d","title":"Superior","author":"Марк Миллар,Лейнил Фрэнсис Ю","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000762374/140/fbe2/__Superior.jpg","isbn":"978-0-7851-5317-7","publisher":"Marvel","pubDate":"2013","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Simon Pooni was a normal kid with a great life, until multiple sclerosis hit. He lost the ability to walk, went blind in one eye and sometimes could barely speak. Every night, Simon would pray that his disease would somehow go away. \"Somehow\" turned out to be a magic monkey named Orman, who granted Simon one wish. And the 12-year-old boy stood transformed into a real-life version of legendary comic-book hero Superior. Simon spent one glorious week saving those in need, averting natural disasters - becoming the mostbeloved man on the planet. But Orman ominously cautioned Simon all would be explained in one week. Will Simon be forced to go back to life in a wheelchair after being the world''s greatest hero? Faced with adversity, will he prove himself to truly be...Superior?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999117,"hdCover":""},{"id":"098930c","title":"The Magic Order. Volume 1","author":"Марк Миллар,Оливье Койпель","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003018920/140/4180/__The_Magic_Order._Volume_1.jpg","isbn":"978-1534308718","publisher":"Image Comics","pubDate":"2019","language":"","series":"The Magic Order","genres":[],"annotation":"We live in a world where we’ve never seen a monster, and The Magic Order is the reason we sleep safely in our beds. Magic meets the Mob in The Magic Order, as five families of magicians -- sworn to protect our world for generations -- must battle an enemy who’s picking them off one by one. By day, they live among us as our neighbors, friends and co-workers, but by night they are the sorcerers, magicians and wizards that protect us from the forces of darkness...unless the darkness gets them first.  Collects THE MAGIC ORDER #1-6.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999116,"hdCover":""},{"id":"098930b","title":"Reborn","author":"Марк Миллар,Грег Капулло,Джонатан Глейпион","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002434236/140/a650/__Reborn.jpg","isbn":"978-1534301580","publisher":"Image Comics","pubDate":"2017","language":"","series":"","genres":["Исторические приключения"],"annotation":"The Millar-Capullo smash-hit sell out REBORN is here. Where do you go when you die? Not heaven or hell. somewhere else. Somewhere you have to fight to survive. Somewhere the people from the past are waiting for you—the good and the bad.  Superstar creators MARK MILLAR and GREG CAPULLO join forces to create the sci-fi story of the year, collecting issues 1-6.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999115,"hdCover":""},{"id":"098930a","title":"Supercrooks 1: The Heist","author":"Mark Millar","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001506807/140/2d2c/Mark_Millar__Supercrooks_1_The_Heist.jpg","isbn":"0785165444,  978-0785165446","publisher":"Marvel Comics","pubDate":"2013","language":"Английский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"One last heist. That''s what they all say, right? Just one final score, and everyone can retire and take up fishing. Thing is, the jails are filled with super villains who thought the same thing, and got busted. But the Heat''s in a jam. He''s run up the kind of gambling debt that - if he can''t pay it back in cash - will be paid in blood. Nobody wants to see the most beloved supercrook of all time rubbed out by the mob - especially his biggest fan, Johnny Bolt. And Johnny''s got a plan to help the Heat and make all his buddies disgustingly rich at the same time. Unfortunately for Johnny''s recruits, they have to head to Spain and rob the world''s most notorious super villain blind. And that''s where things get tricky.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999114,"hdCover":""},{"id":"0989309","title":"Наследие Юпитера. Том 1","author":"Марк Миллар","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006271440/140/82b5/Mark_Millar__Nasledie_Yupitera._Tom_1.jpg","isbn":"978-5-04-123222-1","publisher":"Комильфо","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Тайны. Одиночество. Алкоголь. Супружеская измена. Зависть. Безупречность. Даже ваши герои — всего лишь люди. Легендарный писатель Марк Миллар (\"Гражданская война\", \"Росомаха. Старик Логан\", \"Росомаха. Враг государства\", \"Супермен. Красный сын\") наглядно показывает, что наличие сверхспособностей никого не делает святым. Те, кто спасает мир от вторжения инопланетных захватчиков или козней очередного сумасшедшего учёного, легко могут проиграть схватку своим собственным демонам. И вот герои уже врут, предают, разбивают сердца своим близким и идут на сделки с совестью.  Но сколь многое человечество готово простить своим защитникам? И как далеко зайдут сами герои?  Включает выпуски \"Круга Юпитера\" № 1–6.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999113,"hdCover":""},{"id":"0989308","title":"Убивашка в Колумбии","author":"Марк Миллар","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004136511/140/c3f2/Mark_Millar__Ubivashka_v_Kolumbii.jpg","isbn":"978-5-04-111610-1","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"Комильфо. Альтернативные комиксы","genres":["Комиксы","манга","графические романы"],"annotation":"Первая остановка: Колумбия. Мать, которая хочет отомстить за смерть сына, уговаривает Убивашку разобраться с его убийцей, но у Минди другие планы на самого опасного киллера Пальмиры. Вооружившись до зубов, Убивашка освобождает Фабио \"Мано\" Мендозу, чтобы с его помощью истребить всех местных гангстеров, а потом заставить его выступить проотив бывших подельников. Это термоядерное и полное ультранасилия возвращение самой смертоносной двенадцатилетки – дело рук легендарного сценариста Марка Миллара (\"Мордобой\", \"Kingsman: секретная служба\") и художника Рикардо Лопеса Ортиса (Wolf, \"Гражданская война II: Кингпин\").","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999112,"hdCover":""},{"id":"0989307","title":"Императрица. Книга 1","author":"Марк Миллар","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002698845/140/0804/Mark_Millar__Imperatritsa._Kniga_1.jpg","isbn":"978-5-04-089537-3","publisher":"Fanzon","pubDate":"2017","language":"Русский","series":"Комиксы. Современная классика","genres":["Комиксы","манга","графические романы"],"annotation":"Вместе с неунывающей Эмпорией вам предстоит окунуться в пучины межпланетных войн, посетить погибшие миры, ускользнуть от пасти огромного чудовища, едва спастись от плена подлых работорговцев и безумного жреца, мечтающего принести императрицу в жертву!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999111,"hdCover":""},{"id":"0989306","title":"Мордобой 2. Пролог: Убивашка","author":"Марк Миллар, Джон Ромита мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001443498/140/abe9/Mark_Millar_Dzhon_Romita_ml.__Mordoboj_2._Prolog_Ubivashka.jpg","isbn":"978-5-91339-339-5","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Минди Маккриди освоила сотню способов убить человека. Её отец, супергерой по имени Большой Папочка, сделал всё для этого. Она использовала свои навыки, чтобы очистить город от бандитов, суперзлодеев и прочих сомнительных личностей. Так почему же общение в школе с популярными девчонками для нее стало самым тяжким испытанием? Теперь, когда Большого Папочки уже нет, Убивашка изо всех сил пытается жить \"нормальной жизнью\" с мамой и отчимом. Поэтому она заключает сделку с начинающим супергероем по имени Мордобой: она поможет ему выжить, если тот поможет ей подружиться с одноклассницами. Но в городе новый крёстный отец, так что \"нормальная\" жизнь снова откладывается.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999110,"hdCover":""},{"id":"0989305","title":"Мордобой 3","author":"Марк Миллар, Джон Ромита мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001489973/140/d5e4/Mark_Millar_Dzhon_Romita_ml.__Mordoboj_3.jpg","isbn":"978-5-91339-353-1","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Кто бы мог подумать, что восемнадцатилетний подросток может стать СУПЕРГЕРОЕМ?  Дэйву Лизевски это удалось - после долгих и напряженных тренировок девчонкой, известной как Убивашка, он начал свою супергеройскую карьеру в роли Мордобоя. Они с Убивашкой выпустили против мафии... и победили. Но и у победы есть своя цена.  Теперь, когда Убивашка оказалась в тюрьме, Мордобой должен встать на её место и повести за собой деморализованную команду борцов с преступностью \"Справедливость Навсегда\", несмотря на то, что полиция объявила героев в масках вне закона.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999109,"hdCover":""},{"id":"0989304","title":"Особо опасен","author":"Марк Миллар,Дж. Дж. Джонс,Пол Маунтс","type":"Книга","cover":"https://s1.livelib.ru/boocover/1000311470/140/5859/__Osobo_opasen.jpg","isbn":"978-5-17-054673-2","publisher":"АСТ, Астрель","pubDate":"2008","language":"Русский","series":"Кинороман","genres":["Современная зарубежная литература","Зарубежная фантастика"],"annotation":"Фильм \"Особо опасен\" - сенсационная премьера этого года! В нем приняли участие Джеймс МакЭвой (Уэсли Гибсон), Морган Фриман (Слоан), Константин Хабенский (Истребитель) и Анджелина Джоли (Фокс). В этой книге представлены первые страницы графического романа \"Wanted\", легшего в основу захватывающего фильма.  Уэсли Гибсон (Джеймс МакЭвой) - зануда и нытик, целыми днями торчащий в офисе. Босс его унижает, подружка ему изменяет. Его жизнь катится в никуда! Обнаружив, что отец, бросивший его в раннем детстве, зверски убит, Уэс оказывается втянут в тайное общество киллеров под названием \"Братство\". За его обучение берется опытная наставница Фокс (Анджелина Джоли), и этот когда-то прикованный к офисному креслу тихоня развивает молниеносную реакцию и сверхчеловеческую скорость. Однако уже на первом задании Уэс понимает, что есть вещи посложнее, чем вершить судьбы других людей: набраться храбрости и стать хозяином собственной жизни!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999108,"hdCover":""},{"id":"0989303","title":"Мордобой 2","author":"Марк Миллар, Джон Ромита мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001443515/140/abe9/Mark_Millar_Dzhon_Romita_ml.__Mordoboj_2.jpg","isbn":"978-5-91339-340-1","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Обладая минимальной физподготовкой и парой дубинок, он надел маску и решил стать настоящим супергероем по имени Мордобой. И он преуспел в этом. Более чем. Мордобой и Уби-черныйпояс-вашка бросили Мафии...и победили. Неожиданно, стало модно быть супергероем. Какой же следующий логичный шаг предпринял Мордобой. Присоединился к команде супергероев. Однако бывший союзник Мордобоя, Красный туман, считает, что герои - это прошлый век. Он станет самым известным суперзлодеем. Теперь, когда конфликт перешел в массовое столкновение на Таймс-сквер, сможет ли наш герой выжить?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999107,"hdCover":""},{"id":"0989302","title":"Мордобой","author":"Марк Миллар, Джон Ромита мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001388604/140/8f54/Mark_Millar_Dzhon_Romita_ml.__Mordoboj.jpg","isbn":"978-5-91339-324-1","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"О маньяках и расследованиях. Профайлинг и прочее.И книги на «похоронную» тему","genres":["Комиксы","манга","графические романы"],"annotation":"Легендарный комикс Kick-Ass Марка Миллара и Джона Ромиты-младшего - впервые на русском языке!  Дэйв Лизевски - обычный американский подросток. Ему нравятся девочки, видеоигры и комиксы. Но иногда этого становится недостаточно. Превращение в Мордобоя, первого в мире настоящего супергероя, мгновенно делает его Интернет-знаменитостью.  Обыватели любят его, а преступники боятся. Но вскоре он встречает смертельное оружие в юбке по имени Убивашка и её пугающего напарника Большого Папочку, и дела начинают набирать иной, более серьезный и жестокий оборот.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999106,"hdCover":""},{"id":"0989301","title":"Daytripper. Мечтатель","author":"Фабио Мун,Габриэль Ба","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003326300/140/a4fe/__Daytripper._Mechtatel.jpg","isbn":"978-5-389-17160-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Знакомьтесь: Браз де Олива Домингос. Чудо-ребенок, сын знаменитого бразильского писателя. Днем он сочиняет некрологи, а по ночам мечтает стать известным литератором, придумывая финалы чужих жизней, хотя его собственная только-только началась.  Но когда Браз заметит это? В 21 год, после встречи с девушкой его мечты? В 11 лет, после первого поцелуя? Или позже, после рождения его сына? Или до того, как он обретет свой писательский голос?  Каждый день в жизни Браза – точно страница книги. На каждой странице мы встречаем тех, кто сделал его именно таким: отец и мать, сын и лучший друг, первая любовь и любовь всей жизни. И, как во всех великих произведениях, в каждом дне его ждет новый поворот, который нашему герою не преодолеть...  Лауреаты премии Айснера близнецы Фабио Мун и Габриэль Ба рассказывают волшебную, таинственную и волнующую историю самой жизни. Во время этого поразительного лирического путешествия авторы используют минуты тишины, чтобы задаться серьезными вопросами.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999105,"hdCover":""},{"id":"0989300","title":"Batman: Year 100","author":"Paul Pope","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001245838/140/aef5/Paul_Pope__Batman_Year_100.jpg","isbn":"9781401211929","publisher":"DC Comics","pubDate":"2013","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Visionary writer/artist Paul Pope presents a futuristic mystery of epic proportions set in a dark, dystopian world devoid of privacy and filled with government conspiracies, psychic police, holographic caller ID and absolutely no room for \"secret identities.\"  In Gotham City, 2039, a federal agent is murdered and a contingent of Washington''s top agents is hot on the suspect''s trail. The Batman, a forgotten icon from the past, is wanted for the murder. Amid the chaos Gotham City Police Detective Gordon, grandson of the former commissioner, discovers that the man they are chasing shouldn''t exist at all.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999104,"hdCover":""},{"id":"09892ff","title":"100%","author":"Paul Pope","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000461175/140/b87d/Paul_Pope__100.jpg","isbn":"9781401224615","publisher":"Vertigo","pubDate":"2010","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"All five issues of the edgy, groundbreaking miniseries from writer/artist Paul Pope are collected in one stunning hardcover package. This \"graphic movie\" tells three separate but interconnected stories in Pope''s trademark dynamic style, shifting viewpoints and characters across the urban maze of 2038 Manhattan. Filled with wit, charm, sex and menace, 100% brings a surprisingly true-feeling future to gritty life. The collection also includes a host of character sketches, designs, and other material from creator Pope.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999103,"hdCover":""},{"id":"09892fe","title":"Ultramega #1","author":"James Harren","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1010816507/140/a319/James_Harren__Ultramega_1.jpg","isbn":"","publisher":"","pubDate":"2021","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"A cosmic plague has spread, transforming everyday people into violent, monstrous kaiju. Only the Ultramega—three individuals imbued with incredible powers—hold the line against this madness. Their battles level cities and leave untold horror in their wake. Now, the final reckoning approaches for the Ultramega…but is this a war they can even win?  Fight monsters and stand with humanity in this new Skybound original from the greatest artist of his generation, JAMES HARREN (RUMBLE, BPRD) and Eisner Award-winning colorist DAVE STEWART. Each issue is extra-sized, with a 60-page debut that can barely contain its giant heroes, creatures, and devastation!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999102,"hdCover":""},{"id":"09892fd","title":"Marvel 1602: New World","author":"Грег Пак","type":"Книга","cover":"https://s1.livelib.ru/boocover/1009043230/140/dffc/Greg_Pak__Marvel_1602_New_World.jpg","isbn":"978-0785114949","publisher":"Marvel Comics","pubDate":"2006","language":"","series":"","genres":[],"annotation":"Return to the world of 1602! Rising stars Greg Pak (X-Men: Phoenix -- Endsong) and Greg Tocchini (Thor: Son Of Asgard) pick up where the best-selling story by Neil Gaiman left off: America, the New World! When Captain America was thrust back in time, it changed reality as we know it. Dinosaurs still roam the earth, and the Marvel super heroes we know came to exist 500 years early. Witness David Bruce Banner and Peter Parquagh become the Hulk and Spider-Man in the most eagerly-awaited event of the year!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999101,"hdCover":""},{"id":"09892fc","title":"Marvel 1602: New World/Fantastick Four TPB","author":"Питер Дэвид,Грег Пак,Паскаль Аликсе,Грег Токкини","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000947151/140/79fa/__Marvel_1602_New_WorldFantastick_Four_TPB.jpg","isbn":"978-0785141372","publisher":"Marvel Comics","pubDate":"2010","language":"Английский","series":"Graphic Novel Pb","genres":["Детские книги","Комиксы","манга","графические романы"],"annotation":"Return to the world of 1602! First, Greg Pak and Greg Tocchini pick up where the bestselling story by Neil Gaiman left off: America, the New World! When Captain America was thrust back in time, it changed reality as we know it. Dinosaurs still roam the earth, and the Marvel heroes we know came to exist 500 years early. Now, witness David Bruce Banner and Peter Parquagh become the Hulk and Spider-Man! Then, Peter David and Pascal Alixe take the reins as Doom returns! The Four from the Fantastik''s greatest enemy has an insidious plan that takes them to the ends of the Earth! What does he want? Why doesn''t Invisible Woman want to fight him? And what does Shakespeare have to do with it?  Collects Marvel 1602: New World #1-5, and Marvel 1602: Fantastick Four #1-5.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999100,"hdCover":""},{"id":"09892fb","title":"1602 Ангела, Охотница На Ведьм. Часть 1.","author":"Маргерит Беннетт","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002758774/140/1f9e/Margerit_Bennett__1602_Angela_Ohotnitsa_Na_Vedm._Chast_1..jpg","isbn":"","publisher":"Marvel Comics","pubDate":"2015","language":"","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999099,"hdCover":""},{"id":"09892fa","title":"Marvel 1602: Spider-Man","author":"Джефф Паркер,Рамон Росаньес","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000457451/140/023f/__Marvel_1602_SpiderMan.jpg","isbn":"978-0785128175, 0785128174","publisher":"Marvel Comics","pubDate":"2010","language":"Английский","series":"Marvel 1602","genres":["Комиксы","манга","графические романы"],"annotation":"A return to the acclaimed universe created by Neil Gaiman and Andy Kubert picks up as THE SPIDER has reached manhood in the New World! The young nation has grown peacefully, but Norman Osbourne''s treachery fi nds a way to spoil the peace and put Peter''s life on a new course-back to Europe. Jeff Parker (Agents of Atlas) joins artist Ramon Rosanas in the final story of the 1602 saga!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999098,"hdCover":""},{"id":"09892f9","title":"Я герой Нагасаки","author":"Кэнго Ханадзава","type":"Книга","cover":"https://i.livelib.ru/workpic/1005719038/140/08ef/Kengo_Hanadzava__Ya_geroj_Nagasaki.jpg","isbn":"","publisher":"","pubDate":"","language":"","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999097,"hdCover":""},{"id":"09892f8","title":"Hiroaki Samura''s Emerald and Other Stories","author":"Hiroaki Samura","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001782806/140/7d42/Hiroaki_Samura__Hiroaki_Samura039s_Emerald_and_Other_Stories.jpg","isbn":"9781616550653","publisher":"","pubDate":"2015","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999096,"hdCover":""},{"id":"09892f7","title":"Batman: The Caped Crusader Vol. 5","author":"Питер Миллиган","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007470912/140/0cdf/Piter_Milligan__Batman_The_Caped_Crusader_Vol._5.jpg","isbn":"978-1779506016","publisher":"DC","pubDate":"2021","language":"","series":"","genres":[],"annotation":"Gotham City is plagued by an endless supply of criminals who unleash constant chaos upon the city. But Gotham has a protector: Batman, the fearless Caped Crusader. He stands ever ready to fight the mayhem and keep the citizens of Gotham safe, one night at a time.  With the Ghost Dragon gang committing daring warehouse robberies, Batman and Robin chase the gang''s lieutenant, Lynx, through the streets. When Robin discovers an old nemesis—the Ghosts'' dead leader, King Snake—might be alive and out for Robin''s head, the stakes only get higher! Plus, Batman travels to Rio de Janeiro to track a serial killer known as the Queen of Hearts, a woman whose life he once saved. Can the Caped Crusader battle his way through the streets filled with drug-addled teenagers and a bizarre dimension known as the Idiot Zone?  An all-star cast of talent, led by Peter Milligan (Justice League Dark), Norm Breyfogle (Detective Comics), and Jim Aparo (The Brave and the Bold), presents Batman: The Caped Crusader Vol. 5,","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999095,"hdCover":""},{"id":"09892f6","title":"Batman: The Caped Crusader Vol. 6","author":"Alan Grant","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007470918/140/d1b6/Alan_Grant__Batman_The_Caped_Crusader_Vol._6.jpg","isbn":"978-1779508003","publisher":"DC","pubDate":"2022","language":"","series":"","genres":[],"annotation":"A new collection featuring the legendary 1990s Batman epics \"The Return of Scarface\" and more!   This new collection of 1990s Batman tales includes the legendary story \"The Return of Scarface,\" one of DC''s most vindictive villains made famous from the Batman: The Animated Series. This volume also includes the first appearance of the Gotham Gargoyle, and a run of stories in which the Dark Knight must stop crime boss Zucco.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999094,"hdCover":""},{"id":"09892f5","title":"Batman: The Caped Crusader Vol. 3","author":"Марв Вульфман","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007470906/140/7363/Marv_Vulfman__Batman_The_Caped_Crusader_Vol._3.jpg","isbn":"978-1401294274","publisher":"DC","pubDate":"2019","language":"","series":"","genres":[],"annotation":"A new collection featuring the legendary 1990s Batman epics \"Dark Knight, Dark City\" and more.  THE CAPED CRUSADER  Batman leaves the crime-riddled streets of Gotham City for the snowy cityscape of Moscow to hunt a disciple of the KGBeast known as the NKVDemon who is mercilessly killing members of the Soviet Union''s Politburo. Bruce Wayne must first ditch the Soviet agents keeping a watchful eye on him to don his cowl and cape and confront this new Soviet assassin.  Back in Gotham, Batman confronts a new scheme by the Penguin who has enlisted the help of Harold, a hunchback genius who has invented a technology to control birds to use them as an unconventional army--and as assassins. Then the Caped Crusader must deal with a newly vicious and bloodthirsty Riddler, as the villain kidnaps innocent babies and leads Batman through a labyrinth of grim trials to rescue them.  An all-star cast of talent, led by legendary writer Marv Wolfman (Crisis on Infinite Earths) and featuring the dynamic art of Jim Aparo (The Brave and the Bold), and Norm Breyfogle (Detective Comics), presents Batman: The Caped Crusader Vol. 3,","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999093,"hdCover":""},{"id":"09892f4","title":"Batman: The Caped Crusader Vol. 4","author":"Alan Grant","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007470909/140/1c09/Alan_Grant__Batman_The_Caped_Crusader_Vol._4.jpg","isbn":"978-1779500304","publisher":"DC","pubDate":"2020","language":"","series":"","genres":[],"annotation":"Gotham City has endured much through its dark, twisted history, and even the cosmic changes wrought by the Crisis on Infinite Earths couldn''t give the town a fresh start--the grime is in its DNA. The Crisis did, though, allow for the reintroduction of familiar foes, albeit with a fresh take on the Caped Crusader featuring a back-to-basics approach to crime-fighting.  This new collection of 1990s Batman stories reveals the origin story of Tim Drake as Robin. With crime running amok and an overwhelming sense of responsibility to help all, Batman considers partnering up. Commissioner Gordon rekindles an old flame and Batman decides whether or not he is ready to fight crime with a partner by his side.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999092,"hdCover":""},{"id":"09892f3","title":"Batman: The Caped Crusader Vol. 2","author":"Марв Вульфман","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007470903/140/a7bf/Marv_Vulfman__Batman_The_Caped_Crusader_Vol._2.jpg","isbn":"978-1401287825","publisher":"DC","pubDate":"2019","language":"","series":"","genres":[],"annotation":"A new collection featuring the legendary 1990s Batman epics \"The Many Deaths of Batman\" and \"A Lonely Place of Dying.\"  This new collection of 1980s Batman tales includes the legendary story \"A Lonely Place of Dying,\" in which a new Robin emerges in the form of computer hacker Tim Drake, who rescues Batman from The Joker and Two-Face. This volume also includes the mystery story \"The Many Deaths of Batman,\" and a run of stories in which the Dark Knight must stop crime boss Zucco.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999091,"hdCover":""},{"id":"09892f2","title":"Batman: The Caped Crusader Vol. 1","author":"Джим Старлин","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007470900/140/fba5/Dzhim_Starlin__Batman_The_Caped_Crusader_Vol._1.jpg","isbn":"978-1401281366","publisher":"DC","pubDate":"2018","language":"","series":"","genres":[],"annotation":"Gotham City has endured much through its dark, twisted history, and even the cosmic changes wrought by the Crisis on Infinite Earths couldn''t give the town a fresh start--the grime is in its DNA. The Crisis did, though, allow for the reintroduction of familiar foes, albeit with a fresh take on the Caped Crusader featuring a back-to-basics approach to crime-fighting.  Criminals don''t always wear a colorful costumes: some just stalk the shadows with sinister plots and evil intentions. A new threat, a fearsome assassin known as the KGBeast, is prowling the streets of Gotham City and he''s out to dismantle America''s Strategic Defense Initiative. After saving the United States government, Batman must then solve the mystery of ten murdered women before the killer claims even more victims!  An all-star cast of talent, led by writer Jim Starlin (Batman: The Cult, Mystery In Space) and the dynamic art duo of Jim Aparo (The Brave and The Bold, Batman & The Outsiders) and Mike DeCarlo (The Legion Of Super-Heroes), present Batman: The Caped Crusader Vol. 1,","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999090,"hdCover":""},{"id":"09892f1","title":"Сага Электра","author":"Фрэнк Миллер","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007476609/140/7147/Frenk_Miller__Saga_Elektra.jpg","isbn":"","publisher":"Марвел","pubDate":"1983","language":"","series":"#168, 174-182 и 187-190","genres":[],"annotation":"Электра уехала изучать боевые искусства в Японии, где вскоре примкнула к тайной организации боевых искусств, возглавляемой Стиком, который также был сэнсэем у Мёрдока. Электра провела там год и значительно развила свои навыки в боевых искусствах. Но Стик попросил её выйти из группы, потому что её по-прежнему переполняет боль от смерти отца и она испытывает ненависть к миру. Электра уходит к своему старому сэнсэю.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999089,"hdCover":""},{"id":"09892f0","title":"PLUTO: Urasawa x Tezuka, Volume 001","author":"Naoki Urasawa","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001133418/140/f64b/Naoki_Urasawa__PLUTO_Urasawa_x_Tezuka_Volume_001.jpg","isbn":"1421519186,  978-1-42-151918-0","publisher":"VIZ Media LLC","pubDate":"2009","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"In a distant future where sentient humanoid robots pass for human, someone or some thing is out to destroy the seven great robots of the world. Europol''s top detective Gesicht is assigned to investigate these mysterious robot serial murders. the only catch is that he himself is one of the seven targets.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999088,"hdCover":""},{"id":"09892ef","title":"Chew, Volume 5","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001994501/140/6ca8/Dzhon_Lajman_Rob_Gillori__Chew_Volume_5.jpg","isbn":"","publisher":"","pubDate":"","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"This gorgeous oversized edition collects the ninth and tenth storylines of the New York Times Best Selling, Harvey and multiple Eisner Award series, as well as the beloved one-shot WARRIOR CHICKEN POYO. Collects CHEW #41-#50 plus WARRIOR CHICKEN POYO.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999087,"hdCover":""},{"id":"09892ee","title":"Chew, Volume 6","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002698655/140/4d69/Dzhon_Lajman_Rob_Gillori__Chew_Volume_6.jpg","isbn":"1534301801","publisher":"Image Comics","pubDate":"2017","language":"Английский","series":"Chew","genres":["Комиксы","манга","графические романы"],"annotation":"The final story arc of Tony Chu, the cibopathic federal agent with the ability to get psychic impressions from what he eats. Mysteries are solved, secrets are reveals and lives are lost. Many, many lives. This is the end of the line for the New York Times Best Selling, Harvey and multiple Eisner Award-winner series about cops, crooks, cooks, cannibals, and clairvoyants.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999086,"hdCover":""},{"id":"09892ed","title":"Chew, Volume 4","author":"Джон Лайман, Роб Гиллори","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002765999/140/669f/Dzhon_Lajman_Rob_Gillori__Chew_Volume_4.jpg","isbn":"163215031X","publisher":"Image Comics","pubDate":"2014","language":"Английский","series":"","genres":[],"annotation":"A glorious Hardcover collection of CHEW #31-#40 with all the fixin''s. Anthony and Antonelle Chu are fraternal twins. Tony and Toni. Each with their an extraordinary, albeit diametrically opposed, ability. Tony is Cibopathic, able to get psychic sensations of the past of anything he bites into or ingests. Toni is Cibovoyant, able to flash onto a vision of the future of any living thing she bit into or ingested.  Tony is alive. Toni is dead. Toni has been murdered. Tony has vowed to catch her killer. Toni is going to help.  Presenting a new storyline of the New York Times Best Selling, Harvey and multiple Eisner Award-winning series about cops, crooks, cooks, cannibals, and clairvoyants.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999085,"hdCover":""},{"id":"09892ec","title":"Chew Volume 12: Sour Grapes","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002141751/140/0d99/Dzhon_Lajman_Rob_Gillori__Chew_Volume_12_Sour_Grapes.jpg","isbn":"978-1534300316","publisher":"Image Comics","pubDate":"2017","language":"Английский","series":"","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"The final story arc of Tony Chu, the cibopathic federal agent with the ability to get psychic impressions from what he eats. Mysteries are solved, secrets are revealed, and lives are lost. Many, many lives. This is the end of the line for the New York Times bestselling, Harvey and multiple Eisner Award-winning series about cops, crooks, cooks, cannibals, and clairvoyants.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999084,"hdCover":""},{"id":"09892eb","title":"Chew Volume 11: The Last Suppers","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002004257/140/02f4/Dzhon_Lajman_Rob_Gillori__Chew_Volume_11_The_Last_Suppers.jpg","isbn":"978-1632156815","publisher":"Image Comics","pubDate":"2016","language":"Английский","series":"","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"Tony Chu, the cibopathic federal agent with the ability to get psychic impressions from what he eats, is getting closer to finding the answers he’s been looking for—answers about the bird flu that killed millions, answers about the conspiracy to keep people from discovering the truth. And the only thing standing in Tony’s way is his Mason Savoy, fellow cibopath, ex-mentor—and unrepentant murderer! Presenting the second-to-last storyline of the New York Times Best Selling, Harvey and multiple Eisner Award-winner series about cops, crooks, cooks, cannibals, and clairvoyants.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999083,"hdCover":""},{"id":"09892ea","title":"Chew Volume 10: Blood Puddin''","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001493868/140/2e83/Dzhon_Lajman_Rob_Gillori__Chew_Volume_10_Blood_Puddin039.jpg","isbn":"978-1632153968","publisher":"Image Comics","pubDate":"2015","language":"Английский","series":"","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"CAN TONY STOP HIS MOST DANGEROUS ENEMY? Presenting a new storyline of the New York Times Best Selling, Harvey- and multiple Eisner Award-winning series about cops, crooks, cooks, cannibals, and clairvoyants.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999082,"hdCover":""},{"id":"09892e9","title":"Chew Volume 9: Chicken Tenders","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001493867/140/2e83/Dzhon_Lajman_Rob_Gillori__Chew_Volume_9_Chicken_Tenders.jpg","isbn":"978-1632152893","publisher":"Image Comics","pubDate":"2015","language":"Английский","series":"Chew","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"Tony Chu, the cibopathic federal agent with the ability to get psychic impressions from what he eats, has been busy — busy settling into married life, and busy investigating one assignment after another that takes him to the most remote corners of the planet. Meanwhile, the people closest to Tony are conspiring to take on the brutal killer who murdered Tony’s twin sister. And this conspiracy includes Tony’s partner, his arch enemy — and his teenage daughter!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999081,"hdCover":""},{"id":"09892e8","title":"Chew Volume 8: Family Recipes","author":"Джон Лайман, Роб Гиллори","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001493866/140/2e83/Dzhon_Lajman_Rob_Gillori__Chew_Volume_8_Family_Recipes.jpg","isbn":"978-1607069386","publisher":"Image Comics","pubDate":"2014","language":"Английский","series":"Chew","genres":[],"annotation":"Anthony and Antonelle Chu are fraternal twins. Tony and Toni. Each with their own extraordinary, albeit diametrically opposed, ability. Tony is Cibopathic, able to get psychic sensations of the past of anything he bites into or ingests. Toni is Cibovoyant, able to flash onto a vision of the future of any living thing she bit into or ingested. Tony is alive. Toni is dead. Toni has been murdered. Tony has vowed to catch her killer. Toni is going to help.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999080,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09892e7","title":"Chew Volume 7: Bad Apples","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001493864/140/2e83/Dzhon_Lajman_Rob_Gillori__Chew_Volume_7_Bad_Apples.jpg","isbn":"978-1607067672","publisher":"Image Comics","pubDate":"2013","language":"Английский","series":"Chew","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"Presenting a new storyline of the New York Times Bestselling, Harvey and multiple Eisner Award-winning series about cops, crooks, cooks, cannibals, and clairvoyants. Tony Chu — the cibopathic federal agent with the ability to get psychic impressions from what he eats — is back in action, just in time to face a cult of egg-worshipping terrorists who''ve declared holy war on the chicken-eaters of the world.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999079,"hdCover":""},{"id":"09892e6","title":"Chew, Vol. 6: Space Cakes","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001493863/140/2e83/Dzhon_Lajman_Rob_Gillori__Chew_Vol._6_Space_Cakes.jpg","isbn":"978-1607066217","publisher":"Image Comics","pubDate":"2013","language":"Английский","series":"Chew","genres":["Комиксы","манга","графические романы"],"annotation":"While Tony Chu — the cibopathic federal agent with the ability to get psychic impressions from what he eats — clings to life in a hospital ICU, his twin sister Toni steps up to take center stage. Toni is cibovoyant, able to see the future of anything she eats, and, lately, she’s seeing some pretty terrible things. Presenting a new storyline of the New York Times Bestselling, Harvey and multiple Eisner Award-winning series about cops, crooks, cooks, cannibals, and clairvoyants.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999078,"hdCover":""},{"id":"09892e5","title":"Chew, Volume 5: Major League Chew","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001493862/140/2e83/Dzhon_Lajman_Rob_Gillori__Chew_Volume_5_Major_League_Chew.jpg","isbn":"978-1607065234","publisher":"Image Comics","pubDate":"2012","language":"Английский","series":"Chew","genres":["Комиксы","манга","графические романы"],"annotation":"Tony Chu — the cibopathic federal agent with the ability to get psychic impressions from what he eats — has been kidnapped! He was ambushed, knocked out, brought to a remote location, and bound securely. His captor intends to feed Tony from a menu of his choosing, to find out what Tony can see, in order to learn from him. His daughter, Olive, has been kidnapped for the exact same reason. Two kidnappers, two captives, and two very different outcomes.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999077,"hdCover":""},{"id":"09892e4","title":"Chew Volume 4: Flambe","author":"Джон Лайман, Роб Гиллори","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001236579/140/4d67/Dzhon_Lajman_Rob_Gillori__Chew_Volume_4_Flambe.jpg","isbn":"978-1607063988","publisher":"Image Comics","pubDate":"2011","language":"Английский","series":"Chew","genres":[],"annotation":"These are strange times for Tony Chu, the cibopathic federal agent with the ability to get psychic impressions from the things he eats. Strange writing in extraterrestrial script has appeared in the skies of Planet Earth - and stayed there! People don''''t know if the end days are upon them or not, but they don''''t seem terribly concerned about the laws of the FDA, and what was once the most powerful law enforcement agency is rapidly descending into irrelevancy. So where does that leave the FDA best agent, Tony Chu?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999076,"hdCover":""},{"id":"09892e3","title":"Chew Volume 3: Just Desserts","author":"Джон Лайман, Роб Гиллори","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001236578/140/4d67/Dzhon_Lajman_Rob_Gillori__Chew_Volume_3_Just_Desserts.jpg","isbn":"978-1607063353","publisher":"Image Comics","pubDate":"2010","language":"Английский","series":"Chew Book Series","genres":[],"annotation":"Things are looking up for Tony Chu, the cibopathic federal agent with the ability to get psychic impressions from the things he eats. He''s got a girlfriend. He''s got a partner he trusts. He even seems to be getting along with his jerk boss. But his ruthless ex-partner is still out there, operating outside of the law, intending to make good on his threats against Tony and everybody Tony cares about. It''s just a matter of time before their investigations collide, blood spills and, inevitably, body parts are eaten!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999075,"hdCover":""},{"id":"09892e2","title":"Chew Volume 2: International Flavor","author":"Rob Guillory, John Layman","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001236571/140/4d67/Rob_Guillory_John_Layman__Chew_Volume_2_International_Flavor.jpg","isbn":"978-1607062608","publisher":"Image Comics","pubDate":"2010","language":"Английский","series":"Chew","genres":[],"annotation":"Tony Chu, the cibopathic federal agent with the ability to get psychic impressions from the things he eats, is on a bizarre new case. A newly discovered fruit takes Agent Chu to a remote island full of secrets, Presenting the second storyline of IGN.com''s pick for Best Indie Series of 2009 and MTV Splash Page.com''s pick for Best New Series of 2009. Find out what the fuss is about in this latest a twisted and darkly funny comic about cops, crooks, cooks, cannibals and clairvoyants.strangeness-and a shadowy killer with a particularly sinister appetite.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999074,"hdCover":""},{"id":"09892e1","title":"Жуй. Книга 3 (сборник)","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002875952/140/06b5/Dzhon_Lajman_Rob_Gillori__Zhuj._Kniga_3_sbornik.jpg","isbn":"978-5-91996-207-6","publisher":"XL Media","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"Тони и Тоня Чжуй — близнецы. Тони — цибопат, а это значит, что он может получать экстрасенсорные впечатления от любой еды, которую ест. А еще Тони может попробовать часть тела умершего человека и узнать, чем тот занимался в прошлом. Тоня — цибо воянт, а это значит, что, укусив любого живого человека, она увидит его будущее. Тони недавно вышибли со службы в особом отделе Федеральной Службы Контроля Продуктов, и он стал простым патрульным Муниципальной дорожной инспек ции, а Тоня — действующий агент НАСА, ныне самой могущественной организации в мире. Теперь именно ей предстоит расследовать всякие странные и загадочные нераскрытые дела...  Перед вами невероятная нарезка из черного юмора, фантастики и умело обыгран ных штампов полицейского боевика, приправленная обязательными ингредиентами второсортного кино: спецагентами, мошенниками, людоедами и экстрасенсами. Вас ждет незабываемое послевкусие, и вы наверняка не откажетесь от добавки! В эту книгу вошли пятая и шестая части серии: «Высшая лига» и «Космические плюшки», а также специальный выпуск о приключениях секретного агента — бойцового петуха Пойо!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999073,"hdCover":""},{"id":"09892e0","title":"Жуй. Книга 1 (сборник)","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001269459/140/406a/Dzhon_Lajman_Rob_Gillori__Zhuj._Kniga_1_sbornik.jpg","isbn":"978-5-91996-062-1","publisher":"XL Media","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"У детектива Тони Чжуя есть один очень неприятный секрет. Чжуй - цибопат, а это значит, что он может получать экстрасенсорные видения от любой еды, которую попробует. А еще Чжуй не перед чем не остановится ради того, чтобы раскрыть преступление и найти виновного. Даже если это означает попробовать кусочек трупа жертвы, если в этом будет необходимость... Способности Тони оказываются чересчур пугающими для службы в обычной полиции, зато идеально подходят для работы в особом отделе Федеральной Службы Контроля Продуктов, самой могущественной правоохранительной организации в мире. Ему предстоит расследовать самые странные и загадочные нераскрытые дела. Перед вами невероятная нарезка из черного юмора, фантастики и умело обыгранных штампов полицейского боевика, приправленная обязательными ингредиентами второсортного кино: полицейскими, мошенниками, людоедами и экстрасенсами. Вас ждет незабываемое послевкусие и вы наверняка не откажетесь от добавки! В этой книге вас ждут две первые части серии: \"Вкус жизни\", попавшая в список бестселлеров \"Нью-Йорк Таймс\", и ее продолжение - \"Вкус без границ\".","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999072,"hdCover":""},{"id":"09892df","title":"Жуй. Книга 2 (сборник)","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001619248/140/018f/Dzhon_Lajman_Rob_Gillori__Zhuj._Kniga_2_sbornik.jpg","isbn":"978-5-91996-093-5","publisher":"XL Media","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"У детектива Тони Чжуя есть один очень неприятный секрет. Чжуй - цибопат, а это значит, что он может получать экстрасенсорные видения от любой еды, которую попробует. А еще Чжуй не перед чем не остановится ради того, чтобы раскрыть преступление и найти виновного. Даже если это означает попробовать кусочек трупа жертвы, если в этом будет необходимость... Способности Тони оказываются чересчур пугающими для службы в обычной полиции, зато идеально подходят для работы в особом отделе Федеральной Службы Контроля Продуктов, самой могущественной правоохранительной организации в мире. Ему предстоит расследовать самые странные и загадочные нераскрытые дела.  Перед вами невероятная нарезка из черного юмора, фантастики и умело обыгранных штампов полицейского боевика, приправленная обязательными ингредиентами второсортного кино: полицейскими, мошенниками, людоедами и экстрасенсами. Вас ждет незабываемое послевкусие и вы наверняка не откажитесь от добавки! В эту книгу вошли третья и четвертая части серии: \"Только десерт\" и \"Фламбе\".","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999071,"hdCover":""},{"id":"09892de","title":"人でなしの恋 / Hitodenashi no Koi Izumi Komitsukusu","author":"Хироаки Самура","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001447062/140/6491/Hiroaki_Samura__%E4%BA%BA%E3%81%A7%E3%81%AA%E3%81%97%E3%81%AE%E6%81%8B__Hitodenashi_no_Koi_Izumi_Komitsukusu.jpg","isbn":"978-4870766549","publisher":"Issuisya","pubDate":"2006","language":"Японский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999070,"hdCover":""},{"id":"09892dd","title":"Magneto, Volume 3: Shadow Games","author":"Cullen Bunn","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002066433/140/4ce4/Cullen_Bunn__Magneto_Volume_3_Shadow_Games.jpg","isbn":"","publisher":"Marvel","pubDate":"2015","language":"Английский","series":"","genres":[],"annotation":"In his war against those who would see his kind extinguished, Magneto has one steadfast ally: the mysterious woman called Briar Raleigh. But what are her true designs for the Master of Magnetism? On the island of Genosha, the backdrop for his greatest triumphs and most devastating tragedies, Magneto is confronted by S.H.I.E.L.D.! But the Master of Magnetism doesn''t stand alone...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999069,"hdCover":""},{"id":"09892dc","title":"Magneto Vol. 4: Last Days","author":"Paul Davidson,Каллен Банн","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002971904/140/5230/__Magneto_Vol._4_Last_Days.jpg","isbn":"","publisher":"Marvel","pubDate":"2015","language":"","series":"Magneto","genres":[],"annotation":"Earth is on a collision course with oblivion, and Magneto has just learned that time is running out. With everything he''s fought for being brought to an end, how will the Master of Magnetism spend his last days on Earth? Will he celebrate his legacy? Be tortured by his past? Or take it upon himself to stop the end of all things? Desperate to prevent the mutant race from its inevitable extinction, Magneto faces down the gruesome Sugar Man. But has the key to salvation been right in front of him all along — in the form of his daughter, Polaris? With Earth on the verge of destruction, the Master of Magnetism is determined to be mutantkind''s savior at long last — but what terrible price is he willing to pay?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999068,"hdCover":""},{"id":"09892db","title":"Человек-череп. Том 4","author":"Симамото Кадзухико,Исиномори Сетаро","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000955904/140/92a6/__Chelovekcherep._Tom_4.jpg","isbn":"978-5-7525-2916-0,  978-5-7525-2912-2,  978-4-8899-1726-0","publisher":"Фабрика комиксов","pubDate":"2014","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"У него забрали семью, лицо и саму душу, но он вернулся из страны мертвых, чтобы отомстить злодеям и заодно узнать, кто наделил его сверхъестественными способностями. В сопровождении верного помощника Гаро, в случае опасности трансформирующегося в огромных размеров волка, крокодила и летучую мышь, он идет по следу заказчика убийства своих родителей, но когда достигает цели, правда оказывается слишком ужасной даже для такого хладнокровного и бездушного мстителя, как он. Порвав с прошлым, он начинает бороться против таинственного синдиката, управляющего всем преступным миром страны. Он будет защищать людей. Он никогда не остановится. он будет испепелять врагов адским огнем, что бушует внутри него. Он - Человек-череп!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999067,"hdCover":""},{"id":"09892da","title":"Человек-череп. Том 3","author":"Симамото Кадзухико,Исиномори Сетаро","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000946333/140/5842/__Chelovekcherep._Tom_3.jpg","isbn":"978-5-7525-2915-3,  978-5-7525-2912-2,  978-4-8899-1716-1","publisher":"Фабрика комиксов","pubDate":"2014","language":"Русский","series":"Сыщик Патмосов","genres":["Комиксы","манга","графические романы"],"annotation":"У него забрали семью, лицо и саму душу, но он вернулся из страны мертвых, чтобы отомстить злодеям и заодно узнать, кто наделил его сверхъестественными способностями. В сопровождении верного помощника Гаро, в случае опасности трансформирующегося в огромных размеров волка, крокодила и летучую мышь, он идет по следу заказчика убийства своих родителей, но когда достигает цели, правда оказывается слишком ужасной даже для такого хладнокровного и бездушного мстителя, как он. Порвав с прошлым, он начинает бороться против таинственного синдиката, управляющего всем преступным миром страны. Он будет защищать людей. Он никогда не остановится. он будет испепелять врагов адским огнем, что бушует внутри него. он - человек-череп!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999066,"hdCover":""},{"id":"09892d9","title":"Человек-череп. Том 2","author":"Симамото Кадзухико,Исиномори Сетаро","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000942108/140/d90b/__Chelovekcherep._Tom_2.jpg","isbn":"978-5-7525-2914-6,  978-5-7525-2912-2,  978-4-8899-1708-6","publisher":"Фабрика комиксов","pubDate":"2014","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"У него забрали семью, лицо и саму душу, но он вернулся из страны мертвых, чтобы отомстить злодеям и заодно узнать, кто наделил его сверхъестественными способностями. В сопровождении верного помощника Гаро, в случае опасности трансформирующегося в огромных размеров волка, крокодила и летучую мышь, он идет по следу заказчика убийства своих родителей. Но когда достигает цели, правда оказывается слишком ужасной даже для такого хладнокровного и без-душного мстителя, как он. Порвав с прошлым, он начинает бороться против таинственного синдиката, управляющего всем преступным миром страны. Он будет защищать людей. Он никогда не остановится. Он будет испепелять врагов адским огнем, что бушует внутри него. Он - Человек-череп!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999065,"hdCover":""},{"id":"09892d8","title":"День революционера","author":"Дзиро Мацумото","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002472588/140/7b72/Dziro_Matsumoto__Den_revolyutsionera.jpg","isbn":"978-5-905295-37-9","publisher":"Alt Graph","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"«День революционера» — сборник из пяти разношёрстных историй от одного из самых необычных и неоднозначных авторов сэйнэн-манги Дзиро Мацумото, известного своими работами «Фризия» и «Дикая планета». Истории не объединены общим сюжетом, но их связывает иррациональность окружающей действительности и трагикомичность нашей жизни.  Это книга полна иронии, чёрного юмора, сюрреализма и, конечно, насилия и секса. Срез жизни, который автор мастерский преподносит в своем фирменном стиле, одновременно реалистичном и карикатурном, сказочном и хулиганском. Эта манга рассмешит вас или заставит задуматься, но точно не даст заскучать!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999064,"hdCover":""},{"id":"09892d7","title":"Странники. Том 1","author":"Макото Юкимура","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002872217/140/9a9e/Makoto_Yukimura__Stranniki._Tom_1.jpg","isbn":"978-5-905295-47-8","publisher":"Alt Graph","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"На дворе 2074 год. Человечество покоряет орбиты ближайших планет и разрабатывает месторождения экзотических ресурсов по всей Солнечной системе, но даже на новых горизонтах люди остаются теми же, что на Земле. Они привносят в космос свои земные проблемы: взаимную ненависть, социальное неравенство, загрязнение окружающей среды, извечный поиск себя и тоску по неизведанному. Но, как и на старушке Земле, на просторах космоса найдутся те, кто будет противостоять извечным проблемам человечества своей целеустремлённостью, трудолюбием и надеждой на лучшее. На стареньком и потрёпанном космическом мусоросборщике, который очищает земную орбиту от списанных спутников, различных обломков и прочего мусора, работает разношёрстная команда: самоуверенный мечтатель Хатимаки, грезящий о собственном космическом корабле, молчаливый Юрий, медитирующий на остатки разбитых спутников, и грозная капитан Фи, подчас готовая на всё ради сигареты. Они не герои галактики. И на первый взгляд их опасная работёнка может показаться скучной и однообразной. Но среди старого хлама всегда можно отыскать что-то неожиданное: начиная от сентиментальных ценностей и заканчивая мировым заговором. Пристегните ремни, ключ на старт — одиссея космических странников начинается!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999063,"hdCover":""},{"id":"09892d6","title":"Своими глазами","author":"Кэйдзи Накадзава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002086660/140/49af/Kejdzi_Nakadzava__Svoimi_glazami.jpg","isbn":"978-5-905295-33-1","publisher":"Alt Graph","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"«Своими глазами» — автобиографический рассказ Кэйдзи Накадзавы, опубликованный в 1972 году в журнале Monthly Shonen Jump. На страницах этого рассказа Кэйдзи Накадзава впервые поделился с широкой публикой своими воспоминаниями о войне, ядерном взрыве, а также о тяготах и лишениях, которые преследовали его семью в послевоенные годы. Эта история вызвала широкий резонанс в японском обществе, где тема ядерных бомбардировок Хиросимы и Нагасаки оставалась негласным табу на протяжении долгих лет. Именно рассказ «Своими глазами» подтолкнул Кэйдзи Накадзаву на создание его самой известной манги — «Босоногого Гэна».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999062,"hdCover":""},{"id":"09892d5","title":"Fatale #1","author":"Ed Brubaker","type":"Книга","cover":"https://s1.livelib.ru/boocover/1000529082/140/7612/Ed_Brubaker__Fatale_1.jpg","isbn":"","publisher":"","pubDate":"2012","language":"","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999061,"hdCover":""},{"id":"09892d4","title":"Город, в котором меня нет. Том 1","author":"Кэй Самбэ","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002845010/140/63a8/Kej_Sambe__Gorod_v_kotorom_menya_net._Tom_1.jpg","isbn":"978-5-907014-30-5","publisher":"Истари Комикс","pubDate":"2018","language":"Русский","series":"Город, в котором меня нет","genres":["Комиксы","манга","графические романы"],"annotation":"Жизнь Сатору Фудзинумы не задалась — ему почти тридцать, а он так и не нашёл своего места в мире. Кроме будничных невзгод ему приходиться мириться ещё и со странным феноменом, «перемоткой», о котором не знает больше никто. Но вскоре одно событие целиком переворачивает его жизнь, разделив её на «до» и «после». Гибель одноклассников, дело серийного убийцы, похищавшего детей, близкий друг, которого он не смог защитить, и неразгаданная тайна личности преступника заставляют Сатору заглянуть в прошлое, и его настоящее начинает меняться.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999060,"hdCover":""},{"id":"09892d3","title":"Нелюдь. Том 1","author":"Гамон Сакураи,Цуйна Миура","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002603019/140/1751/__Nelyud._Tom_1.jpg","isbn":"978-5-91996-125-3","publisher":"XL Media","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Семнадцать лет назад в Африке обнаружили первого из так называемых нелюдей - существ, которые внешне неотличимы от людей, но которых невозможно убить. Это открытие стало для человечества событием огромного масштаба, но спустя годы шумиха улеглась: хотя нелюди по-прежнему невероятно важны для мировых правительств и научных лабораторий, на жизнь простых обывателей их существование почти никакого влияния не оказывает.  Обычный старшеклассник Кэй Нагаи никогда не думал, что когда-нибудь столкнется с этими полумифическими существами. Но однажды он попадает в аварию и по всем известным законам медицины должен умереть - но... почему-то не умирает. И тут же становится объектом жестокой охоты...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999059,"hdCover":""},{"id":"09892d2","title":"Blame! Том 1","author":"Цутому Нихэй","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002326163/140/ee57/Tsutomu_Nihej__Blame_Tom_1.jpg","isbn":"978-5-91996-130-7","publisher":"XL Media","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Может быть, на Земле… Может быть, в далеком будущем… В мире, называемом Мегаструктурой, – невероятном по размерам многоуровневом лабиринте, населенном последними представителями человечества и всевозможными странными существами частично или полностью небиологического происхождения, – молодой человек по имени Килли, преодолевая этаж за этажом, постепенно поднимается наверх. Он ищет Сетевые Терминальные Гены, с помощью которых можно подключиться к Сетевой сфере, но носителей этих генов почти не осталось. Увенчаются ли успехом поиски Килли?  Архитектор по профессии, Цутому Нихэй смог создать удивительный, уникальный мир, где сочетаются техногенные образы далекого будущего и мрачный дух постапокалиптики. Манга «Blame!» – один из общепризнанных шедевров научной фантастики, прославившийся благодаря как уникальному художественному стилю, так и неповторимой атмосфере безысходности и тайны.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999058,"hdCover":""},{"id":"09892d1","title":"Redrum 327. Том 1","author":"Я Сен Ко","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000316163/140/0bba/Ya_Sen_Ko__Redrum_327._Tom_1.jpg","isbn":"978-5-7525-1823-2,  978-5-7525-1822-5,  89-528-5911-1,  978-985-16-5972-8","publisher":"Харвест, Фабрика комиксов","pubDate":"2008","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Отправлялись на выходные в уединенный горный коттедж, семеро студентов университета и представить не могли, что их романтический уикенд превратится в настоящий кошмар. Появление новичка - прекрасной и загадочной девушки по имени Гаэ - вносит разлад в компанию старых друзей. Мрачная атмосфера пронизываемого холодными ветрами дома пробуждает в душе подростков навязчивые воспоминания о давнишней трагедии, которая, казалось, была забыта навсегда. Мелкие ссоры, любовные трагедии, сведение старых счетов - все это стало только прелюдией к ужасу, воцарившемуся под сводами виллы, когда обнаружилась пропажа одной из девушек. Кто затаился в окружающей дом темноте? Кто перерезал телефонные провода и вывел из строя единственную машину? Отрезанные от внешнего мира, преследуемые неведомым маньяком, друзья с замиранием сердца ждут очередного удара неумолимого рока. Новая манхва Я-Сен Ко выполнена в лучших традициях \"Сияния\" С.Кинга и \"Крика\" У.Крейвена.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999057,"hdCover":""},{"id":"09892d0","title":"Redrum 327. Том 2","author":"Я Сен Ко","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000315985/140/0bba/Ya_Sen_Ko__Redrum_327._Tom_2.jpg","isbn":"978-5-7525-1828-7,  978-5-7525-1822-5,  89-528-5911-1,  89-528-5910-3","publisher":"Фабрика комиксов","pubDate":"2009","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Отправляясь на выходные в уединенный горный коттедж, семеро студентов университета и предста­вить не могли, что их романтический уикенд Пре­вратится в самый настоящий кошмар. Появление новичка, прекрасной и загадочной девушки по имени Газ, вносит разлад в компанию старых друзей. Мрачная атмосфера пронизываемого колодными ветрами доме пробуждает в душе подростков навяз­чивые воспоминания о давнишней трагедии, кото­рая, казалось, была забыта навсегда. Мелкие ссоры, любовные трагедии, сведение старых счетов -все это становится лишь прелюдией к ужасу, обрушивающемуся на молодых людей с приходом ночи. Кто прячется в темных закоулках дома? Кто -вывел из строя телефонную линию, соединявшую обитателей виллы с внешним миром? Потерявшие надежду на помощь извне, преследуемые неведо­мым маньяком друзья с замиранием сердца ждут очередного удара неумолимого рока, Новая манхва. Я Сен Ко выполнена в лучших традициях \"\"Сияния\"\" С, Кинга и \"\"Крика\"\" У. Крейвена.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999056,"hdCover":""},{"id":"09892cf","title":"Redrum 327. Том 3","author":"Я Сен Ко","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000441416/140/114b/Ya_Sen_Ko__Redrum_327._Tom_3.jpg","isbn":"978-5-7525-2638-1","publisher":"Фабрика комиксов","pubDate":"2010","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Отправляясь на выходные в уединенный горный коттедж, семеро студентов университета и представить не могли, что их романтический уикенд превратится в самый настоящий кошмар. Появление новичка, прекрасной и загадочной девушки по имени Гаэ, вносит разлад в компанию старых друзей. Мрачная атмосфера пронизываемого холодными ветрами дома пробуждают в душе подростков навязчивые воспоминания о давнишней трагедии, которая, казалось, была забыта навсегда. Мелкие ссоры, любовные трагедии, сведение старых счетов - все это становится лишь прелюдией к ужасу, обрушивающемуся на молодых людей с приходом ночи...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999055,"hdCover":""},{"id":"09892ce","title":"Деревья. Книга 2","author":"Уоррен Эллис,Джейсон Говард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002811263/140/657a/__Derevya._Kniga_2.jpg","isbn":"978-5-04-095321-9","publisher":"Fanzon","pubDate":"2018","language":"Русский","series":"Комиксы. Современная классика","genres":["Комиксы","манга","графические романы"],"annotation":"Десять лет, как они приземлились на Землю. Их явление знаменует скорый конец света. Отомстят ли герои Деревьям за внезапное вторжение?  Завершение НФ-новеллы Уоррена Эллиса («Трансметрополитен», «РЭД») и Джейсона Говарда («Супердинозавр», «Удивительный Человек-волк»).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999054,"hdCover":""},{"id":"09892cd","title":"Деревья. Книга 1","author":"Уоррен Эллис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002785726/140/a17b/Uorren_Ellis__Derevya._Kniga_1.jpg","isbn":"978-5-04-094468-2","publisher":"Fanzon","pubDate":"2018","language":"Русский","series":"Комиксы. Современная классика","genres":["Комиксы","манга","графические романы"],"annotation":"Первая книга повествует о ближайшем будущем человечества, проходящем в тени Деревьев. Несколько судеб, объединенных страшной тайной: в Китае молодой художник прибывает в «специальную культурную зону» под Деревом. молодая женщина в Италии под опасным покровительством нацистской банды встречает старика, который хочет обучить её ужасным умениям. группа ученых на Шпицбергене случайно обнаруживает, что Деревья вовсе «не спят», а представляют ужасную опасность.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999053,"hdCover":""},{"id":"09892cc","title":"Ultimate Comics Ultimates By Jonathan Hickman, Vol. 2","author":"Эсад Рибич,Люк Росс,Sam Humphries,Джонатан Хикман","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002955138/140/4342/__Ultimate_Comics_Ultimates_By_Jonathan_Hickman_Vol._2.jpg","isbn":"9780785157205","publisher":"Marvel","pubDate":"2013","language":"Английский","series":"Ultimate Comics Ultimates","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999052,"hdCover":""},{"id":"09892cb","title":"Batman: Detective Comics Vol. 3: Greetings from Gotham","author":"Питер Дж. Томаси","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005904267/140/cac2/Piter_Dzh._Tomasi__Batman_Detective_Comics_Vol._3_Greetings_from_Gotham.jpg","isbn":"978-1401288617","publisher":"DC Comics","pubDate":"2020","language":"","series":"Detective Comics","genres":[],"annotation":"Following the events of Detective Comics Vol. 2: Arkham Knight, Batman''s limits will be pushed to the limit as he faces off against some of his deadliest foes including Deadshot and The Joker!  Detective Jim Corrigan has been shot on the streets of Gotham City--and the Spectre must reach out to Batman to help him find the secret assassin! There''s only one life Batman would be willing to risk saving Jim Corrigan and the Spectre: his own! Plus, Deadshot has returned to Gotham City following a long stint with the Suicide Squad, and Batman fears that without the oversight of Amanda Waller, Floyd Lawton will go back to his old ways.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999051,"hdCover":""},{"id":"09892ca","title":"That Texas Blood, Volume 1","author":"Крис Кондон","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005883762/140/8389/Kris_Kondon__That_Texas_Blood_Volume_1.jpg","isbn":"978-1534318069","publisher":"Image Comics","pubDate":"2021","language":"","series":"That Texas Blood","genres":[],"annotation":"After an explosive confrontation over a casserole dish, Joe Bob Coates begins to question his effectiveness as Sheriff of Ambrose County, Texas. Matters only get worse as Los Angeles-based writer Randy Terrill returns home following the sudden and mysterious death of his brother, causing a spiral down into a past filled with treachery and blood.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999050,"hdCover":""},{"id":"09892c9","title":"Dead Body Road, Volume 2: Bad Blood","author":"Джастин Джордан","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005883717/140/bbbb/Dzhastin_Dzhordan__Dead_Body_Road_Volume_2_Bad_Blood.jpg","isbn":"978-1534317215","publisher":"Image Comics","pubDate":"2021","language":"","series":"Dead Body Road","genres":[],"annotation":"Bree Hale has left a lot behind in her life. Crime. The military. But she can''t leave behind her own family, and when the local crime boss puts a hit out on her brother, there''s nothing she won''t do to save him. Absolutely nothing.  Skybound’s pulse-pounding action-crime series returns, with writer Justin Jordan (REAVER, The Strange Talent of Luthor Strode) and artist Benjamin Tiesma delivering an explosive tale of revenge like you’ve never seen before!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999049,"hdCover":""},{"id":"09892c8","title":"Новый Призрачный Гонщик. Том 2. Легенда","author":"Фелипе Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001668538/140/e5da/Felipe_Smit__Novyj_Prizrachnyj_Gonschik._Tom_2._Legenda.jpg","isbn":"978-5-91339-410-1","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Впервые за долгое время жизнь Робби Рейеса идёт в гору. Он немало зарабатывает на гонках, а его братец, Гейб, наконец-то получает то внимание, которое было ему необходимо. Но серийный убийца-сатанист Эли Морроу кое-что припас для своего юного носителя, и это уж точно не богато наследство или физиотерапия. Адские искры летят вовсе стороны, ведь легенда столкнётся с современностью: Джонни Блейз, оригинальный Призрачный Гонщик, и Робби Рейес! Олдскул и ньюскул, опыт и молодость, Восток и Запад — Призрачный Гонщик и Призрачный Гонщик! А также: вместе с развивающимися силами, Робби узнаёт шокирующую правду о пропавших родителях — но что ждёт Гейба? И чего на самом деле добивается Эли? Финишная черта уже рядом, и Робби предстоит сражение не с одним Духом Возмездия.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999048,"hdCover":""},{"id":"09892c7","title":"Новый Призрачный Гонщик. Том 1. Двигатели возмездия","author":"Трэдд Мур,Фелипе Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001519975/140/af4e/__Novyj_Prizrachnyj_Gonschik._Tom_1._Dvigateli_vozmezdiya.jpg","isbn":"978-5-91339-366-1","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Где-то в одном из районов Восточного Лос-Анджелеса, полном банд, перестрелок и наркоторговли, Робби Рейес получает невероятную новую силу! Но сможет ли подросток справиться с ней, или же она заведёт его на путь разрушений? В преступном мире назревает война, на улицах Восточного Лос-Анджелеса то здесь, то там вспыхивают стычки группировок из-за усиливающего наркотика, созданного Доктором Кельвином Забо, а Мистер Хайд пускает в ход дьявольский план по расширению своей преступной империи. И вот, встретив таинственную сущность, повинующуюся ему, примет ли Робби этого духа и как далеко он зайдёт, охраняя район? Новый Призрачный Гонщик встретится с Мистером Хайдом в этом драйвовом комиксе, неожиданный финал которого собьёт вас на скорости 160 км/ч!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999047,"hdCover":""},{"id":"09892c6","title":"Веном. Край, где обитают убийцы","author":"Каллен Банн,Каленн Банн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005614941/140/2fe3/__Venom._Kraj_gde_obitayut_ubijtsy.jpg","isbn":"978-5-91878-368-9","publisher":"Фантастика Книжный Клуб","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Агент Веном выходит на улицы ради старой доброй борьбы с преступностью... Но криминал не сдаётся, и Лорд Огр, вожак уголовного мира Филадельфии, объявляет войну самозваному защитнику города! Хладнокровные убийцы лезут из всех щелей, стремясь получить награду за голову Венома, его личность раскрывают, и теперь Флэшу Томпсону понадобится любая помощь — хотя бы для того, чтобы выжить. Положение ещё больше усложняется, когда в схватку вступает новая симбиотическая сущность: доблестный поступок Юджина случайно приводит к рождению Мании! Можно ли справиться с этой новой опасностью? И кто такая Мания — друг или враг?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999046,"hdCover":""},{"id":"09892c5","title":"Punisher: Frank Castle Max - Welcome to the Bayou","author":"Виктор Гишлер,Горан Парлов","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003193048/140/f763/__Punisher_Frank_Castle_Max__Welcome_to_the_Bayou.jpg","isbn":"978-0785133780","publisher":"Marvel","pubDate":"2009","language":"Английский","series":"","genres":[],"annotation":"Traveling the Louisiana back roads with something awful stored in his trunk, Frank Castle stops at a service station on the edge of the bayou... and steps into a world of unspeakable horror! Patrolling the depths of hell, the Punisher has crossed paths with some unsavory characters, but nothing has prepared him for the unspeakable depravity of the Geautreauxs.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999045,"hdCover":""},{"id":"09892c4","title":"Punisher Presents: Barracuda MAX","author":"Гарт Эннис","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003193052/140/9484/Gart_Ennis__Punisher_Presents_Barracuda_MAX.jpg","isbn":"978-0785124658","publisher":"Marvel","pubDate":"2007","language":"Английский","series":"","genres":[],"annotation":"The Punisher''s wildest foe is back. This time he''s embarking on a solo mission of playing bodyguard to the son of a dangerous mob boss. Junior is a hemophiliac - and every crime syndicate in the country can''t wait to take a shot at him as payback to his dad.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999044,"hdCover":""},{"id":"09892c3","title":"Untold Tales of Punisher Max","author":"Джейсон Старр","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001849773/140/58b9/Dzhejson_Starr__Untold_Tales_of_Punisher_Max.jpg","isbn":"9780785165927","publisher":"MAX","pubDate":"2012","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"PunisherMAX returns for another round as talented creators including JASON LATOUR (BPRD, Loose Ends) and award-winning crime novelist JASON STARR bring their unique visions to the gritty MAX world of Frank Castle! A massive debt, a gun with untraceable bullets, and one unthinkable choice. Whose side will the Punisher take? Frank gets involved in the most twisted encounter ever. COLLECTING: UNTOLD TALES OF PUNISHER MAX 1-5","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999043,"hdCover":""},{"id":"09892c2","title":"Punisher: Frank Castle Max - Six Hours to Kill","author":"Дуэйн Сверчински,Michael A. LaCombe","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003193046/140/1669/__Punisher_Frank_Castle_Max__Six_Hours_to_Kill.jpg","isbn":"978-0785131823","publisher":"Marvel","pubDate":"2009","language":"Английский","series":"","genres":["Триллеры"],"annotation":"The Punisher always knew he''d die on the job. But he didn''t know he''d have an expiration date. After busting up a slave ring in downtown Philadelphia, Frank Castle has been tricked, trapped, gassed, strapped to a table, and injected with a serum that will turn him into a 220-pound corpse by dawn - six hours from now. The people who grabbed him want him to do a simple little job and then they''ll give him the antidote - simple, right? Guess again! The Punisher is nobody''s errand boy! There''s only one thing he wants to do before he dies: Take as many bastards as he can with him!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999042,"hdCover":""},{"id":"09892c1","title":"Guardians of the Galaxy, Vol. 1: It''s On Us","author":"Эл Юинг,Juann Cabal","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005139384/140/a509/__Guardians_of_the_Galaxy_Vol._1_It039s_On_Us.jpg","isbn":"9781302920753","publisher":"Marvel","pubDate":"2020","language":"Английский","series":"","genres":[],"annotation":"Once they were a team of misfits. Now they''re a family, and they''ve earned their peace. But the universe is not a peaceful place - and it''s only getting worse. The Great Empires are in turmoil. The rule of law is dead. And amid the chaos, the gods of Olympus have returned - harbingers of a new age of war, reborn to burn their mark on the stars themselves. Someone has to guard the galaxy - but who will accept the mission? And will they survive it? Al Ewing (IMMORTAL HULK) and Juann Cabal (FRIENDLY NEIGHBORHOOD SPIDER-MAN) bring you in on the ground floor of a whole Marvel Universe of action and suspense! COLLECTING: GUARDIANS OF THE GALAXY (2020) 1-6","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999041,"hdCover":""},{"id":"09892c0","title":"Daredevil Vol 1 (#1-394)","author":"Фрэнк Миллер,Марв Вульфман,Стив Гербер,Рой Томас,Ann Nocenti,Roger McKenzie,показать всех","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001446109/140/3a2a/__Daredevil_Vol_1_1394.jpg","isbn":"","publisher":"Marvel Comics","pubDate":"1964","language":"","series":"","genres":[],"annotation":"The series that introduced Daredevil, the Man Without Fear! Daredevil’s first ongoing solo series. Unlike many Marvel heroes launched during the Silver Age of Comics, Daredevil debuted in his own series without first being test launched in another title. The series started in 1964 and lasted 380 issues until being cancelled in 1998. The series returned to its original numbering with issue #500 in Oct. 2009.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999040,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09892bf","title":"Essential Daredevil Volume 3 TPB (Essential)","author":"Гэри Фридрих","type":"Книга","cover":"https://s1.livelib.ru/boocover/1000204174/140/edfb/Geri_Fridrih__Essential_Daredevil_Volume_3_TPB_Essential.jpg","isbn":"0785117245","publisher":"","pubDate":"2005","language":"Русский","series":"","genres":["Зарубежное фэнтези"],"annotation":"Book DescriptionDaredevil''s original identity crisis kicks off a collection of Colan classics! The ups and downs of his doomed love for Karen Page begin here! And DD goes Hollywood with the Stuntmaster and Brother Brimstone, but is any star as big","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999039,"hdCover":""},{"id":"09892be","title":"Marvel Knights: Defenders of the Streets","author":"Чак Диксон,Eduardo Barreto,Mike Lilly","type":"Книга","cover":"https://s1.livelib.ru/boocover/1004474818/140/364b/__Marvel_Knights_Defenders_of_the_Streets.jpg","isbn":"978-1302912130","publisher":"Marvel","pubDate":"2018","language":"","series":"Marvel Knights (Book 1)","genres":[],"annotation":"Daredevil! Black Widow! Dagger! Shang-Chi! And...the Punisher?! What terrible evil could unite these vigilantes on a single mission? Would you believe...Ulik the Troll?! As DD leads them deep underground in search of answers, is Ulik really the priority - or is it taking down Frank Castle? How about helping Dagger''s troubled partner Cloak? Could it be Zaran the Weapons Master, who is leaving a trail of bodies in his wake? Or maybe it''s the ancient menace that Zaran is working for! Whatever the biggest problem faced by this vigilante team, only Moon Knight would be crazy enough to want in! Doctor Strange makes a house call as the group faces a nightmarish enemy, while Widow takes Dagger under her wing. All this plus Nick Fury, Luke Cage, and the final face-off between the Punisher and Daredevil!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999038,"hdCover":""},{"id":"09892bd","title":"Daredevil","author":"","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001850917/140/a9ef/Marvel_Comics__Daredevil.jpg","isbn":"9780785193265","publisher":"","pubDate":"2015","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999037,"hdCover":""}]');

UPDATE library_settings SET initialized = 1, updated_at = CURRENT_TIMESTAMP WHERE id = 1;
